-- Poems batch 154
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('d8904de5-a869-41d0-bfd3-3962b519164f','早雪','章甫','宋','宋诗','song-poetry','','[]','賤夫流落來淮海，兩紀悠然忘凍餒。',96,'全唐诗/poet.song.156000.json','["賤夫流落來淮海，兩紀悠然忘凍餒。", "烏薪白粲不論錢，近歲山林禁樵采。", "去年差官打炭窑，淮民畏事誰敢燒。", "官軍巡山得心力，草木欣欣有顔色。", "九月未霜雲漫漫，雪花爭先飛作團。", "凍坐孤吟還自寬，邊頭牽挽人夫寒。"]'),
('a1dd7c23-600c-4468-bd15-389ce2674cd6','雪中張仲庠惠十詩老懶不能追逐戲答古風兼簡陳伯茂','章甫','宋','宋诗','song-poetry','','[]','愛君詩好韻倔奇，快如天馬不容羈。',186,'全唐诗/poet.song.156000.json','["愛君詩好韻倔奇，快如天馬不容羈。", "惜君有錢不沽酒，盡日苦吟難療饑。", "我生真成錯料事，陳子生涯畧相似。", "敢持短兵與君接，笑我老來長退怯。", "空山一夜雪盈階，軒窗晃耀如瑶臺。", "尊中尚喜有餘綠，紅潮兩頰心悠哉。", "安得萬里江，變作葡萄醅。", "笑呼姮娥共起舞，夜闌更酌北斗杯。", "一醉三千年，從教海水揚塵埃。", "妻孥笑我言，此樂恐未諧，典衣且復沽茅柴。", "淮南有薄田，與汝歸去來。", "願身長健眉長開，好插梅花醉幾回。"]'),
('c2fa30db-e5ac-47b6-9ec3-f7d34bd43de5','春日呈韓丈','章甫','宋','宋诗','song-poetry','','[]','陽烏陰兔爭馳騁，人世光陰剎那頃。',128,'全唐诗/poet.song.156000.json','["陽烏陰兔爭馳騁，人世光陰剎那頃。", "玉盤生菜亂青絲，三歲公家喫春餠。", "前年班春池陽城，民物熙熙簫鼓聲。", "去年轉粟巡邊徼，聖朝初下和戎詔。", "祇今塞下不傳烽，野梅官柳競春風。", "相從且作無事飲，莫辭節物來匆匆。", "明年上國春應早，棠棣陰中詩更好。", "詩成但遣阿買書，郵筒寄我江南道。"]'),
('a618d986-3a2b-4c43-8477-70f878d7d2bb','劉祼卿送筍','章甫','宋','宋诗','song-poetry','','[]','俗子貪錢如食蜜，幽人愛竹如種玉。',160,'全唐诗/poet.song.156000.json','["俗子貪錢如食蜜，幽人愛竹如種玉。", "君家大隠城一隅，萬个深圍數間屋。", "陽春不住長兒孫，犢角貓頭還滿目。", "却恐繁陰礙風月，童奴時取供肴䔩。", "朝來想掛北窗坐，應念先生食無肉。", "故遣此君來起予，斕斑嫩籜森盈束。", "先生饑腸非雷吼，米糝鹽醯羹杞菊。", "急呼瀹釜然枯薪，殷勤留客晨炊熟。", "不羨侯家五鼎烹，得此一飽萬事足。", "客去關門聽雨眠，枕上詩成翻水速。"]'),
('87df8e17-48ed-4db6-b1d3-7e5f0c4ea9c1','清明病中遣酒問訊史授夫','章甫','宋','宋诗','song-poetry','','[]','一榻蕭然唯坐卧，風雨欺人打窗破。',128,'全唐诗/poet.song.156000.json','["一榻蕭然唯坐卧，風雨欺人打窗破。", "數片飛花何處來，寒食清明病中過。", "疏狂閒憶少年時，問柳尋花夜不歸。", "春衣一任酒狼籍，玉山自有人扶持。", "日月變遷衰相現，世途迫隘令人倦。", "耳冷那聞白雪歌，眼寒不識春風面。", "懷君著書坐僧房，呼兒與撥浮蛆香。", "往澆萬卷文字腸，莫學病夫多感傷。"]'),
('dc9dc963-177f-407f-a0aa-ad0c24b6a96b','惜花','章甫','宋','宋诗','song-poetry','','[]','前朝西風不肯住，紅雨毿毿落深樹。',96,'全唐诗/poet.song.156000.json','["前朝西風不肯住，紅雨毿毿落深樹。", "昨日東風更放顛，香雪紛紛飄滿園。", "四時催人頭髮白，薄相春風亦欺客。", "漸覺繁枝過眼空，歷歷黄花亂疏麥。", "野店沽酒酸如虀，先生不飲春將歸。", "屋頭向晚雨聲急，自炷爐香坐盤膝。"]'),
('c3303b29-c3ad-4a5d-b07e-10f037ac0336','盱眙館中題雲山圖','章甫','宋','宋诗','song-poetry','','[]','北風三日吹黄土，長淮浪高少人渡。',96,'全唐诗/poet.song.156000.json','["北風三日吹黄土，長淮浪高少人渡。", "客愁正坐小窗間，眼明見此江南山。", "好山連娟螺髻鬟，白雲無心終日閒。", "野橋溪水流彎環，旁有幽人晝掩關。", "道路只今多險艱，林泉有約吾當還。", "黄精可駐冰雪顔，時時令人雙鬢斑。"]'),
('50939fbb-6d19-4880-a26f-a827cba5c081','葉子逸以惠山泉瀹日鑄新茶餉予與常鄭卿','章甫','宋','宋诗','song-poetry','','[]','惠山甘泉苦不冷，日鑄茶香方是真。',64,'全唐诗/poet.song.156000.json','["惠山甘泉苦不冷，日鑄茶香方是真。", "廣文喚客作妙供，石銚風爐皆手親。", "神清便欲排閶闔，且了吾人淡生活。", "瓶芽分送已無餘，杯水尚容消午渴。"]'),
('aaa70a88-b4e7-4b4f-8a45-2cf7232aae70','戲簡樂長卿','章甫','宋','宋诗','song-poetry','','[]','長卿談兵氣飄揚，半生漫趁槐花忙。',128,'全唐诗/poet.song.156000.json','["長卿談兵氣飄揚，半生漫趁槐花忙。", "塵埃綠綺誰拂拭，雞羣野鶴空昂藏。", "何必明經取青紫，請君囊書獻天子。", "中原猶未息兵戈，萬里橫行丈夫事。", "愞夫株守衡門裏，初無長鬚給薪水。", "故舊經年絕尺書，烏鵲玩人頻送喜。", "欲行萬里囊無錢，移牀且對薰風眠。", "兒啼妻怒了不問，誦詩過午聲琅然。"]'),
('19bb4e4a-8c8d-4b64-8bf5-74577155eba0','雨凉成詩一首簡子逸','章甫','宋','宋诗','song-poetry','','[]','坦率每愁遭怒嗔，閉門直欲全吾真。',64,'全唐诗/poet.song.156000.json','["坦率每愁遭怒嗔，閉門直欲全吾真。", "美人娟娟不可見，薄俗往往難相親。", "夢斷風扉自開闔，還喜晚涼生意活。", "未能衝雨過蘇端，且乞新詩慰饑渴。"]'),
('984d1f7a-ec35-4ca8-a30d-495e9d6c4886','戲簡李清宇','章甫','宋','宋诗','song-poetry','','[]','四十九年真大謬，三百六旬長鮮驩。',64,'全唐诗/poet.song.156000.json','["四十九年真大謬，三百六旬長鮮驩。", "人生一夢何足較，田穀薦饑良獨難。", "酒邊志氣漫豪放，眼中骨相殊酸寒。", "輸與能詩李供奉，水旱不憂吾有官。"]'),
('4eb72279-c8e6-4924-bfe6-fd46f79bfa9e','送張安國','章甫','宋','宋诗','song-poetry','','[]','前日見公如桂林，梅黄風雨天多陰。',160,'全唐诗/poet.song.156000.json','["前日見公如桂林，梅黄風雨天多陰。", "今年見公長沙去，草綠江湖春水深。", "借問長沙多少路，盡是前年曾到處。", "如公正合在朝廷，胸中素藴經綸具。", "吾君一視而同仁，且欲煩公蘇遠人。", "親朋漫作別離惡，王事敢辭行役頻。", "嗟予潦倒百無用，客食淮南兩相送。", "青山可買坐無錢，日長只作還鄉夢。", "九重早晚催賜環，了却功名歸故山。", "屋頭乞我茆三間，布襪青鞋相伴閒。"]'),
('bb3cc19a-4957-413f-8798-ae58acf8a878','題趙純甫渭川千畝圖','章甫','宋','宋诗','song-poetry','','[]','君家天姥山前居，未辦種竹先作圖。',96,'全唐诗/poet.song.156000.json','["君家天姥山前居，未辦種竹先作圖。", "不惟要與千戶等，亦念豈可一日無。", "勁節虛心聽霜露，細香靜色宜風雨。", "玉版禪師得飽參，翠袖佳人定何許。", "津津喜氣見眉間，準擬他年如此閑。", "可無嵇阮相往還，俗客儻來君掩關。"]'),
('015034b1-4798-4676-957e-c014504a4753','題張希穎筠坡圖','章甫','宋','宋诗','song-poetry','','[]','緣坡種竹自成趣，籃輿造門今有誰。',96,'全唐诗/poet.song.156000.json','["緣坡種竹自成趣，籃輿造門今有誰。", "張侯好事果絕俗，因人隔江來覓詩。", "披圖識面恨不早，更愛諸公妙詞藻。", "繁霜密雪得天全，明月清風爲君好。", "易足堂前方欲栽，摩挲短軸心眼開。", "忽思江南讀書處，碧玉如椽歸去來。"]'),
('187de15b-8014-4a0b-b8d9-00a3e034adc7','颺稻行','章甫','宋','宋诗','song-poetry','','[]','屋頭場地如鏡光，未曉相呼來破場。',96,'全唐诗/poet.song.156000.json','["屋頭場地如鏡光，未曉相呼來破場。", "今年慙愧好天色，颺稻得風尤省力。", "分時往往只論𥰭，主客四六無偏頗。", "高低十分早晚禾，就中誰家收最多。", "妻兒舂糯試新麴，隣舍茅柴相接續。", "醉來起舞自頓足，官無差科即爲福。"]'),
('c2369996-be66-4840-a10d-4e16eef38cb8','題長蘆方丈','章甫','宋','宋诗','song-poetry','','[]','笑別靈巖日當午，籃輿軋軋轉江浦。',64,'全唐诗/poet.song.156000.json','["笑別靈巖日當午，籃輿軋軋轉江浦。", "眼明初入菩提場，一燈傳自西來祖。", "老禪留客苦殷勤，汲泉煮茗添爐薰。", "空江向晚無人度，明月滿天秋正分。"]'),
('a008b9d1-8f27-4b4a-a8d6-7fea00682e4e','中秋次韻','章甫','宋','宋诗','song-poetry','','[]','秋浦堂前有清集，久客思家淚痕濕。',160,'全唐诗/poet.song.156000.json','["秋浦堂前有清集，久客思家淚痕濕。", "連年客裏作中秋，今歲還家又無及。", "山中茅屋冷如水，應念征塵何日洗。", "邊鴻也解寄歸音，旅燕亦能辭故壘。", "滔滔四海知音誰，公家公子歲寒期。", "殷勤爲我撥新釀，煖熱向我哦好詩。", "我生志願良自足，肯向天涯長碌碌。", "願君腰金佩鳴玉，從我羹藜飯脫粟。", "秋風舟子兩相催，側帽長吟歸去來。", "開帆轉柁清溪口，還山要趁重陽酒。"]'),
('76d0aeac-64ac-47ca-bd7e-77066f8f5c23','諸公過易足爲紅梅一醉醉後率成數語','章甫','宋','宋诗','song-poetry','','[]','一冬雪與寒俱少，膏澤春來頗傾倒。',128,'全唐诗/poet.song.156000.json','["一冬雪與寒俱少，膏澤春來頗傾倒。", "畏寒病懶不出門，未覺心情被春惱。", "花木今春種種遲，眼明始見紅梅枝。", "容顔頗稱俗子意，風骨獨有詩人知。", "人生百年誰滿百，去日漸多來日窄。", "衰顔已減舊年紅，短髮明年應更白。", "甕頭有酒不用沽，肴䔩得隨家有無。", "主人頹然客亦走，明朝無事重來否。"]'),
('5b5b3c69-1032-4ad8-bdcb-1ecd0c4f7633','呈謝仲連','章甫','宋','宋诗','song-poetry','','[]','一葦江頭風雨寒，邂逅三日同清驩。',64,'全唐诗/poet.song.156000.json','["一葦江頭風雨寒，邂逅三日同清驩。", "諸塵不染眼自碧，萬事隨緣心已安。", "雨晴歸路馬蹄疾，問君呼船定何日。", "杖藜過我城南偏，遊戲世間文字禪。"]'),
('128f339d-ecb8-4f8c-b8ef-cd7c4b76bd7d','從賈倅乞貓','章甫','宋','宋诗','song-poetry','','[]','渚宮茅屋住經年，牆壁苦遭羣鼠穿。',96,'全唐诗/poet.song.156000.json','["渚宮茅屋住經年，牆壁苦遭羣鼠穿。", "旋乞狸奴名去惡，中宵客枕得安眠。", "携之俱東泛江水，饜飫魚腥二千里。", "半途忽作楚人弓，兒女憐渠今未已。", "昨宵聞說二車家，花墩五子俱可誇。", "此詩雖拙勝鹽茶，不問白黑灰貍花。"]'),
('955ad3e6-c282-467b-a1b0-f4810341336b','書黄叔虎傳神卷','章甫','宋','宋诗','song-poetry','','[]','鶴骨何清癯，腹空惟貯書。',56,'全唐诗/poet.song.156000.json','["鶴骨何清癯，腹空惟貯書。", "山林日月長，掉頭賦歸歟。", "松竹歲寒金石友，身後虛名眼前酒。", "與世相違豈盡然，江湖猶有丹青手。"]'),
('6e2ddd04-accb-4524-a87f-9576c7ef94cc','與北山長老','章甫','宋','宋诗','song-poetry','','[]','數間破屋城南街，坐卧一榻心如灰。',96,'全唐诗/poet.song.156000.json','["數間破屋城南街，坐卧一榻心如灰。", "現身幻化本無住，疾病問渠何自來。", "剝喙誰歟破幽寂，道人定起北山北。", "齒冰骨玉兩高寒，禪病詩魔俱辟易。", "我倦欲眠君且歸，籃輿入郭知何時。", "貧家客來無準擬，爲君時供雞蘇水。"]'),
('c4a3c9d8-b38e-48fc-93fb-93f841e735dc','法剛化士幹蔣山藏經乞語','章甫','宋','宋诗','song-poetry','','[]','鍾山夜半發奇怪，火光熾然脫三昧。',96,'全唐诗/poet.song.156000.json','["鍾山夜半發奇怪，火光熾然脫三昧。", "法筵龍象不須驚，寶公留得眉毛在。", "食輪才轉法輪隨，樓臺金碧還相輝。", "大千經卷何處覓，剛禪藏在僧伽葉。", "如來言語皆真實，別有真經名第一。", "琅函寶藏不能收，若遇知音請拈出。"]'),
('cf42a5fe-6706-4bfd-97e9-f75e68e54a5c','題張季子妄菴','章甫','宋','宋诗','song-poetry','','[]','世間種種無非妄，云何以妄爲庵榜。',64,'全唐诗/poet.song.156000.json','["世間種種無非妄，云何以妄爲庵榜。", "君欲捨妄却求真，展轉思維增妄想。", "即妄即真君勿疑，真妄俱忘也大奇。", "笑我猖狂今老矣，因君聊復妄言之。"]'),
('183eebab-fb1a-457e-b6b8-a1d0dca98bf2','次韓無咎途中寄陸務觀  其一','章甫','宋','宋诗','song-poetry','','[]','風高微退鷁，雲好合從龍。',48,'全唐诗/poet.song.156000.json','["風高微退鷁，雲好合從龍。", "蕭艾長貪雨，松筠却耐冬。", "禁途今不遠，歸興未應濃。", "莫羨朱雙轂，相期祿萬鍾。"]'),
('4be2aff9-6199-4c88-b1db-98336fb3027b','次韓無咎途中寄陸務觀  其二','章甫','宋','宋诗','song-poetry','','[]','戎馬馳驅日，江湖邂逅間。',48,'全唐诗/poet.song.156000.json','["戎馬馳驅日，江湖邂逅間。", "笑談無逆旅，翰墨落名山。", "畫省春風入，漁舟夜月還。", "唱酬能見記，書札忍令慳。"]'),
('ef4f65a1-a450-4f50-af23-c44d5ea9af16','次韓無咎途中寄陸務觀  其三','章甫','宋','宋诗','song-poetry','','[]','寒梅欺雪白，臘酒愛鵝黄。',48,'全唐诗/poet.song.156000.json','["寒梅欺雪白，臘酒愛鵝黄。", "花下觥籌亂，燈前錦繡香。", "醉吟揮字大，愁別聽更長。", "近報蛾眉好，何時奉一觴。"]'),
('71372613-afa1-45fb-9756-a1379413da16','次韓無咎途中寄陸務觀  其四','章甫','宋','宋诗','song-poetry','','[]','晝永渾無事，昏歸只掩門。',48,'全唐诗/poet.song.156000.json','["晝永渾無事，昏歸只掩門。", "甘貧同陋巷，多病似文園。", "對月人千里，論文酒一尊。", "遠懷霄漢路，愁絕虎狼村。"]'),
('966755f7-1c89-429b-bdc5-d74d6007c75d','次韓無咎途中寄陸務觀  其五','章甫','宋','宋诗','song-poetry','','[]','園筍看成竹，庭榴已著花。',48,'全唐诗/poet.song.156000.json','["園筍看成竹，庭榴已著花。", "老來猶是客，歸去亦無家。", "萬事大槐國，一身焦穀芽。", "心閒聊默坐，紅日下天涯。"]'),
('6bd8a89d-3e41-43cf-8fbf-5dd65c98073d','即日  其一','章甫','宋','宋诗','song-poetry','','[]','苦憶花吹盡，生嫌草長齊。',48,'全唐诗/poet.song.156000.json','["苦憶花吹盡，生嫌草長齊。", "鶑啼春已暮，客散日還西。", "孺子拋書卷，童奴理菜畦。", "怒雷將急雨，一夜水平堤。"]'),
('b059d9f1-8c2a-4c00-865b-a067acf966ab','即日  其二','章甫','宋','宋诗','song-poetry','','[]','吟苦知音少，棋低敵手多。',48,'全唐诗/poet.song.156000.json','["吟苦知音少，棋低敵手多。", "故人無恙不，薄酒奈愁何。", "未暇兔三窟，聊同鷗一波。", "傳聞江北路，人應力田科。"]'),
('7d7e4fca-e84f-4ef9-ae61-d7d40c777a74','即日  其三','章甫','宋','宋诗','song-poetry','','[]','醉裏三春了，山中五載留。',48,'全唐诗/poet.song.156000.json','["醉裏三春了，山中五載留。", "日長知已夏，雨冷忽如秋。", "書貸監河粟，箱存季子裘。", "曲肱朝睡美，身外付悠悠。"]'),
('4770b4ed-8c32-4246-bbec-b16b5d4e74d5','春盡','章甫','宋','宋诗','song-poetry','','[]','晝永花陰直，風輕麥浪勻。',48,'全唐诗/poet.song.156000.json','["晝永花陰直，風輕麥浪勻。", "僧歸還逼夏，鶑語欲留春。", "鬚髮垂垂老，親朋往往貧。", "地偏人事少，聊以寄吾真。"]'),
('27b9e6a5-3143-45a1-9734-932f34220e1b','獨登南樓兼懷嚴聖幾俞若晦  其一','章甫','宋','宋诗','song-poetry','','[]','瓜茗難逃暑，蚊蠅正作秋。',48,'全唐诗/poet.song.156000.json','["瓜茗難逃暑，蚊蠅正作秋。", "勞生一念錯，晚境萬緣休。", "筆老無新語，囊空有敝裘。", "閒携瘦藤杖，獨上郡南樓。"]'),
('43f9098e-252b-41bf-9b16-36dd821829a6','獨登南樓兼懷嚴聖幾俞若晦  其二','章甫','宋','宋诗','song-poetry','','[]','城外江山好，樓前市井喧。',48,'全唐诗/poet.song.156000.json','["城外江山好，樓前市井喧。", "登高明遠目，直北望中原。", "濟世原無策，傷心不忍言。", "唯餘憂國淚，還共水潺湲。"]'),
('cf81f1e4-ecdf-4a52-8231-0b4334d52fb8','獨登南樓兼懷嚴聖幾俞若晦  其三','章甫','宋','宋诗','song-poetry','','[]','晝景微微歛，陰雲稍稍低。',48,'全唐诗/poet.song.156000.json','["晝景微微歛，陰雲稍稍低。", "炎涼催旅燕，風雨聽鳴雞。", "獨立江樓上，相思浙水西。", "詩情兼酒伴，何日手重携。"]'),
('c2449582-4133-46f4-a970-6d69983f6800','夜坐','章甫','宋','宋诗','song-poetry','','[]','枕簟遲遲睡，軒窗一一開。',48,'全唐诗/poet.song.156000.json','["枕簟遲遲睡，軒窗一一開。", "市收人語寂，江迥水風來。", "熠耀明衣袂，嬋娟到酒杯。", "新涼兒女健，促織已相催。"]'),
('c2ccba0a-73a9-4b7f-a7e3-88de334d9d07','喜凉  其一','章甫','宋','宋诗','song-poetry','','[]','暑氣今全減，人心始少蘇。',48,'全唐诗/poet.song.156000.json','["暑氣今全減，人心始少蘇。", "客愁生海燕，秋意入庭梧。", "歲月真虛擲，詩書只自娛。", "荆山誰獻玉，齊國正吹竽。"]'),
('948c7c4c-8709-4f63-a078-076a14361669','喜凉  其二','章甫','宋','宋诗','song-poetry','','[]','老去孤黄嬭，愁來頼麴生。',48,'全唐诗/poet.song.156000.json','["老去孤黄嬭，愁來頼麴生。", "客居宜落寞，寒事費經營。", "歲稔鍛聲急，夜長燈影明。", "深懷不成寐，四壁候蟲鳴。"]'),
('69ab0f67-8b24-488b-b848-7515d542ea16','宿靈巖','章甫','宋','宋诗','song-poetry','','[]','異縣經年客，靈巖一夕留。',48,'全唐诗/poet.song.156000.json','["異縣經年客，靈巖一夕留。", "涼風吹薄暮，明月照中秋。", "閲世身將老，尋山興未休。", "還驅羸馬去，訪古大江頭。"]'),
('3a5084c2-84a3-4f3b-93e7-c6da646d7dc7','不寐','章甫','宋','宋诗','song-poetry','','[]','不眠知夜永，危坐起憂端。',48,'全唐诗/poet.song.156000.json','["不眠知夜永，危坐起憂端。", "木葉紛猶落，篝燈炯未殘。", "年華今晼晚，邊堠且平安。", "以我衣裳冷，遥憐弟妹寒。"]'),
('698c0828-ecde-4a41-b130-60ae7609083c','聞鴉','章甫','宋','宋诗','song-poetry','','[]','柳暗啼春處，庭空反哺時。',48,'全唐诗/poet.song.156000.json','["柳暗啼春處，庭空反哺時。", "鳴聲元自樂，世俗亦多疑。", "凶吉何須問，雌雄未易知。", "寧棲丈人屋，莫借上林枝。"]'),
('f5945df5-a460-4516-865e-5580785d21e3','除草','章甫','宋','宋诗','song-poetry','','[]','惡草溷嘉蔬，涼風獨荷鋤。',48,'全唐诗/poet.song.156000.json','["惡草溷嘉蔬，涼風獨荷鋤。", "薅耘非敢後，滋蔓恐難除。", "女大知艱食，兒癡亦廢書。", "歸來一長歎，不是厭山居。"]'),
('7475bfc8-2f3a-4dbd-9c0d-355a4619ff56','春日村居  其一','章甫','宋','宋诗','song-poetry','','[]','築圃未成趣，栽桃纔試花。',48,'全唐诗/poet.song.156000.json','["築圃未成趣，栽桃纔試花。", "年饑兒强飯，春困婦煎茶。", "爲客空遲暮，逢人只歎嗟。", "上天新號令，雷雨起龍蛇。"]'),
('a3a2ad1e-dad3-4606-bcac-7b16e1043bff','春日村居  其二','章甫','宋','宋诗','song-poetry','','[]','村迥客來少，山寒春到遲。',48,'全唐诗/poet.song.156000.json','["村迥客來少，山寒春到遲。", "修塘留野水，插槿補疏籬。", "旁舍閒相過，幽人舊有期。", "出門看遠燒，拄杖立多時。"]'),
('bf654f08-f0c4-479f-b566-4455854e4f87','春日村居  其三','章甫','宋','宋诗','song-poetry','','[]','冬暖惟憂麥，春寒却勒花。',48,'全唐诗/poet.song.156000.json','["冬暖惟憂麥，春寒却勒花。", "地偏宜鳥雀，江遠少魚蝦。", "驚犬時時吠，歸鴻字字斜。", "故園芳草色，遊子亦思家。"]'),
('3e602f66-6181-4914-8f69-8042e129cf18','春日村居  其四','章甫','宋','宋诗','song-poetry','','[]','浦樹微微改，溪流稍稍深。',48,'全唐诗/poet.song.156000.json','["浦樹微微改，溪流稍稍深。", "春來差少病，歲後苦多陰。", "隴畝三年夢，親朋萬里心。", "感時仍念舊，老淚欲沾襟。"]'),
('5a970611-4c4a-460b-aeb2-3dc0bfad4be8','春日村居  其五','章甫','宋','宋诗','song-poetry','','[]','土室宜冬夏，柴門玩歲時。',48,'全唐诗/poet.song.156000.json','["土室宜冬夏，柴門玩歲時。", "不嫌貧作祟，直恐老相欺。", "草茁牛羊壯，山空虎豹饑。", "天晴好挑菜，吾亦伴兒嬉。"]'),
('4cbb5c71-bdf3-412f-b756-475ede56ccfc','新凉','章甫','宋','宋诗','song-poetry','','[]','白帝揚鑣後，炎官退舍初。',48,'全唐诗/poet.song.156000.json','["白帝揚鑣後，炎官退舍初。", "江山驚客恨，風月到吾廬。", "黄嬭宜相就，青奴稍見疏。", "寄聲蓮社友，秋興復何如。"]'),
('6e499448-ddb1-4252-b8ea-3268f0877c67','同湯叔度兄弟賦秋聲','章甫','宋','宋诗','song-poetry','','[]','古木斜陽暮，寒江澹月秋。',48,'全唐诗/poet.song.156000.json','["古木斜陽暮，寒江澹月秋。", "蕭騷初滿耳，蟋蟀最關愁。", "茅屋疑鳴雨，雲溪想枕流。", "幾回連別恨，爲我過西州。"]'),
('9cc0778f-2658-4b1d-939c-c2be247e3ed8','送潘致虛之湖南','章甫','宋','宋诗','song-poetry','','[]','久客兒童狎，窮居草木長。',48,'全唐诗/poet.song.156000.json','["久客兒童狎，窮居草木長。", "蛙聲猶鼓吹，燕子亦炎涼。", "度日工詩律，傷時洒淚行。", "輸君載明月，先我過瀟湘。"]'),
('e13dc421-cc65-43fd-a7bb-ba13828b7171','即事  其一','章甫','宋','宋诗','song-poetry','','[]','暑雨何時了，江雲不肯開。',48,'全唐诗/poet.song.156000.json','["暑雨何時了，江雲不肯開。", "窮途惟有死，薄俗動相猜。", "怪事供詩卷，閒愁付酒杯。", "欲從湖海去，安得小舟來。"]'),
('b257954b-59f6-4781-977a-c4bcf0ce63d3','即事  其二','章甫','宋','宋诗','song-poetry','','[]','俯仰憐身世，飄零玩歲時。',48,'全唐诗/poet.song.156000.json','["俯仰憐身世，飄零玩歲時。", "道途多異說，客子有新詩。", "日落乾坤慘，風生草木悲。", "高樓空北望，清淚不勝垂。"]'),
('562da022-e929-4170-aa16-ec1fc7dfc8c6','即事  其三','章甫','宋','宋诗','song-poetry','','[]','天意誠難測，人言果有不。',48,'全唐诗/poet.song.156000.json','["天意誠難測，人言果有不。", "便令江海竭，未厭虎狼求。", "獨下傷時淚，誰陳活國謀。", "君王自神武，况乃富貔貅。"]'),
('cf657386-a05e-4d46-b7a5-d91e2338c0ae','即事  其四','章甫','宋','宋诗','song-poetry','','[]','門靜悠悠日，春愁淡淡天。',48,'全唐诗/poet.song.156000.json','["門靜悠悠日，春愁淡淡天。", "風塵殊未已，形影自相憐。", "有客還詩債，無人與酒錢。", "感時歌慷慨，憂國淚潺湲。"]'),
('2e7db086-445b-40c7-9674-a2556802ef4c','即事  其五','章甫','宋','宋诗','song-poetry','','[]','風急收殘雨，花輕點客衣。',48,'全唐诗/poet.song.156000.json','["風急收殘雨，花輕點客衣。", "江山爭秀發，燕雁不同飛。", "異縣交遊少，中原信息稀。", "王師戰甚苦，方解蔡州圍。"]'),
('14d05df5-81c8-495a-95cf-eb909c64ec21','即事  其六','章甫','宋','宋诗','song-poetry','','[]','弟妹今安在，飄零各賤貧。',48,'全唐诗/poet.song.156000.json','["弟妹今安在，飄零各賤貧。", "詩成難寄遠，目斷更傷神。", "風俗殊方異，交情白首新。", "辛勤營一飽，媿此百年身。"]'),
('a9f22da9-4a59-4989-92f2-99e29a79b4a4','即事  其七','章甫','宋','宋诗','song-poetry','','[]','探報無虛日，淮東有捷音。',48,'全唐诗/poet.song.156000.json','["探報無虛日，淮東有捷音。", "周王方北伐，蠢動敢南侵。", "四海當多事，羣公在一心。", "祖宗功業盛，德澤結民深。"]'),
('e4680555-9878-4c4a-94d2-49aea5b8d3a7','即事  其八','章甫','宋','宋诗','song-poetry','','[]','兩淮仍蜀道，群寇再侵尋。',48,'全唐诗/poet.song.156000.json','["兩淮仍蜀道，群寇再侵尋。", "不戒兵猶火，唯誇旅若林。", "皇圖終復古，天意亦難諶。", "咨爾無猖獗，須思後患深。"]'),
('8ec3b02b-d929-48a0-880c-713a3a4327ae','即事  其九','章甫','宋','宋诗','song-poetry','','[]','羣寇仍猖獗，城邊即棄捐。',48,'全唐诗/poet.song.156000.json','["羣寇仍猖獗，城邊即棄捐。", "休兵雖上策，講信竟虛傳。", "人事今如此，天心恐未然。", "忍令唇齒地，重此染腥羶。"]'),
('de4698df-b1cb-44be-a2e6-39b6ba578b31','即事  其一○','章甫','宋','宋诗','song-poetry','','[]','初失清河口，駸駸遂逼人。',48,'全唐诗/poet.song.156000.json','["初失清河口，駸駸遂逼人。", "餘生偷歲月，無處避風塵。", "精銳看諸將，謀謨仰大臣。", "愞夫憂國淚，欲忍已沾巾。"]'),
('d06ec58b-2d12-4182-860f-966e96816b11','江北','章甫','宋','宋诗','song-poetry','','[]','江北多戎馬，江南有戰船。',48,'全唐诗/poet.song.156000.json','["江北多戎馬，江南有戰船。", "艱難吾欲老，輾轉夜無眠。", "歸去須三逕，飄零又一年。", "鄰舟聽客語，愁絕晚來天。"]'),
('28e03e9e-3028-4cea-a3ad-5da3b2158595','山行','章甫','宋','宋诗','song-poetry','','[]','江行風浪惡，石路僕夫勞。',48,'全唐诗/poet.song.156000.json','["江行風浪惡，石路僕夫勞。", "一水幾回度，亂山無數高。", "村醪清似鏡，早稻細如毛。", "愁聽田家語，令人首屢搔。"]'),
('3149c143-4415-47cf-a8a3-2f7bb3da5794','松滋縣作','章甫','宋','宋诗','song-poetry','','[]','月近中秋白，雲隨落日橫。',48,'全唐诗/poet.song.156000.json','["月近中秋白，雲隨落日橫。", "途窮諳客味，歲晚見交情。", "念舊傷存沒，憂時尚戰爭。", "西風催起柁，鷗鷺莫寒盟。"]'),
('fdbb4335-a7c4-4a0a-ae31-fc392b4e5f46','十二月朔巢縣道中','章甫','宋','宋诗','song-poetry','','[]','瘦馬從摇兀，行裝更寂寥。',48,'全唐诗/poet.song.156000.json','["瘦馬從摇兀，行裝更寂寥。", "老來寧浪出，此去有佳招。", "歲暮風霜苦，山長舘舍遥。", "兒曹應念我，今日是生朝。"]'),
('cdf7bca3-e4b6-4936-aabd-4c12a7a19dd8','守倅元日唱酬次韻','章甫','宋','宋诗','song-poetry','','[]','別駕篇章敏，黄堂句法新。',48,'全唐诗/poet.song.156000.json','["別駕篇章敏，黄堂句法新。", "宜民多受福，把筆競題春。", "拖玉丹墀曉，鳴珂紫陌塵。", "退朝如有作，應亦念茲辰。"]'),
('6b7bd465-94d7-4909-886f-4744e8ecf27f','舟中簡祖顯  其一','章甫','宋','宋诗','song-poetry','','[]','計拙生無益，時危老可傷。',48,'全唐诗/poet.song.156000.json','["計拙生無益，時危老可傷。", "江山雙敝屣，詩酒一空囊。", "夜雨茆廬破，秋風菊逕荒。", "閒隨枕流客，蓑笠釣滄浪。"]'),
('d9517880-ca1b-4dd1-a1d9-1133d235f510','舟中簡祖顯  其二','章甫','宋','宋诗','song-poetry','','[]','散髮扁舟上，秋江一段清。',48,'全唐诗/poet.song.156000.json','["散髮扁舟上，秋江一段清。", "魚肥新入饌，鷗狎舊同盟。", "浦樹參差出，雲山遠近迎。", "君詩妙圖寫，不減謝宣城。"]'),
('1dfb97d0-bdc4-4dba-b833-913f0baed7d6','雨中簡孫文輔  其一','章甫','宋','宋诗','song-poetry','','[]','多病愁陰晦，長貧慣寂寥。',48,'全唐诗/poet.song.156000.json','["多病愁陰晦，長貧慣寂寥。", "一江雲漠漠，十日雨瀟瀟。", "蛙黽誇秋水，魚蝦趁晚潮。", "新來疏酒盞，頗覺負清宵。"]'),
('c54c6cf7-19fe-45f8-b221-db7d836661ef','雨中簡孫文輔  其二','章甫','宋','宋诗','song-poetry','','[]','馬瘦憑誰相，龜靈故自焦。',48,'全唐诗/poet.song.156000.json','["馬瘦憑誰相，龜靈故自焦。", "世途何偪仄，物性各逍遥。", "君老嗟黄綬，吾衰感黑貂。", "雨寒無病惱，酒熟即招邀。"]'),
('5d93efb6-9c2f-4910-8911-54f1ebba38d7','雨中簡孫文輔  其三','章甫','宋','宋诗','song-poetry','','[]','寂寂諸緣省，緜緜一氣存。',48,'全唐诗/poet.song.156000.json','["寂寂諸緣省，緜緜一氣存。", "心情親藥裹，口味減盤飱。", "龐藴無生話，維摩不二門。", "秋聲摇萬壑，落葉會歸根。"]'),
('1ec7423a-6570-4344-86a0-4edf025da5e2','贈李君玉  其一','章甫','宋','宋诗','song-poetry','','[]','奔走空塵土，歸來日暝時。',48,'全唐诗/poet.song.156000.json','["奔走空塵土，歸來日暝時。", "喜迎蓮社客，細說錦囊詩。", "短世相逢晚，高樓欲下遲。", "坐中無賀監，誰與解金龜。"]'),
('e218ea34-9c1c-4691-895c-d53539d03a8b','贈李君玉  其二','章甫','宋','宋诗','song-poetry','','[]','老大何堪客，窮愁畧不醒。',48,'全唐诗/poet.song.156000.json','["老大何堪客，窮愁畧不醒。", "髮因閒事白，眼爲好山青。", "月下南飛鵲，風前自照螢。", "倚君如玉樹，蒲柳愧雕零。"]'),
('3944beea-9454-459f-9e37-356aa77295ff','登譙樓','章甫','宋','宋诗','song-poetry','','[]','老大心雖懶，登臨眼尚明。',48,'全唐诗/poet.song.156000.json','["老大心雖懶，登臨眼尚明。", "水流春後暖，樓迥晚來晴。", "翔集鳩無數，歸飛雁一鳴。", "闌干成獨倚，愁絕莫雲平。"]'),
('60fe1bdc-a153-414d-891d-a629587ba524','次郝澤民韻','章甫','宋','宋诗','song-poetry','','[]','歸雁衝寒去，棲烏向日啼。',48,'全唐诗/poet.song.156000.json','["歸雁衝寒去，棲烏向日啼。", "山明初過雨，沙靜不多泥。", "江上梅花細，村中酒價低。", "無人可同出，課僕理荒畦。"]'),
('c5f5ccb0-385b-465d-b4aa-2324de5404b5','次通一見詒韻','章甫','宋','宋诗','song-poetry','','[]','酒力添春意，詩魔惱夜眠。',48,'全唐诗/poet.song.156000.json','["酒力添春意，詩魔惱夜眠。", "老來尤惜日，客裏又逢年。", "送雁寒雲外，尋梅野水邊。", "無錢供劇飲，空枉故人篇。"]'),
('47daada2-06ef-45d9-8c6d-e26820aa09f6','送任政道','章甫','宋','宋诗','song-poetry','','[]','蕭寺同時客，交情子更深。',48,'全唐诗/poet.song.156000.json','["蕭寺同時客，交情子更深。", "有時長共說，無事即相尋。", "臨水初分袂，因風數寄音。", "青雲如得路，珍重歲寒心。"]'),
('02da699b-2605-4130-b2ee-3f3a14cb51e5','和沈商卿次前韻  其一','章甫','宋','宋诗','song-poetry','','[]','故人邊上去，春到未還家。',48,'全唐诗/poet.song.156000.json','["故人邊上去，春到未還家。", "奔走因王事，艱難感歲華。", "詩壇推俊逸，醉帽想欹斜。", "莫怪書題少，新年眼更花。"]'),
('3c038ba7-0e8b-4a82-b637-1f0285b1feee','和沈商卿次前韻  其二','章甫','宋','宋诗','song-poetry','','[]','逢人問行李，幾日至東園。',48,'全唐诗/poet.song.156000.json','["逢人問行李，幾日至東園。", "別去將三月，書來得五言。", "淮山分限域，風土異寒暄。", "四大知安穩，根塵要反源。"]'),
('23ac7ef3-7bcd-441d-8933-94406dc8c5ec','王漕舟行邵伯枯河之間一花獨秀有詩次韻','章甫','宋','宋诗','song-poetry','','[]','志在冥鴻上，舟行白鷺羣。',48,'全唐诗/poet.song.156000.json','["志在冥鴻上，舟行白鷺羣。", "水花明晚色，詩態藹春雲。", "獨立興三歎，孤斟爲十分。", "錦囊曾不惜，還遣野人聞。"]'),
('85194b9d-987b-4f35-8359-5d1a602b0a8d','陪王漕右司遊東園  其一','章甫','宋','宋诗','song-poetry','','[]','籍甚皇華使，詩清思不羣。',48,'全唐诗/poet.song.156000.json','["籍甚皇華使，詩清思不羣。", "建臺多暇日，領客總能文。", "花好杯重勸，茶香手自分。", "禮寬情爛熳，小雨夜深聞。"]'),
('b88d4918-626c-4dbc-ac95-14b31acc8240','陪王漕右司遊東園  其二','章甫','宋','宋诗','song-poetry','','[]','不到東園久，從公喜再遊。',48,'全唐诗/poet.song.156000.json','["不到東園久，從公喜再遊。", "名花移別島，新築俯長流。", "蕩漾扁舟穩，回還一徑幽。", "胸中擅邱壑，此地得冥搜。"]'),
('c291c270-bcbe-4358-9e1e-fccafff390e3','陪王漕右司遊東園  其三','章甫','宋','宋诗','song-poetry','','[]','晝永花紅困，烟輕草綠齊。',48,'全唐诗/poet.song.156000.json','["晝永花紅困，烟輕草綠齊。", "緩行金瑣細，爛醉玉東西。", "棋局觀成敗，河魚入品題。", "門闌老賓客，勝處謝招携。"]'),
('056d8c83-0a36-47db-b492-d9d38486be01','再用前韻  其一','章甫','宋','宋诗','song-poetry','','[]','公合麒麟畫，吾今麋鹿羣。',48,'全唐诗/poet.song.156000.json','["公合麒麟畫，吾今麋鹿羣。", "別離頻換歲，夢寐昔論文。", "寒盡春生後，涇清渭濁分。", "喜還親几席，語妙得時聞。"]'),
('af9ca08f-5a01-4020-a5f6-fe24efcafbd2','再用前韻  其二','章甫','宋','宋诗','song-poetry','','[]','黄闥清華選，湖山爛熳遊。',48,'全唐诗/poet.song.156000.json','["黄闥清華選，湖山爛熳遊。", "秋筠同節操，春柳似風流。", "鬚鬢莖莖白，園林事事幽。", "天然詩句好，初不待窮搜。"]'),
('f82abdd6-81da-42ab-8150-b1463c9f178e','再用前韻  其三','章甫','宋','宋诗','song-poetry','','[]','紅紫今無幾，寒暄尚未齊。',48,'全唐诗/poet.song.156000.json','["紅紫今無幾，寒暄尚未齊。", "春愁人更瘦，午醉日還西。", "課僕除新草，呼兒檢舊題。", "空庭可徐步，藜杖故相携。"]'),
('2bf376be-a08e-4723-adbe-400daedda279','次王勉夫見招  其一','章甫','宋','宋诗','song-poetry','','[]','浪迹踰三紀，知音只數公。',48,'全唐诗/poet.song.156000.json','["浪迹踰三紀，知音只數公。", "拙非今日用，愚與古人同。", "賓客雖常滿，簞瓢或屢空。", "躬耕逢歲旱，拄杖立西風。"]'),
('c94fcb15-3be3-4e7e-b059-03094c1fc890','次王勉夫見招  其二','章甫','宋','宋诗','song-poetry','','[]','風月分公宇，圖書靜客堂。',48,'全唐诗/poet.song.156000.json','["風月分公宇，圖書靜客堂。", "交情知爛熳，暇日想倘徉。", "我老嗟筋力，詩成損腎腸。", "報章慚不敏，秋至足悲傷。"]'),
('d97bb023-f98e-457d-acb8-e7bf0774ea39','送謝王夢得監稅借示詩卷兼簡王僉  其一','章甫','宋','宋诗','song-poetry','','[]','人入江西社，詩參活句禪。',48,'全唐诗/poet.song.156000.json','["人入江西社，詩參活句禪。", "盤珠無滯迹，溪月有餘妍。", "不采龐公藥，宜先祖逖鞭。", "淹留茆屋底，愁坐算商船。"]'),
('dca6bdba-4501-4601-8311-17dac2e268b4','送謝王夢得監稅借示詩卷兼簡王僉  其二','章甫','宋','宋诗','song-poetry','','[]','歲月易飄忽，文章空怪奇。',48,'全唐诗/poet.song.156000.json','["歲月易飄忽，文章空怪奇。", "宦遊君未達，耕種我長饑。", "事往休三歎，春來又幾時。", "官閒宜把酒，蓮幕最相知。"]'),
('7541e4d8-4943-4ade-968d-289a283d70ae','憶弟妹','章甫','宋','宋诗','song-poetry','','[]','新年思弟妹，何處有田園。',48,'全唐诗/poet.song.156000.json','["新年思弟妹，何處有田園。", "見面寧無日，傷心不忍言。", "飄零空歲晚，契闊又春暄。", "腸斷東來水，滔滔共一源。"]'),
('b48679b1-6ddd-4f37-a8a9-05f5e2d06d89','憂旱','章甫','宋','宋诗','song-poetry','','[]','貧賤甘羈旅，淹留頼薄田。',48,'全唐诗/poet.song.156000.json','["貧賤甘羈旅，淹留頼薄田。", "悠悠將送老，比比不逢年。", "旱魃工爲虐，雷公豈易鞭。", "醉能忘萬事，安得酒如川。"]'),
('75fd3aa1-e928-40c7-9421-23f487270701','白露  其一','章甫','宋','宋诗','song-poetry','','[]','歲旱今如此，天高豈不聞。',48,'全唐诗/poet.song.156000.json','["歲旱今如此，天高豈不聞。", "家家望秋穀，日日有閒雲。", "聖主焦勞甚，羣公獻納勤。", "老農愁欲死，祈禱漫紛紜。"]'),
('d3638e22-764b-4b35-b639-c730f0873329','白露  其二','章甫','宋','宋诗','song-poetry','','[]','烈日照平野，狂風吹槁苗。',48,'全唐诗/poet.song.156000.json','["烈日照平野，狂風吹槁苗。", "皇天無一雨，白露只明朝。", "世路多艱險，人心恐動摇。", "愁來唯有酒，聊以永今宵。"]'),
('ff5b6dfb-4ceb-496a-807e-d8635b314d1a','薦饑  其一','章甫','宋','宋诗','song-poetry','','[]','隴畝還枯旱，鉏犂謾苦辛。',48,'全唐诗/poet.song.156000.json','["隴畝還枯旱，鉏犂謾苦辛。", "饑寒知不免，盜賊恐相因。", "憂國書生志，安民聖主仁。", "豐凶端有數，天本愛斯民。"]'),
('2e1909f5-a7a1-4cf4-82fb-79dd345444e1','薦饑  其二','章甫','宋','宋诗','song-poetry','','[]','久客身長健，頻年穀不登。',48,'全唐诗/poet.song.156000.json','["久客身長健，頻年穀不登。", "天時有差忒，人事亦因仍。", "鵬運溟南北，魚呼水斗升。", "世途惟論報，誰飯在家僧。"]'),
('00be8f14-f7bc-4398-a6b5-cb58c9c05eeb','和俞若晦晚步','章甫','宋','宋诗','song-poetry','','[]','日落帆歸疾，天寒潮應遲。',48,'全唐诗/poet.song.156000.json','["日落帆歸疾，天寒潮應遲。", "老蟾還照客，宿鳥未安枝。", "懷抱難忘酒，工夫不到詩。", "徘徊江上路，此意有誰知。"]'),
('1de03ca3-014c-47f7-a758-6bf1530f1cf3','閏月二日清坐  其一','章甫','宋','宋诗','song-poetry','','[]','淮海秋風日，柴荆老病夫。',48,'全唐诗/poet.song.156000.json','["淮海秋風日，柴荆老病夫。", "詩因窮處得，愁到酒邊無。", "俗物妨青眼，浮生喜白鬚。", "繩床供午寢，清夢落江湖。"]'),
('e9da2bcd-b307-48bf-9846-c0fc480b3b85','閏月二日清坐  其二','章甫','宋','宋诗','song-poetry','','[]','秋閏遲收穫，年衰惜友朋。',48,'全唐诗/poet.song.156000.json','["秋閏遲收穫，年衰惜友朋。", "每懷人似玉，安得酒如澠。", "鵲語何多誕，蟬聲故可憎。", "茶香新落磨，亦足洗炎蒸。"]'),
('7564ea51-9806-4071-8fa8-18420ec02941','聞下親征詔志喜','章甫','宋','宋诗','song-poetry','','[]','聞下親征詔，軍民喜溢顔。',48,'全唐诗/poet.song.156000.json','["聞下親征詔，軍民喜溢顔。", "天威方一怒，國步久多艱。", "思古傷心處，平戎反掌間。", "書生苦衰懦，空使鬢毛斑。"]'),
('344e264c-d467-4c93-9dd3-1c6a28fb1f23','秋日  其一','章甫','宋','宋诗','song-poetry','','[]','奔走傷形役，艱難感物華。',48,'全唐诗/poet.song.156000.json','["奔走傷形役，艱難感物華。", "澹烟籠遠樹，小雨濕寒沙。", "喚客尊無酒，撩人菊有華。", "弟兄書不至，過盡雁行斜。"]'),
('39cfd021-14a9-45e5-ac77-832cea29fce2','秋日  其二','章甫','宋','宋诗','song-poetry','','[]','故人多鬼錄，久客又驚秋。',48,'全唐诗/poet.song.156000.json','["故人多鬼錄，久客又驚秋。", "爲計無三窟，懷歸在一丘。", "雞鳴風雨晦，雁急稻粱謀。", "憶我山中友，天寒夜飯牛。"]'),
('a4ae6ce1-542e-444b-9872-a53010e33da8','清宇移居','章甫','宋','宋诗','song-poetry','','[]','懷抱俱牢落，相逢得暫開。',48,'全唐诗/poet.song.156000.json','["懷抱俱牢落，相逢得暫開。", "有時逃酒去，排日送詩來。", "撫事空三歎，移家又一回。", "秋涼安穩住，莫負菊花杯。"]'),
('3775f6aa-5d00-4691-9f16-159d6b21ec2b','九日壽之見過','章甫','宋','宋诗','song-poetry','','[]','老去猶耽酒，歸來自撥醅。',48,'全唐诗/poet.song.156000.json','["老去猶耽酒，歸來自撥醅。", "絕憐黄菊好，仍有故人來。", "懷古空三歎，挼香更一杯。", "橫山無十里，騎馬未須回。"]'),
('5bc4bd16-dc4f-4cd8-a358-ddf81ce9b716','過清宇新居再用開字韻  其一','章甫','宋','宋诗','song-poetry','','[]','市遠囂塵息，窗明老眼開。',48,'全唐诗/poet.song.156000.json','["市遠囂塵息，窗明老眼開。", "句從天外得，書自日邊來。", "久住當成趣，相看不忍回。", "涼生初却扇，月出好銜杯。"]'),
('360c5d9a-60ed-4fe2-b595-59f6fd3969dc','過清宇新居再用開字韻  其二','章甫','宋','宋诗','song-poetry','','[]','書帙兒能整，柴扉手自開。',48,'全唐诗/poet.song.156000.json','["書帙兒能整，柴扉手自開。", "夢殘江月上，酒醒竹風來。", "舊集秋重校，微吟日幾回。", "初無俗客飯，當有故人杯。"]'),
('434922ff-ea01-4eb3-9970-eca6c7550689','送孟希道','章甫','宋','宋诗','song-poetry','','[]','異縣交游少，隣牆歲月深。',48,'全唐诗/poet.song.156000.json','["異縣交游少，隣牆歲月深。", "肴蔬長共醉，風雨亦相尋。", "去路逾千里，離筵惜寸陰。", "功名君努力，衰病我何心。"]'),
('021b198c-cdda-4bd0-a5eb-1229f3fd2b0b','寄棻菴主','章甫','宋','宋诗','song-poetry','','[]','問訊棻菴主，菴中事若何。',48,'全唐诗/poet.song.156000.json','["問訊棻菴主，菴中事若何。", "得詩堪供佛，學道想無魔。", "關塞兵戈定，江湖歲月多。", "他年白蓮社，藜杖飽經過。"]'),
('c794cfdd-0863-415b-96e9-9ec4a4076522','秋興','章甫','宋','宋诗','song-poetry','','[]','宿昔驅蠅手，今還把蟹螯。',48,'全唐诗/poet.song.156000.json','["宿昔驅蠅手，今還把蟹螯。", "家愁難止酒，天氣近登高。", "歲月形容改，鄉關夢寐勞。", "小窗無晤對，風葉暮蕭騷。"]'),
('6af875f0-e579-42bb-8d70-008e19ff8e63','答仲韓醉中見和','章甫','宋','宋诗','song-poetry','','[]','外事添蛇足，餘生嚼𧑅螯。',48,'全唐诗/poet.song.156000.json','["外事添蛇足，餘生嚼𧑅螯。", "牀頭新酒熟，江上遠山高。", "紀詠能偷暇，登臨莫憚勞。", "獨醒誠可笑，辛苦賦離騷。"]'),
('6a52059b-4b13-4887-a766-1d50603d22ef','春日山居  其一','章甫','宋','宋诗','song-poetry','','[]','流轉情何限，艱難老見侵。',48,'全唐诗/poet.song.156000.json','["流轉情何限，艱難老見侵。", "兒啼妨午睡，花落攪春心。", "得句從誰說，開尊祇自斟。", "移家近城市，湖水幾時深。"]'),
('a337c279-31fc-46a7-8d31-bb6b8b0e486e','春日山居  其二','章甫','宋','宋诗','song-poetry','','[]','客舍逢迎少，村居道路迷。',48,'全唐诗/poet.song.156000.json','["客舍逢迎少，村居道路迷。", "雨晴知虎過，烟暝有鴉啼。", "輕薄看諸子，辛勤愧老妻。", "人生真寄耳，巢燕亦添泥。"]'),
('78fe7926-f7bf-41b4-8ef6-b596f1368e42','春日山居  其三','章甫','宋','宋诗','song-poetry','','[]','村陋渾成俗，雲山要可人。',48,'全唐诗/poet.song.156000.json','["村陋渾成俗，雲山要可人。", "短籬雞唱午，芳樹鳥啼春。", "地僻愁仍少，身閒懶更真。", "扁舟因送客，重到大江濱。"]'),
('b819d731-193a-410d-b242-1a065451ffb4','登樓','章甫','宋','宋诗','song-poetry','','[]','空室才容膝，樓高適與隣。',48,'全唐诗/poet.song.156000.json','["空室才容膝，樓高適與隣。", "清秋宜眺遠，瘦策故來頻。", "鳥雀寧知我，江山不厭人。", "哦詩兼把酒，地主未嘗嗔。"]'),
('82dc846c-86d1-48b3-89e1-f69c4c3e1c3a','卜煥之求雙竹','章甫','宋','宋诗','song-poetry','','[]','結屋清江上，憐君雅趣深。',48,'全唐诗/poet.song.156000.json','["結屋清江上，憐君雅趣深。", "自移雙竹種，分得半簷陰。", "特立夷齊節，相看管鮑心。", "祇應風雨夜，聽此兩龍吟。"]'),
('6c1b6e12-4a33-4a9c-8cf9-a53e22251e38','問祖顯疾  其一','章甫','宋','宋诗','song-poetry','','[]','念子何多病，逢人問好音。',48,'全唐诗/poet.song.156000.json','["念子何多病，逢人問好音。", "可無安樂法，未用短長吟。", "陋巷隣南北，春風酒淺深。", "杯蛇弓落影，應已斷疑心。"]'),
('cb0bd379-6445-4cb6-8780-531d7cba366f','問祖顯疾  其二','章甫','宋','宋诗','song-poetry','','[]','隠几維摩詰，傷春杜拾遺。',48,'全唐诗/poet.song.156000.json','["隠几維摩詰，傷春杜拾遺。", "觀身如聚沫，憂國正攢眉。", "藥裹添新說，腰圍減舊時。", "朝來强飯不，問訊一憑詩。"]'),
('d903eafa-0c4a-4134-a095-9b682d260679','送野堂禪師赴蔡公寶文之招','章甫','宋','宋诗','song-poetry','','[]','早歲識諸公，雙眸四海空。',48,'全唐诗/poet.song.156000.json','["早歲識諸公，雙眸四海空。", "叢林今日異，風月往時同。", "晚境無茆屋，秋江又釣篷。", "毗耶大居士，游戲有神通。"]'),
('a3339efd-e1e5-43b9-a910-16af32214c03','次惠老見詒','章甫','宋','宋诗','song-poetry','','[]','別去忽三紀，餘生能幾年。',48,'全唐诗/poet.song.156000.json','["別去忽三紀，餘生能幾年。", "相看雙眼碧，且喜一燈傳。", "禪病君無惱，詩狂我欲仙。", "劇談成絕倒，還似蜜中邊。"]'),
('cedefe70-7b7a-4d00-a391-e4e8de9cefa8','次郭遐齡所携張安國詩韻','章甫','宋','宋诗','song-poetry','','[]','早作諸公客，過門競挽留。',48,'全唐诗/poet.song.156000.json','["早作諸公客，過門競挽留。", "憂時心尚壯，懷舊涕難收。", "富貴來何晚，文章老更優。", "尊前身健在，不必問封侯。"]'),
('aab97638-a172-476a-a18a-882616db3f94','和韓丈雪晴','章甫','宋','宋诗','song-poetry','','[]','天公逞巧逐時新，戲把乾坤作爛銀。',64,'全唐诗/poet.song.156000.json','["天公逞巧逐時新，戲把乾坤作爛銀。", "浄壓邊塵無戰馬，寒持使節有詩人。", "夜長霜月爭催曉，年近江山逼放春。", "歸壽高堂先一醉，稱觴漢殿及嘉辰。"]'),
('700bc6a6-a73c-42b7-ad90-0c4e02d7ee90','春望','章甫','宋','宋诗','song-poetry','','[]','東風吹水豈容平，小雨催花却易晴。',64,'全唐诗/poet.song.156000.json','["東風吹水豈容平，小雨催花却易晴。", "旅燕欲來春社近，故人何處晚山橫。", "不才媿忝諸侯客，苦思難攻五字城。", "芳草滿庭無一事，竹間幽鳥變新聲。"]'),
('a9cbd5f1-cafb-4786-a1eb-d44eb204f276','送張揚子','章甫','宋','宋诗','song-poetry','','[]','堂上絃歌吏早休，三年官舍冷於秋。',64,'全唐诗/poet.song.156000.json','["堂上絃歌吏早休，三年官舍冷於秋。", "諸公極力爭推挽，野老何知欲借留。", "去矣青雲皆坦路，歸歟明月只扁舟。", "都城故舊如相問，草滿空山自牧牛。"]'),
('6ace110c-9311-4263-82a2-cfceed7a79ec','憶王履方','章甫','宋','宋诗','song-poetry','','[]','江頭今日少風埃，時有閒雲出斷崖。',64,'全唐诗/poet.song.156000.json','["江頭今日少風埃，時有閒雲出斷崖。", "入網河豚來近市，爭巢野鵲墮空階。", "偶行芳草得佳句，不見故人無好懷。", "愁送客帆西去盡，日隨潮水到秦淮。"]'),
('64f7875c-3754-48bf-9b9a-46040b07af5a','送張玉叔','章甫','宋','宋诗','song-poetry','','[]','春風端的解相期，吹盡桃花作雨飛。',64,'全唐诗/poet.song.156000.json','["春風端的解相期，吹盡桃花作雨飛。", "政苦無錢供劇飲，可堪臨水送將歸。", "窮愁度日添詩卷，老病憂時減带圍。", "後夜思君望銀漢，雙星會處有光輝。"]'),
('898e5d7f-0563-4a7e-8d38-0990d6260f5f','送李清宇','章甫','宋','宋诗','song-poetry','','[]','行李過門復小留，劇譚同此小窗幽。',64,'全唐诗/poet.song.156000.json','["行李過門復小留，劇譚同此小窗幽。", "三杯酒力客愁破，一夜雨聲春事休。", "舊燕尋巢元未毀，新鶑出谷自相求。", "槐牙準擬供湯餠，初夏重來定到不。"]'),
('a30853f1-7bcc-4467-9525-cf4f6ce1b360','和韓無咎使君弔李謫仙','章甫','宋','宋诗','song-poetry','','[]','力士能令妃子嗔，長安無復謫仙人。',64,'全唐诗/poet.song.156000.json','["力士能令妃子嗔，長安無復謫仙人。", "宮袍却換江東酒，野服終爲帝外臣。", "孤冢道旁空怨結，兩峯烟際自愁顰。", "騎鯨捉月知何在，太白光芒夜夜新。"]'),
('104f67ba-c63d-41df-a1bf-f3f884666381','賢府主禱雪而應喜極有詩','章甫','宋','宋诗','song-poetry','','[]','湖海雙魚久不傳，幽人門巷轉蕭然。',64,'全唐诗/poet.song.156000.json','["湖海雙魚久不傳，幽人門巷轉蕭然。", "寒威直與酒爲地，雪片忽共梅爭妍。", "自撥小爐猶有火，擬留佳客苦無錢。", "金篦刮眼何時得，咫尺春風欲換年。"]'),
('8025ffeb-b8b8-49d2-83c9-c13f771fafd4','和朱少翁除夕','章甫','宋','宋诗','song-poetry','','[]','破曉東風又磔雞，人心物態兩推移。',64,'全唐诗/poet.song.156000.json','["破曉東風又磔雞，人心物態兩推移。", "建瓴歲月今將老，漂梗江湖少不羈。", "獨坐舊諳爲客味，長愁新賦悼亡詩。", "多慙府主鶑花約，歸去西疇恐後期。"]'),
('f9a76968-629f-4bc1-bb93-6880ce0dc08e','送十八兄','章甫','宋','宋诗','song-poetry','','[]','故園別去踰三紀，男子生來志四方。',64,'全唐诗/poet.song.156000.json','["故園別去踰三紀，男子生來志四方。", "千里勞君雙足趼，百窮笑我兩眉長。", "雪深客舍衣裘冷，春晚家山杖履香。", "歸省松楸終有日，臨分老淚亦沾裳。"]'),
('5f06717e-92a0-4d71-bd0d-bb569e0a9718','苦旱','章甫','宋','宋诗','song-poetry','','[]','巫歌瓦鼓自村村，下鬼安能謁帝閽。',64,'全唐诗/poet.song.156000.json','["巫歌瓦鼓自村村，下鬼安能謁帝閽。", "盡室每愁風卷屋，何時得見雨翻盆。", "久無蚯蚓來堂上，頗說飛蝗集穀根。", "投老躬耕營一飽，客懷歲晚不堪論。"]'),
('2aba3ec7-1be0-4c95-90d4-71ce5cce7306','送張安國','章甫','宋','宋诗','song-poetry','','[]','萬里烟霄早致身，一麾到處作陽春。',64,'全唐诗/poet.song.156000.json','["萬里烟霄早致身，一麾到處作陽春。", "隨時用舍知無慍，落筆縱橫信有神。", "江國雲山愁送遠，桂林風土獨宜人。", "笑談坐懾羣偷化，便合歸來據要津。"]'),
('de845db5-d0f4-459c-8a3c-00044d578f03','和周師禹所寄','章甫','宋','宋诗','song-poetry','','[]','九載光陰俯仰間，百年人世幾悲懽。',64,'全唐诗/poet.song.156000.json','["九載光陰俯仰間，百年人世幾悲懽。", "竹樓夢斷傷春晚，雲壑書來喜歲寒。", "別久更憐詩筆健，愁多須放酒杯寬。", "相望江北江南路，柳絮隨風又作團。"]'),
('356590c6-9c78-4102-85e2-2d0896eecb26','次仲韓韻兼簡若晦','章甫','宋','宋诗','song-poetry','','[]','世途時事兩艱難，上水船行八節灘。',64,'全唐诗/poet.song.156000.json','["世途時事兩艱難，上水船行八節灘。", "旅雁喚愁秋已盡，隣雞驚夢夜將闌。", "醉狂終是心情懶，老瘦非關骨相寒。", "閒憶能詩俞與趙，久無妙語發毫端。"]'),
('b18a36ac-4e5f-4994-a03f-7c8ca0221d98','張王臣自湖南官滿趨朝舟過白沙和惠資福二詩末章見及次韻  其一','章甫','宋','宋诗','song-poetry','','[]','別來身世轉乖違，老病交攻若有期。',64,'全唐诗/poet.song.156000.json','["別來身世轉乖違，老病交攻若有期。", "目力半昏難結字，心情全懶罷吟詩。", "魚沉湖海無書日，犬吠柴荆有客時。", "三逕莫嫌猶寂寞，地偏花木得春遲。"]'),
('76bda1c6-4b72-4b73-9516-7994c409d09d','張王臣自湖南官滿趨朝舟過白沙和惠資福二詩末章見及次韻  其二','章甫','宋','宋诗','song-poetry','','[]','叢桂書齋念昔遊，紅蓮幕府喜歸休。',64,'全唐诗/poet.song.156000.json','["叢桂書齋念昔遊，紅蓮幕府喜歸休。", "秋風起舵蒹葭渚，春月停橈杜若洲。", "未用把詩輕萬戶，直須呼酒散千憂。", "贊公亦是江湖舊，更問君能少住不。"]'),
('6f620f7f-624a-4c1f-9429-a03b342d2e27','次張子儀韻','章甫','宋','宋诗','song-poetry','','[]','半生江海慣浮游，邂逅今成客此州。',64,'全唐诗/poet.song.156000.json','["半生江海慣浮游，邂逅今成客此州。", "憂國幸逢年穀熟，望鄉長恨晚山稠。", "連天烟雨雙鴻雁，滿地風波一白鷗。", "獨把酒杯悲節物，何時弟勸與兄酬。"]'),
('ab318ce7-e80d-4277-994a-07e7e6f86a77','燈夕韓使君惠谷簾泉','章甫','宋','宋诗','song-poetry','','[]','憶昨嬉遊不忍閒，祇今但欲掩柴關。',64,'全唐诗/poet.song.156000.json','["憶昨嬉遊不忍閒，祇今但欲掩柴關。", "短檠無恙客多病，明月有情天若慳。", "落日哦詩方袖手，故人憶我未還山。", "歸家且酌康廬水，恍墮千巖紫翠間。"]'),
('4b238b4f-7de3-4960-8a16-ecc61d78311d','和劉巖隠道士','章甫','宋','宋诗','song-poetry','','[]','青眼難逢阮步兵，白鬚新識老彌明。',64,'全唐诗/poet.song.156000.json','["青眼難逢阮步兵，白鬚新識老彌明。", "清談畧洗塵埃盡，妙句仍看欬唾成。", "休說有身真是患，但知得酒不須名。", "焦桐更倩揮毫手，要聽秋崖夜鶴鳴。"]'),
('4ed439b2-6549-4801-bf8a-8c5c01a55489','題天開圖畫','章甫','宋','宋诗','song-poetry','','[]','使君新築北城隈，舉酒標名繡斧來。',64,'全唐诗/poet.song.156000.json','["使君新築北城隈，舉酒標名繡斧來。", "一覽江山因勝地，四時圖畫自天開。", "坐令宋史空盤礴，豈有并刀解翦裁。", "暇日莫辭頻領客，年豐無事好銜杯。"]'),
('6aa8047b-5784-4281-ae3e-c41330e48c47','多日不收家信再和呈丁合州','章甫','宋','宋诗','song-poetry','','[]','郵亭盤礴已六日，清坐了無塵事隨。',64,'全唐诗/poet.song.156000.json','["郵亭盤礴已六日，清坐了無塵事隨。", "書寄弟兄猶未到，夢遊京浙不勝馳。", "江邊短艇雨千點，竹裏疎烟梅一枝。", "兒女未知爲客恨，但爭柑橘遶庭墀。"]'),
('53c420c7-79ea-491a-a394-576ef70f4ea3','呈胡德器','章甫','宋','宋诗','song-poetry','','[]','相逢縱酒又連旬，醉倒誰知主與賓。',64,'全唐诗/poet.song.156000.json','["相逢縱酒又連旬，醉倒誰知主與賓。", "舌在莫談當世事，眼明仍是故鄉人。", "不愁春與花俱減，但恨君如我更貧。", "淮上風烟隨分好，他年準擬作比鄰。"]'),
('399099d9-d46c-42e0-8cdd-da8ebb467df2','戲答王通一','章甫','宋','宋诗','song-poetry','','[]','底事重來淮上村，九關難上阻司閽。',64,'全唐诗/poet.song.156000.json','["底事重來淮上村，九關難上阻司閽。", "短衣他日欲射虎，堂印何時看倒盆。", "花著襟裾無定力，雪侵鬚鬢有愁根。", "天河且挽洗瘡疥，若問甲兵君莫論。"]'),
('355e5e8a-f639-4cd9-ae06-20e58b1fa55f','予歸自都梁魏子深來自滁州坐間酌酒','章甫','宋','宋诗','song-poetry','','[]','道路長年笑此身，絕憐塵土涴衣巾。',64,'全唐诗/poet.song.156000.json','["道路長年笑此身，絕憐塵土涴衣巾。", "飛花數點已愁客，歸雁一聲如喚人。", "州縣驅馳君欲老，江湖流落我常貧。", "相逢却恨成匆遽，不醉沙頭爛熳春。"]'),
('3a004fa1-e002-4f0c-ab04-801ed6b094af','寄荆南友人','章甫','宋','宋诗','song-poetry','','[]','餘生自拚一虛舟，未害尋詩慰客愁。',64,'全唐诗/poet.song.156000.json','["餘生自拚一虛舟，未害尋詩慰客愁。", "梅欲飄零猶醖藉，柳纔依約已風流。", "關心弟妹無黄犬，入夢江湖有白鷗。", "別後故人相念否，東風應倚仲宣樓。"]'),
('51730751-0db4-4646-ad1b-bf4332759315','過家留一夕曹丈復和韻再作','章甫','宋','宋诗','song-poetry','','[]','賢聖何曾時一中，扁舟但困打頭風。',64,'全唐诗/poet.song.156000.json','["賢聖何曾時一中，扁舟但困打頭風。", "按田外歎裹糧乏，還舍內嗟瓶粟空。", "論事時遭瞋目視，催科隔絕滿堂烘。", "匆匆結束又西邁，望眼却隨黄鵠東。"]'),
('41395388-6190-43f0-9c74-9ba9855545e1','九日','章甫','宋','宋诗','song-poetry','','["\u897f\u6e56"]','登高長是易銷魂，多病新來目更昏。',64,'全唐诗/poet.song.156000.json','["登高長是易銷魂，多病新來目更昏。", "强引兒童追節物，久拚身世任乾坤。", "江風冷拂烏紗帽，籬菊香浮老瓦盆。", "回首西湖如昨日，交遊凋謝不堪論。"]'),
('d75a2863-7fa9-4916-9f04-59b79d15f8d5','王夢得意久出遠歸惠詩次韻','章甫','宋','宋诗','song-poetry','','[]','手栽桃李已成花，久客歸心急莫鴉。',64,'全唐诗/poet.song.156000.json','["手栽桃李已成花，久客歸心急莫鴉。", "別後新詩圓似彈，依前瘦馬鈍如蛙。", "路長人困煎茶店，春去鶑啼賣酒家。", "三徑未荒還寄傲，只應清夢到京華。"]'),
('308c54b6-3d58-4c91-8106-2237f8cf7217','寄韓漕子雲','章甫','宋','宋诗','song-poetry','','[]','詔書淮上遂休兵，玉帛相隨下帝京。',64,'全唐诗/poet.song.156000.json','["詔書淮上遂休兵，玉帛相隨下帝京。", "且喜王師還禁衛，獨煩使節在邊城。", "轉輸積雪河冰合，離別春風塞草生。", "細札催歸應不晚，到家猶及趁清明。"]'),
('4a9bd881-0c8a-4f80-8743-51d69f6e0880','上黄漕','章甫','宋','宋诗','song-poetry','','[]','漢初曲逆未侯日，窮巷席門誰見收。',64,'全唐诗/poet.song.156000.json','["漢初曲逆未侯日，窮巷席門誰見收。", "固是知人甚難事，懸知同類合相求。", "客懷夜雨打破壁，世事春江橫釣舟。", "爲報能文韓吏部，吹噓籍湜預名流。"]'),
('94d5409b-1dcd-4300-8955-13e40c257619','雨中簡李牧之','章甫','宋','宋诗','song-poetry','','[]','提壺勸飲方多病，布穀催耕未有田。',64,'全唐诗/poet.song.156000.json','["提壺勸飲方多病，布穀催耕未有田。", "老去情懷非宿昔，日長圖史得周旋。", "客愁正是連山雨，時事渾如上水船。", "問訊詩翁無恙否，遥憐裋褐聳雙肩。"]'),
('a3ea62bf-16ad-4856-b71d-b17f83e817b3','燈夕戲簡胥直夫','章甫','宋','宋诗','song-poetry','','[]','小雨催耕苦未勻，東風吹水起魚鱗。',64,'全唐诗/poet.song.156000.json','["小雨催耕苦未勻，東風吹水起魚鱗。", "兵戈關塞今年定，燈火江城此夜新。", "萬點飛花愁客子，一天明月屬遊人。", "舊時面壁胥居士，何處笙歌作好春。"]'),
('944d5701-a59f-42ed-af3d-02cb89f45431','次韓無咎盱眙道中韻','章甫','宋','宋诗','song-poetry','','[]','人家過午絕炊烟，隴上羸牛挽不前。',64,'全唐诗/poet.song.156000.json','["人家過午絕炊烟，隴上羸牛挽不前。", "寇退皇恩方掩骼，民饑客飯只烹鮮。", "觀風到處春隨馬，楗水歸時月滿川。", "王事獨賢無倦色，雞鳴起坐屋三椽。"]'),
('273ba6b6-0444-4b61-bbbc-2b442104beb9','蘇訓直方夷吾相挽同飯招隠','章甫','宋','宋诗','song-poetry','','[]','登臨筋力猶如昨，興廢循環自有時。',64,'全唐诗/poet.song.156000.json','["登臨筋力猶如昨，興廢循環自有時。", "青石獨存超士傳，粉牌新得省郎詩。", "雲山改色風生座，野鹿無蹤水滿池。", "勝處只宜文字飲，不須紅袖苦追隨。"]'),
('63f7800d-d2d7-4d00-a953-28ca62668148','重九前一日示弟姪','章甫','宋','宋诗','song-poetry','','[]','人生百歲未易滿，我已五十仍加三。',64,'全唐诗/poet.song.156000.json','["人生百歲未易滿，我已五十仍加三。", "異縣長憐九月九，故園遠在南山南。", "綠尊青眼舊相得，黄菊白頭還好簪。", "明晨汝輩早同出，脚力躋攀吾尚堪。"]'),
('5c6b1255-dd6a-48ed-9129-65b76fdc8bbd','九日憶俞若晦','章甫','宋','宋诗','song-poetry','','[]','出處殊途會面難，君留湖上我江干。',64,'全唐诗/poet.song.156000.json','["出處殊途會面難，君留湖上我江干。", "黄花三度不同醉，白髮數莖尤寡歡。", "鶚立寥寥天地大，鴻飛漠漠水雲寒。", "登高時節還相憶，朝露誰憐墜木蘭。"]'),
('3c5264f9-577a-4ab7-bc2a-a58da6cd754c','愁坐','章甫','宋','宋诗','song-poetry','','[]','俗物滿前無好懷，可堪時序苦相催。',64,'全唐诗/poet.song.156000.json','["俗物滿前無好懷，可堪時序苦相催。", "飛蚊掃迹夜方靜，過雁傳聲寒已來。", "多病不勝杯瀲灧，遠遊只恐馬虺隤。", "書窗愁坐令人瘦，獨上江樓日幾回。"]'),
('66bc41f1-e93d-49d0-a758-49f75765ff35','同楊德駿任致道登北觀留題壁間','章甫','宋','宋诗','song-poetry','','[]','年來多病廢幽尋，眼底風光亦倦吟。',64,'全唐诗/poet.song.156000.json','["年來多病廢幽尋，眼底風光亦倦吟。", "歲暮情懷傷老大，雪晴筋力試登臨。", "一江烟水分南北，千里雲山自古今。", "杖屨頻來端不惡，只愁東望起歸心。"]'),
('70456609-3ec7-4420-b263-b1c7d2608708','春晚寺居即事','章甫','宋','宋诗','song-poetry','','[]','晚晴鳥雀喜窺簷，客舍餘寒怕卷簾。',64,'全唐诗/poet.song.156000.json','["晚晴鳥雀喜窺簷，客舍餘寒怕卷簾。", "多病新來知本草，安心老去讀楞嚴。", "髮稀帽側頭慵櫛，火冷香消手自添。", "百念不生惟飽飯，春山蔬筍十分甜。"]'),
('9f4147de-73c0-4111-bf3f-f48cddd19099','閒吟  其一','章甫','宋','宋诗','song-poetry','','[]','春風略不欺貧賤，美酒真堪託死生。',64,'全唐诗/poet.song.156000.json','["春風略不欺貧賤，美酒真堪託死生。", "芳草又依窮巷綠，殘尊重與故人傾。", "雨餘入饌添蔬筍，晝永欹眠憶弟兄。", "但得一廛供送老，更將詩頌紀昇平。"]'),
('04a89eec-bbe2-4e01-a055-96671376496f','閒吟  其二','章甫','宋','宋诗','song-poetry','','[]','梅花白盡柳初黄，春未平分日已長。',64,'全唐诗/poet.song.156000.json','["梅花白盡柳初黄，春未平分日已長。", "老眼明邊湖水綠，閒愁來處楚山蒼。", "高吟且喜詩無病，痛飲方知酒有腸。", "南北故人强健否，誰知旅鬢欲秋霜。"]'),
('fd9dce97-925e-4755-8414-ea870198c0fc','蒜山夜歸','章甫','宋','宋诗','song-poetry','','[]','雙雙鷗鳥落蒼灣，點點征帆返照間。',64,'全唐诗/poet.song.156000.json','["雙雙鷗鳥落蒼灣，點點征帆返照間。", "多病久無鐘鼎夢，忘機長伴水雲閒。", "江心古寺入圖畫，烟際好山如髻鬟。", "踏月歸時聞短笛，津頭知有釣舟還。"]'),
('f5e0caf2-9746-41c1-941a-4fc15a8689c8','野步','章甫','宋','宋诗','song-poetry','','[]','天寬地大我何憂，白首行歌得自由。',64,'全唐诗/poet.song.156000.json','["天寬地大我何憂，白首行歌得自由。", "窮既有神安可送，富如非義豈容求。", "四時無出三春好，萬事都拚一醉休。", "茅屋酒旗遥喚客，餘寒未許脫駝裘。"]'),
('7f4600ec-dc4c-4208-84b7-ca1881448de0','得蔡深源信','章甫','宋','宋诗','song-poetry','','[]','左右圖書一小軒，閉門謝客蔡深源。',64,'全唐诗/poet.song.156000.json','["左右圖書一小軒，閉門謝客蔡深源。", "別來三歲喜無恙，老去百懷誰與言。", "神魚不肯貪香鉺，天馬難令駕短轅。", "苦憶當年常款曲，茆簷軟語負朝暄。"]'),
('c31cfb68-2acc-4093-8740-03d942c243d1','簡唐先生谷','章甫','宋','宋诗','song-poetry','','[]','藩籬落日鳥雀閙，江湖西風鴻雁高。',64,'全唐诗/poet.song.156000.json','["藩籬落日鳥雀閙，江湖西風鴻雁高。", "病軀已厭秋夜永，農事更傷終歲勞。", "窮愁滿眼未容遣，俗物敗意時相遭。", "隠芝庵中有高士，拄杖請來同出遨。"]'),
('9f5d0a1e-0246-4cef-ad4c-bdf6762b13bc','送彬禪客','章甫','宋','宋诗','song-poetry','','[]','越王樓畔彬禪客，爲法南游蚤出關。',64,'全唐诗/poet.song.156000.json','["越王樓畔彬禪客，爲法南游蚤出關。", "曾駕鐵船衝巨浪，又携錫杖過他山。", "夢回故國非無侶，身比孤雲只獨閒。", "君到諸方如問我，年來多病鬢毛斑。"]'),
('c5f07ae4-ee4a-4736-9da3-3e91841782f0','即事','章甫','宋','宋诗','song-poetry','','[]','平邊活國不關儂，晝永新添炙背功。',64,'全唐诗/poet.song.156000.json','["平邊活國不關儂，晝永新添炙背功。", "鳩婦仳離天欲雨，鵲巢低穩歲多風。", "一彈指頃韶光半，微破顔時夢事空。", "但得餘生無病惱，從渠南北與西東。"]'),
('114c89c7-62a6-43be-8834-f428069c44ea','湖上吟','章甫','宋','宋诗','song-poetry','','[]','誰家短笛吹楊柳，何處扁舟唱采菱。',64,'全唐诗/poet.song.156000.json','["誰家短笛吹楊柳，何處扁舟唱采菱。", "湖水欲平風作惡，秋雲太薄雨無憑。", "近人白鷺麾方去，隔岸青山喚不譍。", "好景滿前難著語，夜歸茅屋望疏燈。"]'),
('665315cf-8db2-4a62-98ae-03ba44caee66','秋曉  其一','章甫','宋','宋诗','song-poetry','','[]','窗間耿殘燈，屋角照落月。',24,'全唐诗/poet.song.156000.json','["窗間耿殘燈，屋角照落月。", "披衣啟柴關，呼帚掃黄葉。"]'),
('f97945fb-4025-4626-aca0-7395a09f4fae','秋曉  其二','章甫','宋','宋诗','song-poetry','','[]','曉色殊未分，江風飄然起。',24,'全唐诗/poet.song.156000.json','["曉色殊未分，江風飄然起。", "開窗看芭蕉，露重葉如洗。"]'),
('755f5b82-a8c1-4300-a1dc-2c327786f1e9','秋曉  其三','章甫','宋','宋诗','song-poetry','','[]','不雨已三月，草木無光輝。',24,'全唐诗/poet.song.156000.json','["不雨已三月，草木無光輝。", "籬邊舊菊叢，生意良亦微。"]'),
('3c9ad66d-4d1d-4075-a430-ded2274fdc66','秋曉  其四','章甫','宋','宋诗','song-poetry','','[]','鴻雁何時來，肅肅楚天曉。',24,'全唐诗/poet.song.156000.json','["鴻雁何時來，肅肅楚天曉。", "悲鳴向江南，江北稻粱少。"]'),
('d35b25bc-2537-4d34-a917-6e4b4085b8ce','秋曉  其五','章甫','宋','宋诗','song-poetry','','[]','擾擾世間事，悠悠眼中人。',24,'全唐诗/poet.song.156000.json','["擾擾世間事，悠悠眼中人。", "幽懷與誰語，獨立望秋旻。"]'),
('3878581b-6c97-404c-a5b6-073b70102f68','西湖游上人相訪於白沙翌日如金山求詩  其一','章甫','宋','宋诗','song-poetry','','["\u897f\u6e56"]','剝啄驚春睡，蕭然湖上僧。',24,'全唐诗/poet.song.156000.json','["剝啄驚春睡，蕭然湖上僧。", "篝燈夜深語，多說鑒巴陵。"]'),
('46c054e2-6f66-4442-9902-b50e0c9bafe6','西湖游上人相訪於白沙翌日如金山求詩  其二','章甫','宋','宋诗','song-poetry','','["\u897f\u6e56"]','宗師貪寂滅，祖道益衰遲。',24,'全唐诗/poet.song.156000.json','["宗師貪寂滅，祖道益衰遲。", "只有青山色，相逢似舊時。"]'),
('86f38f6d-ab3f-417f-97b9-9aaebac1040f','西湖游上人相訪於白沙翌日如金山求詩  其三','章甫','宋','宋诗','song-poetry','','["\u897f\u6e56"]','江草隨春遠，沙鷗伴我閒。',24,'全唐诗/poet.song.156000.json','["江草隨春遠，沙鷗伴我閒。", "殷勤東去水，送子過金山。"]'),
('02bf19fa-2dd9-4374-97cf-f0cae39cc150','趙再可以通一所作梅雀求題','章甫','宋','宋诗','song-poetry','','[]','老去詩情在，逢春祇欲狂。',24,'全唐诗/poet.song.156000.json','["老去詩情在，逢春祇欲狂。", "飛來枝上雀，似亦愛幽香。"]'),
('a8378371-5124-44f2-bc74-b0a46e6438a1','雨後十小絕以一雨洗殘暑萬家生早凉爲韻  其一','章甫','宋','宋诗','song-poetry','','[]','閒居何所宜，把酒策第一。',24,'全唐诗/poet.song.156000.json','["閒居何所宜，把酒策第一。", "石田今有秋，痛飲事可必。"]'),
('7e378654-1e07-48bb-9d8a-8e7fd78fb43d','雨後十小絕以一雨洗殘暑萬家生早凉爲韻  其二','章甫','宋','宋诗','song-poetry','','[]','去秋旱太甚，百神無不舉。',24,'全唐诗/poet.song.156000.json','["去秋旱太甚，百神無不舉。", "今歲感天公，時有容易雨。"]'),
('be15cc22-d23b-4744-a01e-4824dbf6e341','雨後十小絕以一雨洗殘暑萬家生早凉爲韻  其三','章甫','宋','宋诗','song-poetry','','[]','暄濁氣未收，夜雨聊一洗。',24,'全唐诗/poet.song.156000.json','["暄濁氣未收，夜雨聊一洗。", "心清不受塵，眼凈豈容瞇。"]'),
