('3c66a7bb-39ef-407f-babc-2ebcf486a502','游洋州崇法院','鄭鄖','宋','宋诗','song-poetry','','[]','曉色熹微麥隴間，杖藜徐步扣禪關。',64,'全唐诗/poet.song.157000.json','["曉色熹微麥隴間，杖藜徐步扣禪關。", "兩澆水足東西堰，一抹雲收南北田。", "仕路馳驅驚歲晚，僧寮燕坐覺身閒。", "故園早辦歸來計，莫待星霜滿鬢斑。"]'),
('02e62e4d-51fd-4f2c-8f62-26abedce27b3','陶隠居上館','王萊','宋','宋诗','song-poetry','','[]','最上華陽舘，凄涼豈舊基。',48,'全唐诗/poet.song.157000.json','["最上華陽舘，凄涼豈舊基。", "山中爲相日，樓上待仙時。", "精力凋文字，羣居厭朮芝。", "却輸元處士，薪爨得天知。"]'),
('7758e832-ca6c-4983-91d0-2ee27561b91b','題妙庭觀','孫紹遠','宋','宋诗','song-poetry','','[]','爐鼎丹飛又未還，不應忘却舊家山。',32,'全唐诗/poet.song.157000.json','["爐鼎丹飛又未還，不應忘却舊家山。", "玉笙餘韵君須聽，只在環流松竹間。"]'),
('8d33ea48-9cc9-4f5e-85b9-ee8b49803d0e','到崑山','奚商衡','宋','宋诗','song-poetry','','[]','客槎無路到天津，五斗依然不救貧。',64,'全唐诗/poet.song.157000.json','["客槎無路到天津，五斗依然不救貧。", "斂版進趨慚大吏，打門呼索愧窮民。", "酒邊拓落尋真趣，詩裏平章作好春。", "自笑小才還小用，姓名安得上麒麟。"]'),
('643f2984-9c7d-4c82-95d1-74dd3834c294','慧聚上方','奚商衡','宋','宋诗','song-poetry','','[]','小橋官樹綠無央，袖手東風日正長。',32,'全唐诗/poet.song.157000.json','["小橋官樹綠無央，袖手東風日正長。", "料理只今誰到我，祇宜煎茗坐僧房。"]'),
('d2da41c5-e13f-48b6-8768-7abb063165ac','簿舍西堂','奚商衡','宋','宋诗','song-poetry','','[]','麤官到眼惟朱墨，箇裏清虛却可人。',64,'全唐诗/poet.song.157000.json','["麤官到眼惟朱墨，箇裏清虛却可人。", "曉徑忽聞花信早，晚窗時對月痕新。", "客來但怪階庭寂，晝永偏於枕簟親。", "莫莫只求閒裏過，抗顔何苦拜車塵。"]'),
('e89df64d-3317-4603-ac90-99b86aae1cb0','題梨嶺馮唐廟','盧篆','宋','宋诗','song-poetry','','[]','五原塞外驕兒悍，萬死臺前女子多。',32,'全唐诗/poet.song.157000.json','["五原塞外驕兒悍，萬死臺前女子多。", "聞道中郎知魏尚，不教天子憶廉頗。"]'),
('7cbef460-9d59-41cd-ad52-7e1c676d3be4','舟行松江聞雞鳴犬吠','趙彥肅','宋','宋诗','song-poetry','','[]','循緣多熟境，溺法無要津。',48,'全唐诗/poet.song.157000.json','["循緣多熟境，溺法無要津。", "慮心屏百慮，猶是隔幾塵。", "雲邊察飛翼，水底觀躍鱗。", "悶殺魯中叟，笑倒濠上人。"]'),
('3eb58d3b-5c6c-4da1-bd04-66c4f9867080','夏夜書所見','吳伯凱','宋','宋诗','song-poetry','','[]','吳牛見月喘，引重不得休。',48,'全唐诗/poet.song.157000.json','["吳牛見月喘，引重不得休。", "孤螢出露草，意行凌九秋。", "形大苦見役，物微長自由。", "世無漆園吏，持問逍遥遊。"]'),
('c74ce685-2561-4b13-a3b5-7af2d5ace8cc','牧兒','吳伯凱','宋','宋诗','song-poetry','','[]','磊塊胸懷漫不平，牧兒橫草耤功名。',32,'全唐诗/poet.song.157000.json','["磊塊胸懷漫不平，牧兒橫草耤功名。", "韓彭不戴貂蟬死，牛背斜陽且意行。"]'),
('093232e4-9cf0-4e80-bd23-ef6125ec727c','句','吳伯凱','宋','宋诗','song-poetry','','[]','平生五千卷，爲方不爲圓。',12,'全唐诗/poet.song.157000.json','["平生五千卷，爲方不爲圓。"]'),
('d606df37-87ad-4054-9b33-668129899c29','方壺','何澹','宋','宋诗','song-poetry','','[]','玉壺清景面瑶池，便入丹青也自宜。',32,'全唐诗/poet.song.157000.json','["玉壺清景面瑶池，便入丹青也自宜。", "挾冊幾回成獨往，壺公應笑一書癡。"]'),
('a6e257f2-7351-47d9-9420-5c6662d13f38','和王成之同趙達明遊西湖','何澹','宋','宋诗','song-poetry','','["\u897f\u6e56"]','只對西湖也自涼，雨餘天更辟商羊。',64,'全唐诗/poet.song.157000.json','["只對西湖也自涼，雨餘天更辟商羊。", "水交秋色心田靜，風入山花鼻觀香。", "別駕慇懃能設醴，吾曹嬉戲且逢場。", "鳳凰池上今文伯，猶憶春闈夜卷長。"]'),
('27aa1710-bbab-49da-9f1f-48c3dafa2f39','和張時可景靈宮即事及暫歸南湖二詩  其一','何澹','宋','宋诗','song-poetry','','[]','嵯峨宮殿曉風清，月掛林梢夜欲更。',64,'全唐诗/poet.song.157000.json','["嵯峨宮殿曉風清，月掛林梢夜欲更。", "戶外朝紳千綺集，馬頭椽燭五枝明。", "諸天唄響超三界，衆妙香然罄一誠。", "渭北衣冠應北顧，請扶大漢振天聲。"]'),
('30b2b6f9-a536-47b5-9de5-caf8e3f6a329','和張時可景靈宮即事及暫歸南湖二詩  其二','何澹','宋','宋诗','song-poetry','','[]','南湖風月想經行，隠興常多薄宦情。',64,'全唐诗/poet.song.157000.json','["南湖風月想經行，隠興常多薄宦情。", "輦轂只今煩佐治，僮奴休復事歡迎。", "人如仲舉輿增重，客爲相如座盡傾。", "咫尺不妨時問道，病餘已覺此身輕。"]'),
('13e1c012-c750-49cf-a70b-f00d7a51452f','登遶花臺  其一','何澹','宋','宋诗','song-poetry','','[]','詩翁當日上凌風，面面看花得句工。',32,'全唐诗/poet.song.157000.json','["詩翁當日上凌風，面面看花得句工。", "我亦巡簷來索笑，古今人意略相同。"]'),
('dfe029fd-7265-40cb-8bd3-55fad928a0fc','登遶花臺  其二','何澹','宋','宋诗','song-poetry','','[]','臺因水部將花遶，隠爲耶溪號小山。',32,'全唐诗/poet.song.157000.json','["臺因水部將花遶，隠爲耶溪號小山。", "且在我家爲故事，若言衣鉢有慚顔。"]'),
('576da282-f787-4df9-a728-fa6abd32202c','早梅二首  其一','何澹','宋','宋诗','song-poetry','','[]','庾嶺香腮想未真，東明纔見一枝新。',32,'全唐诗/poet.song.157000.json','["庾嶺香腮想未真，東明纔見一枝新。", "陽和衣被凡花卉，繁杏夭桃次第春。"]'),
('fa3b75f9-6784-4bc9-b93c-ea450809563a','早梅二首  其二','何澹','宋','宋诗','song-poetry','','[]','姑射仙肌不受塵，舊粧重傅恰如新。',32,'全唐诗/poet.song.157000.json','["姑射仙肌不受塵，舊粧重傅恰如新。", "東君少試回天手，已占人間幾許春。"]'),
('1067f5ac-71d6-4e09-b727-dd830ca0fa3c','紅梅','何澹','宋','宋诗','song-poetry','','[]','冷淡梳粧不入時，故將粉面以朱施。',64,'全唐诗/poet.song.157000.json','["冷淡梳粧不入時，故將粉面以朱施。", "風標可作孤山殿，枝葉能令北客疑。", "及與松筠論舊故，未容桃李强追隨。", "芳名亦占羣花上，所恨無功到鼎彝。"]'),
('42c2d492-bfb4-4b0f-9247-8ae30c893ba1','館中賞紅梅','何澹','宋','宋诗','song-poetry','','[]','石渠南畔小闌干，一種孤芳萬玉攢。',64,'全唐诗/poet.song.157000.json','["石渠南畔小闌干，一種孤芳萬玉攢。", "應爲癯儒嫌冷淡，故將素面汙鉛丹。", "花前酒盞渾如夢，池上詩盟幸不寒。", "美景要須公管領，轉頭還作隔年看。"]'),
('1ef45d01-285a-4e47-acc8-c4b8e21ad5fc','和聖製蠟梅  其一','何澹','宋','宋诗','song-poetry','','[]','庾嶺天開一種芳，金枝先到殿中央。',32,'全唐诗/poet.song.157000.json','["庾嶺天開一種芳，金枝先到殿中央。", "東皇爲作陽春倡，壓倒千花萬卉香。"]'),
('21ef1146-0a7e-485e-812a-2ac24dd937a2','和聖製蠟梅  其二','何澹','宋','宋诗','song-poetry','','[]','不容紅白鬭芬芳，色染薔薇照水央。',32,'全唐诗/poet.song.157000.json','["不容紅白鬭芬芳，色染薔薇照水央。", "冷艷可供清燕賞，日融風軟暗傳香。"]'),
('014815ad-e8f7-4c9f-8474-fe9376f0bd20','報慈山門','何澹','宋','宋诗','song-poetry','','[]','翠屏一匝梵王城，白練兩條功德水。',32,'全唐诗/poet.song.157000.json','["翠屏一匝梵王城，白練兩條功德水。", "百鳥爭巢高樹枝，似聞佛法心歡喜。"]'),
('334ce41c-4593-4b86-a7f4-dbd587915dde','時思山門','何澹','宋','宋诗','song-poetry','','[]','澗水琤琮鳴屋角，溪潭瀲灧對山門。',32,'全唐诗/poet.song.157000.json','["澗水琤琮鳴屋角，溪潭瀲灧對山門。", "綠崖鳥道人行去，隔岸綠陰春正昏。"]'),
('4fd7f91e-465b-439f-8d58-535909ba6c42','群花盛開  其一','何澹','宋','宋诗','song-poetry','','[]','榮觀新移閬苑栽，芳叢衒晝錦花開。',32,'全唐诗/poet.song.157000.json','["榮觀新移閬苑栽，芳叢衒晝錦花開。", "誰知妙手參元化，頃刻青紅照玉杯。"]'),
('a0f56286-2e7d-45eb-9bcc-c5a186216824','群花盛開  其二','何澹','宋','宋诗','song-poetry','','[]','向陽花木易培栽，略借春風已自開。',32,'全唐诗/poet.song.157000.json','["向陽花木易培栽，略借春風已自開。", "多謝青宮能長養，一枝先壓紫霞杯。"]'),
('6a0e4753-8011-4300-917e-bee4367f7827','詩一首','何澹','宋','宋诗','song-poetry','','[]','茂洪囏險扶傾厦，安石從容抗怒蛙。',32,'全唐诗/poet.song.157000.json','["茂洪囏險扶傾厦，安石從容抗怒蛙。", "習俗風流猶未改，短轅絲竹璧微瑕。"]'),
('e57d20a5-96b7-430b-b4fe-484a18689490','兩監同舍出游和吳監丞韻','何澹','宋','宋诗','song-poetry','','["\u897f\u6e56"]','我本麋鹿姿，牽來入京闕。',120,'全唐诗/poet.song.157000.json','["我本麋鹿姿，牽來入京闕。", "舉動違真性，驅馳了歲月。", "自慚西湖水，照見種種髮。", "乘興陪諸公，放舟烟浪窟。", "小雨裛風埃，輕霾翳林樾。", "春深桃李競，路滑車馬歇。", "已辦登山屐，不羨凌波襪。", "沿堤逐樹陰，傍寺訪禪衲。", "杯行知已深，歡意殊未竭。", "日暮碧雲橫，兩山高突兀。"]'),
('feb9da26-a629-480e-8027-c1714ae20194','山中之樂','何澹','宋','宋诗','song-poetry','','[]','噫，山中之樂兮，與猿鶴兮同遊。',29,'全唐诗/poet.song.157000.json','["噫，山中之樂兮，與猿鶴兮同遊。", "幸儋石之有儲，奚斗升之復求。"]'),
('9632281c-b0d5-4d76-9c82-d1d27827b7b6','和趙知府延綠韻','何澹','宋','宋诗','song-poetry','','[]','柴門三月麥秋寒，日與漁樵自往還。',64,'全唐诗/poet.song.157000.json','["柴門三月麥秋寒，日與漁樵自往還。", "千騎肯來延綠閣，一杯相屬對青山。", "句工烟雨空濛際，筆妙龍蛇夭矯間。", "從此小園增倍價，不妨長作老農閑。"]'),
('46deb04a-43eb-40ee-b95f-fd75c690a790','蘿衣洞','何澹','宋','宋诗','song-poetry','','[]','蘿衣晴带護烟簑，楚國狂夫尚作歌。',64,'全唐诗/poet.song.157000.json','["蘿衣晴带護烟簑，楚國狂夫尚作歌。", "石影到溪千丈勁，藤痕入目八分多。", "泉分小白山中雨，衣取雲門寺頂荷。", "洞口樵人誰語汝，茶過相遇更相過。"]'),
('338d0298-1522-4507-9479-1840134f454b','玉香洞','何澹','宋','宋诗','song-poetry','','[]','玉梅幾歲隔樊牆，剖破籓籬兩鴈行。',32,'全唐诗/poet.song.157000.json','["玉梅幾歲隔樊牆，剖破籓籬兩鴈行。", "青眼相看到頭白，洞中無客自吹香。"]'),
('04f454b3-f3a7-4490-9b20-39ce5fc2c359','棲雲中伏','何澹','宋','宋诗','song-poetry','','[]','炎官驅我入山椒，日日松聲似海潮。',32,'全唐诗/poet.song.157000.json','["炎官驅我入山椒，日日松聲似海潮。", "四月黄梅無不雨，却來三伏洗炎歊。"]'),
('a5f08903-fb51-4bf8-a48c-f664cfde7525','和宋憲乙丑元夕韻','何澹','宋','宋诗','song-poetry','','[]','三神山上隔凡塵，簫鼓喧闐午夜聲。',64,'全唐诗/poet.song.157000.json','["三神山上隔凡塵，簫鼓喧闐午夜聲。", "十里綺羅開翠幕，一天星斗不層城。", "也知故國風光麗，尤喜新元穀價平。", "衰朽尚容陪二妙，不妨欹側到天明。"]'),
('dc34e2d1-74ca-494b-9518-3e721e6ed397','九日偕朱彥器伯仲遊雁門山','何澹','宋','宋诗','song-poetry','','[]','神京浩不及，仙關次第開。',48,'全唐诗/poet.song.157000.json','["神京浩不及，仙關次第開。", "名山逢好友，九日共登台。", "濟勝聊爲具，吟詩愧別才。", "何年清海甸，結屋此中來。"]'),
('acc19995-e699-4b9b-9129-9ad0a0be84e1','登白雪樓','徐似道','宋','宋诗','song-poetry','','[]','水落方成放牧坡，水生還作浴鷗波。',64,'全唐诗/poet.song.157000.json','["水落方成放牧坡，水生還作浴鷗波。", "春風自共桃花笑，秀色偏於麥壠多。", "村號莫愁勞想象，石名宋玉謾摩挲。", "試將有袴無襦曲，翻作陽春白雪歌。"]'),
('d1f93562-e5de-481f-a700-c74a064e7682','買硯','徐似道','宋','宋诗','song-poetry','','[]','俸餘宜辦買山錢，却買端州一硯磚。',32,'全唐诗/poet.song.157000.json','["俸餘宜辦買山錢，却買端州一硯磚。", "依舊被渠驅使出，買山之事定何年。"]'),
('37320e07-4b07-4858-8667-4b01244b79dd','遊廬山得蟹','徐似道','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','不到廬山辜負目，不食螃蟹辜負腹。',96,'全唐诗/poet.song.157000.json','["不到廬山辜負目，不食螃蟹辜負腹。", "亦知二者古難并，到得九江吾事足。", "廬山偃蹇坐吾前，螃蟹郭索來酒邊。", "持螯把酒與山對，世無此樂三百年。", "時人愛畫陶靖節，菊繞東籬手親折。", "何如更畫我持螯，共對廬山作三絕。"]'),
('f67be110-28a9-4f6b-943a-f87d98c79a74','和誠齋跋梅坡詩卷','徐似道','宋','宋诗','song-poetry','','[]','知君得法自南昌，作舍何須問道旁。',64,'全唐诗/poet.song.157000.json','["知君得法自南昌，作舍何須問道旁。", "二老未嘗輕許可，兩詩固已爲平章。", "胸橫雲岫無窮意，語带梅坡不盡香。", "政乏綺紈相嫵媚，不妨風氣似諸王。"]'),
('b6e90ece-74c3-468a-828c-5bd35209bdb4','題仙居道中','徐似道','宋','宋诗','song-poetry','','[]','地褊山成簇，溪平水不奔。',48,'全唐诗/poet.song.157000.json','["地褊山成簇，溪平水不奔。", "晴天带陰色，冬日作春溫。", "草聚雞豚市，機聲桑柘村。", "舟人識行李，相約候歸轅。"]'),
('e4db6c1c-5637-4e7f-ba37-d1e13a1eec92','唐史君與正新建浮橋','徐似道','宋','宋诗','song-poetry','','[]','秋風百柁倚江皋，幻出城南不柱橋。',64,'全唐诗/poet.song.157000.json','["秋風百柁倚江皋，幻出城南不柱橋。", "虹影勒回天際水，鷁頭驚退海東潮。", "白銀闕裏看車馬，赤玉闌邊聽鼓簫。", "硎刃有餘舟楫在，待隨芝檢上雲霄。"]'),
('92fe0b97-a72d-4650-a49b-9b6e176d298d','題仙居相湖','徐似道','宋','宋诗','song-poetry','','[]','嶺名石母誰家母，湖號相公何代公。',64,'全唐诗/poet.song.157000.json','["嶺名石母誰家母，湖號相公何代公。", "欲問嶺雲并嶺月，怕推湖水與湖風。", "漁翁樵子難重問，墨客騷人苦欲窮。", "愚智校行三十里，朔風吹酒又成空。"]'),
('1370167e-a48e-419a-a236-a1f4fdf7562a','宿雲巖二首  其一','徐似道','宋','宋诗','song-poetry','','[]','古書萬卷積成蠹，老屋數閒深却幽。',32,'全唐诗/poet.song.157000.json','["古書萬卷積成蠹，老屋數閒深却幽。", "午枕忽驚毛骨冷，覺來風雨一山秋。"]'),
('acf162c3-aa9b-40f4-944f-b6da79a4e30a','宿雲巖二首  其二','徐似道','宋','宋诗','song-poetry','','[]','殘僧入定夜堂寂，獨客不眠山月高。',32,'全唐诗/poet.song.157000.json','["殘僧入定夜堂寂，獨客不眠山月高。", "靜坐了無塵俗態，一燈窗下讀離騷。"]'),
('f0ad4f20-f217-48d7-a670-59bc7382ced2','題蒼嶺','徐似道','宋','宋诗','song-poetry','','[]','看山每恨眼不飽，上馬豈知程可貪。',32,'全唐诗/poet.song.157000.json','["看山每恨眼不飽，上馬豈知程可貪。", "還我一筇雙不借，緩從雲北過雲南。"]'),
('057bf017-4090-4201-9737-cf58179795ff','九日','徐似道','宋','宋诗','song-poetry','','[]','衰容不似秋容好，坐上誰憐老孟嘉。',32,'全唐诗/poet.song.157000.json','["衰容不似秋容好，坐上誰憐老孟嘉。", "牢裹烏紗莫吹却，免教白髮見黄花。"]'),
('405a9f2e-0dff-4be7-ab0b-d286dddf5130','海棠','徐似道','宋','宋诗','song-poetry','','[]','子美無詩到海棠，酒邊游戲略平章。',64,'全唐诗/poet.song.157000.json','["子美無詩到海棠，酒邊游戲略平章。", "日烘不睡却成睡，風暖無香却自香。", "花事一番勞應接，春光强半被分張。", "速來窠上尋徐老，同醉花前作楚狅。"]'),
('0a2d9720-512c-4402-beb1-c2495a162168','巖桂花','徐似道','宋','宋诗','song-poetry','','[]','重重簾幕護金猊，小樹花開逼麝臍。',64,'全唐诗/poet.song.157000.json','["重重簾幕護金猊，小樹花開逼麝臍。", "寒色十分新疹粟，春心一點暗通犀。", "香延棋畔仙人斧，影射燈前太乙藜。", "從此再週花甲子，伴公長醉日東西。"]'),
('68341726-86fa-451a-9311-af3bda923e99','酴醾','徐似道','宋','宋诗','song-poetry','','[]','紛紛紅紫落莓苔，带月和煙特地開。',32,'全唐诗/poet.song.157000.json','["紛紛紅紫落莓苔，带月和煙特地開。", "疑是玉妃新浴出，翠雲梯上舞風臺。"]'),
('81e3f58b-8ee3-4284-9d49-c49dc688b074','水仙花二首  其一','徐似道','宋','宋诗','song-poetry','','[]','天然初不事鉛華，此是無塵有韵花。',32,'全唐诗/poet.song.157000.json','["天然初不事鉛華，此是無塵有韵花。", "翠带詎容縈俗客，金杯祗合勸詩家。"]'),
('df0ec9c3-7f52-4df5-ab4b-4a495d1c08fa','水仙花二首  其二','徐似道','宋','宋诗','song-poetry','','[]','林下清風自一家，稍親梅竹近蘭芽。',32,'全唐诗/poet.song.157000.json','["林下清風自一家，稍親梅竹近蘭芽。", "祇緣羞與凡花伍，移植名園不肯花。"]'),
('61569589-8b35-4c38-9198-8f9fe7567d82','萱草花','徐似道','宋','宋诗','song-poetry','','[]','莫訝萱枝小，能施宮樣粧。',24,'全唐诗/poet.song.157000.json','["莫訝萱枝小，能施宮樣粧。", "只緣沾染足，絕似杜蘭香。"]'),
('d2c2ef61-de62-4ebc-adb6-b37e77bfc74c','楊梅','徐似道','宋','宋诗','song-poetry','','[]','火齊無光荔實圓，未嘗先說齒流涎。',32,'全唐诗/poet.song.157000.json','["火齊無光荔實圓，未嘗先說齒流涎。", "喚回天竺三年夢，參透披雲一味禪。"]'),
('3279ee37-1def-4127-9cca-ffe1695e5e7c','蒲','徐似道','宋','宋诗','song-poetry','','[]','圓蒲相將結僧厦，荷葉蒲茸綠相亞。',80,'全唐诗/poet.song.157000.json','["圓蒲相將結僧厦，荷葉蒲茸綠相亞。", "浮花浪葉自飄零，小院迴廊正瀟洒。", "葉如青幄花成茵，細腰起舞來送春。", "紙光如銀墨如漆，落筆四座驚有神。", "輕衫短帽付餘子，花前醉倒輸閑人。"]'),
('9492b907-084b-4ec8-82dc-bf00c54a66db','竹','徐似道','宋','宋诗','song-poetry','','[]','盧仝茅屋面桃李，杜老草堂依柳梅。',32,'全唐诗/poet.song.157000.json','["盧仝茅屋面桃李，杜老草堂依柳梅。", "我欲四時相照映，小窗時對此君開。"]'),
('97395ab6-fbfb-4d07-ab01-9d09b5c8e7a2','薺','徐似道','宋','宋诗','song-poetry','','[]','萋萋牆根薺，采掇盈一襜。',48,'全唐诗/poet.song.157000.json','["萋萋牆根薺，采掇盈一襜。", "破白半浮糝，殺青微下鹽。", "長貧歎亦苦，積悟覺尤甘。", "緬想拔葵者，吾今已傷廉。"]'),
('a63657c5-7e63-4e45-817d-c5efcc5a752d','蓴菜二首  其一','徐似道','宋','宋诗','song-poetry','','[]','千里蓴絲未下鹽，北遊誰復話江南。',32,'全唐诗/poet.song.157000.json','["千里蓴絲未下鹽，北遊誰復話江南。", "可憐一筯秋風味，錯被旁人苦未參。"]'),
('0f6cccdc-7276-4112-8770-7c48c18c6153','蓴菜二首  其二','徐似道','宋','宋诗','song-poetry','','[]','堆盤縷縷又秋風，客俎虀鹽一洗空。',64,'全唐诗/poet.song.157000.json','["堆盤縷縷又秋風，客俎虀鹽一洗空。", "羹鱠疑居柁樓底，杯螯如墮酒船中。", "蓴羹本是詩人事，樽俎那容俗子同。", "不日挽君來快問，請分一筯供涪翁。"]'),
('83b802df-33c3-427a-8edc-f562bdb31f96','守太和','徐似道','宋','宋诗','song-poetry','','[]','我本田家子，驅來作長官。',48,'全唐诗/poet.song.157000.json','["我本田家子，驅來作長官。", "政雖無小異，民却自相安。", "靜或焚香坐，閒因展畫看。", "庸人擾之耳，只道太和難。"]'),
('a3b420fd-5461-407f-896f-2572fc7c77bb','題雪巢','徐似道','宋','宋诗','song-poetry','','[]','巢餘太古雪，人有正始風。',24,'全唐诗/poet.song.157000.json','["巢餘太古雪，人有正始風。", "頭如雪絮白，面作春桃紅。"]'),
('6dc114c6-68ae-462e-9291-a68d8af8d90b','裝太和米綱','徐似道','宋','宋诗','song-poetry','','[]','一鞭加爾膚，萬刃劃吾腹。',36,'全唐诗/poet.song.157000.json','["一鞭加爾膚，萬刃劃吾腹。", "就令猛於虎，何忍食子肉。", "世無冷鑊湯，邑盡活地獄。"]'),
('634dfad7-4e69-4d86-9d4b-6ede2fa684ab','秋日','徐似道','宋','宋诗','song-poetry','','[]','老覺此身無一堪，尚牽詩課撚衰髯。',32,'全唐诗/poet.song.157000.json','["老覺此身無一堪，尚牽詩課撚衰髯。", "亦知庭院西風惡，直爲秋香不下簾。"]'),
('1b9cb2d0-2075-47d5-beb3-cc781239b8be','詩一首','徐似道','宋','宋诗','song-poetry','','[]','一瓶儲粟一囊錢，兒學箕裘女紡磚。',32,'全唐诗/poet.song.157000.json','["一瓶儲粟一囊錢，兒學箕裘女紡磚。", "更買小丘吾事畢，勘書評畫了殘年。"]'),
('2fa6d26f-627e-42c1-b669-60e2f034d458','瓶中梅花','徐似道','宋','宋诗','song-poetry','','[]','可憐玉雪不供愁，似倩詩翁作□□。',32,'全唐诗/poet.song.157000.json','["可憐玉雪不供愁，似倩詩翁作□□。", "□□此君雖强項，歲寒相對却風流。"]'),
('5ef56259-aef0-4c82-ae86-e98adda66617','舟行','徐似道','宋','宋诗','song-poetry','','[]','大官連檣十萬艘，小官僅得一葉如漁舠。',194,'全唐诗/poet.song.157000.json','["大官連檣十萬艘，小官僅得一葉如漁舠。", "其中何所有，白髮翁媼並兒曹。", "赤脚婢三後執爨，蒼頭奴二前操篙。", "玄真筆牀間茶竈，吏部酒杯兼蟹螯。", "書緘一箱半魚蠹，一束百軸成牛腰。", "平鋪藁秸薦貓犬，剩買棗栗供猨猱。", "新花鬰屈作萎木，清酒蕩摇成濁醪。", "篷低日覺牛角折，竈近時聞羹釜轑。", "高驤正難望鷁首，緩進豈敢爭龍標。", "全家窘拘嘆蹐跼，長物屏當隨周遭。", "桑樞駟馬各是累，人肝薇蕨俱成饕。", "不須彼此更相笑，未必鬰林之石賢胡椒。"]'),
('6cfe109b-bf56-46de-bff8-1a9609547aef','詩一首','徐似道','宋','宋诗','song-poetry','','[]','植杞必植梓，藝蘭仍藝蓀。',24,'全唐诗/poet.song.157000.json','["植杞必植梓，藝蘭仍藝蓀。", "過庭遺訓在，鑿楹故書存。"]'),
('c09f2068-9c51-4e0d-a914-4e7d5e08ba3c','偶題','徐似道','宋','宋诗','song-poetry','','[]','老去功名不掛懷，高眠之外只清齋。',32,'全唐诗/poet.song.157000.json','["老去功名不掛懷，高眠之外只清齋。", "偶因種竹便多事，風葉掃餘還滿階。"]'),
('56903549-fabb-4610-9e41-8e2b2ee9caad','白龍洞','徐似道','宋','宋诗','song-poetry','','[]','靈仙窟宅不多見，車馬往來成再游。',64,'全唐诗/poet.song.157000.json','["靈仙窟宅不多見，車馬往來成再游。", "後洞白雲前洞出，上池紅葉下池流。", "水花照眼明金鯽，石髮藏春護玉虬。", "邂逅尚青遊子眼，棲遲應白老僧頭。"]'),
('bea611be-4ff7-4d85-bb63-f70b410b2e3a','呈周子充','徐似道','宋','宋诗','song-poetry','','[]','翰林帳下飲羊羔，客子騎馿渡灞橋。',32,'全唐诗/poet.song.157000.json','["翰林帳下飲羊羔，客子騎馿渡灞橋。", "莫似靈鼇笑浮蟻，戴山負粟各逍遥。"]'),
('2b4c4939-cfce-4e7b-98e6-6baa337bc3bc','爲劉改之作五首  其一','徐似道','宋','宋诗','song-poetry','','[]','江西詩社久淪落，晚得一人劉改之。',32,'全唐诗/poet.song.157000.json','["江西詩社久淪落，晚得一人劉改之。", "不向嶺頭拈取去，此衣此鉢付他誰。"]'),
('3db5b53f-df66-44c1-854c-7f2328ccb2c5','爲劉改之作五首  其二','徐似道','宋','宋诗','song-poetry','','[]','謫仙昔者號無敵，侯喜中間還有聲。',32,'全唐诗/poet.song.157000.json','["謫仙昔者號無敵，侯喜中間還有聲。", "後五百年無繼者，得渠一句便堪聽。"]'),
('a2a2f882-5de4-43c0-97d7-3dcdbcf56fa4','爲劉改之作五首  其三','徐似道','宋','宋诗','song-poetry','','[]','一生能著幾兩屐，萬戶何如千首詩。',32,'全唐诗/poet.song.157000.json','["一生能著幾兩屐，萬戶何如千首詩。", "竹隠在傍須徑造，醉鄉有路莫他之。"]'),
('8f6df2f1-ae35-4ebe-be47-90203ae2d4c6','爲劉改之作五首  其四','徐似道','宋','宋诗','song-poetry','','[]','風吹客袂遊甘露，雪打人頭入半山。',32,'全唐诗/poet.song.157000.json','["風吹客袂遊甘露，雪打人頭入半山。", "無故被他林鳥覺，競傳新句落人間。"]'),
('3d498518-bea8-48ee-a972-f274393d485b','爲劉改之作五首  其五','徐似道','宋','宋诗','song-poetry','','[]','閉門長安十日雨，車馬不來蛙黽多。',32,'全唐诗/poet.song.157000.json','["閉門長安十日雨，車馬不來蛙黽多。", "若往澹然應子是，作商聲者必君歌。"]'),
('b26ed9a3-8101-4cf7-a31f-460a145455d3','過月巖','徐似道','宋','宋诗','song-poetry','','[]','橋虹跨水千尺，巖月倚空半規。',28,'全唐诗/poet.song.157000.json','["橋虹跨水千尺，巖月倚空半規。", "歲晚相看如昨，夕陽佇立移時。"]'),
('d2cc2450-1af3-469b-af5a-6b06f6f1fd48','舟中','徐似道','宋','宋诗','song-poetry','','[]','紅漆樓船黑占牌，漁翁一見便驚猜。',31,'全唐诗/poet.song.157000.json','["紅漆樓船黑占牌，漁翁一見便驚猜。", "生怕打官交道，撐入蘆花喚不來。"]'),
('3e49fae7-bff2-4cde-b49e-8f20b0e14412','縉雲道中','徐似道','宋','宋诗','song-poetry','','[]','夜泊紅樓市，朝餐黑笠家。',48,'全唐诗/poet.song.157000.json','["夜泊紅樓市，朝餐黑笠家。", "淺溪才泛鴨，疏樹不藏鴉。", "鬲上村坊酒，眉尖野店茶。", "尚緣門有竹，忘却去程賒。"]'),
('053c0bf6-54d8-4e2d-a5f4-dc001ce29e5b','石夫人','徐似道','宋','宋诗','song-poetry','','[]','消山偃蹇消湖碧，夫人此恨消未得。',32,'全唐诗/poet.song.157000.json','["消山偃蹇消湖碧，夫人此恨消未得。", "海上人歸會有時，怪爾鬢雲非舊色。"]'),
('589acf89-29c2-4b74-8d29-dbb06c71d87a','妙嚴禪寺','徐似道','宋','宋诗','song-poetry','','[]','宿霧釀成三日雨，曉風鏖退一天雲。',32,'全唐诗/poet.song.157000.json','["宿霧釀成三日雨，曉風鏖退一天雲。", "落花院宇渾無事，閑拂碑塵看斷文。"]'),
('f4858baf-97a0-489b-9310-9e3c6d8f742b','虞仲房司馬遊園約予不赴因次其韻','徐似道','宋','宋诗','song-poetry','','[]','祕書行處有歌鐘，身在名園錦繡叢。',64,'全唐诗/poet.song.157000.json','["祕書行處有歌鐘，身在名園錦繡叢。", "試問高吟梁苑雪，何如共快楚臺風。", "人鷗不去機方息，魚我相忘樂未窮。", "待得芙容濯雲錦，弄花翻水與君同。"]'),
('a3d06460-3c5c-4ba3-950a-29420e63b694','自笑','徐似道','宋','宋诗','song-poetry','','[]','黄昏茅店带星入，清曉竹輿蒙露行。',32,'全唐诗/poet.song.157000.json','["黄昏茅店带星入，清曉竹輿蒙露行。", "客路三千年五十，對人猶說是歸耕。"]'),
('9be2a3b6-86d3-4a44-9e78-485c993e13c2','硐嶺樵歌','徐似道','宋','宋诗','song-poetry','','[]','黄山東南數十里，芙蓉削翠連雲起。',64,'全唐诗/poet.song.157000.json','["黄山東南數十里，芙蓉削翠連雲起。", "蕭蕭褐褐三五群，生薪半肩歌不止。", "石徑迢迢雲外行，煙霧滿地穿林坰。", "聖世不須紫芝曲，息擔擊壤歌太平。"]'),
('256b20bf-9e4f-4045-9129-b4aaab0378d8','扈隩牧笛','徐似道','宋','宋诗','song-poetry','','[]','濛濛香霧濕未乾，煙光匝地春風寒。',64,'全唐诗/poet.song.157000.json','["濛濛香霧濕未乾，煙光匝地春風寒。", "牧童三五喚歸切，鞭牛爲馬蓑爲鞍。", "一聲蘆管振林木，口畔嗚嗚相戲逐。", "梅花亂落自瀟灑，絕勝豪門調新曲。"]'),
('294622f1-00f3-4c48-99e3-03213aa86bc2','北閘停舟','徐似道','宋','宋诗','song-poetry','','[]','昔人築斯防旱澇，龍鍾常相天地造。',64,'全唐诗/poet.song.157000.json','["昔人築斯防旱澇，龍鍾常相天地造。", "舟航群泊沙外汀，酒旗斜插江亭小。", "歲歲常豐民自怡，幾家燈火兒誦詩。", "何處漁歌蘆中起，欵乃一聲山月低。"]'),
('9fb7cdaa-c42a-44f8-b092-9db746fd5f3b','馬橋秋月','徐似道','宋','宋诗','song-poetry','','[]','石梁橫卧清溪曲，波光上下風吹綠。',64,'全唐诗/poet.song.157000.json','["石梁橫卧清溪曲，波光上下風吹綠。", "海東推上月輪來，鱗龍閃閃浮寒玉。", "昔人呼爲飲馬泉，至今飲者誰投錢。", "吟餘不覺露華重，桂花香墮綃衣寒。"]'),
('69652064-9d86-4b39-ac07-f3b37380d4b2','溪上值雨','徐似道','宋','宋诗','song-poetry','','[]','行到溪光竹色間，客懷於此最相關。',32,'全唐诗/poet.song.157000.json','["行到溪光竹色間，客懷於此最相關。", "無端一陣西風雨，不許從容坐看山。"]'),
('72535966-6f04-4dee-ba87-6d69566d21da','句  其一','徐似道','宋','宋诗','song-poetry','','[]','煖分煨芋火，明借績麻燈。',12,'全唐诗/poet.song.157000.json','["煖分煨芋火，明借績麻燈。"]'),
('fb538401-a600-4faf-a2ca-f055874939d2','句  其二','徐似道','宋','宋诗','song-poetry','','[]','小桃洗面添光澤，未點胭脂已自紅。',16,'全唐诗/poet.song.157000.json','["小桃洗面添光澤，未點胭脂已自紅。"]'),
('ee87e0c4-903f-4a85-9fff-3f85444b7419','句  其三','徐似道','宋','宋诗','song-poetry','','[]','紅芭蕉映黑牽牛。',8,'全唐诗/poet.song.157000.json','["紅芭蕉映黑牽牛。"]'),
('55ffca6e-b54f-4fbc-9da6-37a6739ac785','句  其四','徐似道','宋','宋诗','song-poetry','','[]','牧童出捲烏鹽角，越女歸簪謝豹花。',16,'全唐诗/poet.song.157000.json','["牧童出捲烏鹽角，越女歸簪謝豹花。"]'),
('89b0f946-e8d2-4e56-9a17-9a53be8bff21','句  其五','徐似道','宋','宋诗','song-poetry','','[]','曉風洛浦凌波際，夜月江臯解佩時。',16,'全唐诗/poet.song.157000.json','["曉風洛浦凌波際，夜月江臯解佩時。"]'),
('379c1549-2eae-431f-9190-ac83d70d2e72','句  其六','徐似道','宋','宋诗','song-poetry','','[]','一带拒霜三十里，又催簫鼓作秋聲。',16,'全唐诗/poet.song.157000.json','["一带拒霜三十里，又催簫鼓作秋聲。"]'),
('bc3f865a-c1c4-447a-a5ab-c9f33b61802d','句  其七','徐似道','宋','宋诗','song-poetry','','[]','葉從秋後變，色向晚來紅。',12,'全唐诗/poet.song.157000.json','["葉從秋後變，色向晚來紅。"]'),
('ce6404ad-8ada-4de6-8343-71a2958ea5ac','句  其八','徐似道','宋','宋诗','song-poetry','','[]','那堪富有千頭橘，便可稱爲四老人。',16,'全唐诗/poet.song.157000.json','["那堪富有千頭橘，便可稱爲四老人。"]'),
('10aed115-30a7-4b84-b40a-507b8393b484','句  其九','徐似道','宋','宋诗','song-poetry','','[]','後茁碧含蘚，厥包黄带沙。',12,'全唐诗/poet.song.157000.json','["後茁碧含蘚，厥包黄带沙。"]'),
('39a5f26d-1032-4c2c-8cdc-e25cd94023c8','句  其一○','徐似道','宋','宋诗','song-poetry','','[]','見說周顒誇早韭，斲煙鋤雨幸時分。',16,'全唐诗/poet.song.157000.json','["見說周顒誇早韭，斲煙鋤雨幸時分。"]'),
('93ef9716-f6f9-4a2d-a174-064b112d59a7','句  其一一','徐似道','宋','宋诗','song-poetry','','[]','胡椒尚殺元丞相，薏苡猶疑馬伏波。',16,'全唐诗/poet.song.157000.json','["胡椒尚殺元丞相，薏苡猶疑馬伏波。"]'),
('884c0100-eefc-43ac-9c01-25b3960f8e4b','句  其一二','徐似道','宋','宋诗','song-poetry','','[]','曉梵魚出聽，夜禪石點頭。',12,'全唐诗/poet.song.157000.json','["曉梵魚出聽，夜禪石點頭。"]'),
('a5217abd-500f-4352-8432-f70c07ff89d1','句  其一三','徐似道','宋','宋诗','song-poetry','','[]','胸中著雲夢，皮裏有陽秋。',12,'全唐诗/poet.song.157000.json','["胸中著雲夢，皮裏有陽秋。"]'),
('8237b09a-b163-4ce9-b858-ebe3101a5938','句  其一四','徐似道','宋','宋诗','song-poetry','','[]','自作先生傳，誰爲故吏碑。',12,'全唐诗/poet.song.157000.json','["自作先生傳，誰爲故吏碑。"]'),
('ece0328e-7f49-4a3b-b136-9241f0e01cfa','句  其一五','徐似道','宋','宋诗','song-poetry','','[]','肩成山聳因尋句，眼作花昏爲勘碑。',16,'全唐诗/poet.song.157000.json','["肩成山聳因尋句，眼作花昏爲勘碑。"]'),
('b059c057-9d41-4638-97e6-e9d477d4e3b8','句  其一六','徐似道','宋','宋诗','song-poetry','','[]','天寒不知翠袖薄，日煖但覺玉煙生。',16,'全唐诗/poet.song.157000.json','["天寒不知翠袖薄，日煖但覺玉煙生。"]'),
('43604c95-8ca5-40b6-baec-6b1340e47bce','句  其一七','徐似道','宋','宋诗','song-poetry','','[]','黄四孃花空朵朵，謝三郎鬢已蒼蒼。',16,'全唐诗/poet.song.157000.json','["黄四孃花空朵朵，謝三郎鬢已蒼蒼。"]'),
('d01c1a98-acff-4346-a8d6-76929bc7e39e','句  其一八','徐似道','宋','宋诗','song-poetry','','[]','索醉寧傾問字酒，忍饑不取作碑錢。',16,'全唐诗/poet.song.157000.json','["索醉寧傾問字酒，忍饑不取作碑錢。"]'),
('14d30fbc-3ae2-43e5-9245-d2fc2a1ff947','句  其一九','徐似道','宋','宋诗','song-poetry','','[]','駒入隙來元不礙，蠅鑽紙出定何妨。',16,'全唐诗/poet.song.157000.json','["駒入隙來元不礙，蠅鑽紙出定何妨。"]'),
('4c208c0d-4c32-48cd-80cd-b0e9f96f7c0a','句  其二○','徐似道','宋','宋诗','song-poetry','','[]','化成銀地佛應喜，移下玉樓天不知。',16,'全唐诗/poet.song.157000.json','["化成銀地佛應喜，移下玉樓天不知。"]'),
('9bd48af1-40a3-4234-b310-07af9e26eca8','句  其二一','徐似道','宋','宋诗','song-poetry','','[]','北風萬籟自宮徵，南日一軒真袴襦。',16,'全唐诗/poet.song.157000.json','["北風萬籟自宮徵，南日一軒真袴襦。"]'),
('419e7ab5-4cd8-4099-9e6c-a2609f13648a','句  其二二','徐似道','宋','宋诗','song-poetry','','[]','但欲有衣存妓妾，不愁無帳列生徒。',16,'全唐诗/poet.song.157000.json','["但欲有衣存妓妾，不愁無帳列生徒。"]'),
('bab53ae9-c9b6-4c1e-9372-edaa12da1c32','句  其二三','徐似道','宋','宋诗','song-poetry','','[]','劉顯貴爲天子友，退之窮作相君書。',16,'全唐诗/poet.song.157000.json','["劉顯貴爲天子友，退之窮作相君書。"]'),
('ef34a1d3-565b-434d-b210-88dfa43b77c6','病中無聊忽徐淵子送酒','丁世昌','宋','宋诗','song-poetry','','[]','丹桂傳香後，黄花著蕊時。',48,'全唐诗/poet.song.157000.json','["丹桂傳香後，黄花著蕊時。", "老懷期欲賞，病足瘦難移。", "靜對陶潛徑，長吟杜甫詩。", "白衣人忽至，把酒慰愁眉。"]'),
('879eeab3-564e-4aa0-a58e-3c4c56b3661f','次虞仲房司馬送秋韻','丁世昌','宋','宋诗','song-poetry','','[]','自入秋光能幾時，無端又賦別秋詩。',64,'全唐诗/poet.song.157000.json','["自入秋光能幾時，無端又賦別秋詩。", "夜長月冷蟲鳴急，天闊風高雁過遲。", "三徑黄花存舊節，半欄紅葉墮殘枝。", "往來畢竟乘除法，何用年年宋玉悲。"]'),
('2bbff770-a3be-4bb3-9c74-6bd3b93856e1','古樂府','丁世昌','宋','宋诗','song-poetry','','[]','郎如枝上禽，妾比庭前樹。',24,'全唐诗/poet.song.157000.json','["郎如枝上禽，妾比庭前樹。", "翅健入雲飛，根深隨不去。"]'),
('8054b7a3-02dd-441d-970f-2a13b7311352','少永少雲二弟對弈','丁世昌','宋','宋诗','song-poetry','','[]','平處須忘險，危時好計安。',24,'全唐诗/poet.song.157000.json','["平處須忘險，危時好計安。", "興亡關一著，慎勿等閒看。"]'),
('727fc8bb-a7bc-4f17-8868-879af5855be7','和徐淵子九日','開禧朝士','宋','宋诗','song-poetry','','[]','呼兒爲我整烏紗，不是無心學孟嘉。',32,'全唐诗/poet.song.157000.json','["呼兒爲我整烏紗，不是無心學孟嘉。", "要摘金英滿頭插，明朝還是過時花。"]'),
('ab322aaa-dfba-4875-9e47-4bd9ace729f8','超覽堂','徐大忠','宋','宋诗','song-poetry','','[]','君侯雅有博大見，胸次不使倥傯蝕。',144,'全唐诗/poet.song.157000.json','["君侯雅有博大見，胸次不使倥傯蝕。", "一朝放步城東南，超然神會而心得。", "咄嗟高棟倚層空，振古奇觀今未識。", "桃花春暖意如迷，凍雨聲來雲潑墨。", "天青一紙雁橫書，雪白千林梅著色。", "四筵有客無留觴，萬事不來咸得職。", "鴻筆昭代今文宗，危言劘上古遺直。", "願馮英略決籌帷，凈掃妖氛清八極。", "緣知此景不須戀，留與邦人勤愛惜。"]'),
('5fdae6ee-66d5-42c9-b5e1-84097f637d5d','和放翁題鶑花亭','江濤','宋','宋诗','song-poetry','','[]','春雨溪頭長柳圍，游仙枕上賦黄鸝。',32,'全唐诗/poet.song.157000.json','["春雨溪頭長柳圍，游仙枕上賦黄鸝。", "誰知醉卧古藤下，却是浮生夢裏詩。"]'),
('ac25784d-00d1-48f6-b9c8-016f178680d8','句','江濤','宋','宋诗','song-poetry','','[]','麥隴將雛馴乳雉，柳塘遺子漾游魚。',16,'全唐诗/poet.song.157000.json','["麥隴將雛馴乳雉，柳塘遺子漾游魚。"]'),
('6eab8e48-1454-4cf2-b3d3-44657aab3672','羯鼓縚','彭演','宋','宋诗','song-poetry','','[]','長安宮闕半蓬蒿，塵暗紅梁羯鼓縚。',32,'全唐诗/poet.song.157000.json','["長安宮闕半蓬蒿，塵暗紅梁羯鼓縚。", "惟有水天明月夜，一條空碧見秋毫。"]'),
('8297fc56-4e4e-4580-92fd-25b7d8fde0da','題棲真院棲隠閣','祝禹圭','宋','宋诗','song-poetry','','[]','督郵一見未爲辱，不暇稅冕爲膰肉。',32,'全唐诗/poet.song.157000.json','["督郵一見未爲辱，不暇稅冕爲膰肉。", "棲隠閣上字猶新，堪歎五湖去不速。"]'),
('bd055f13-f182-4379-bb96-18bc72dcf92e','次袁尚書巫山十二峰二十五韻','李嘉謀','宋','宋诗','song-poetry','','[]','道人愛山出天姿，自謂計黠人嫌癡。',384,'全唐诗/poet.song.157000.json','["道人愛山出天姿，自謂計黠人嫌癡。", "獨游名山看不足，每得勝處行爲遲。", "誰人能知物外賞，世上自有靈中奇。", "一行作吏困汩沒，便與好境相參差。", "脫兔投林今適願，窮猿得木吾何之。", "芒鞋竹杖恣如往，煙蓑雨笠長相隨。", "青山愈好足力盡，此意未止駑駘疲。", "路逢行人說大尹，正見諭蜀揚舲旗。", "好賢招邀每虛席，問俗疾苦時褰帷。", "才華落落清廟器，詩筆粲粲珊瑚枝。", "胸吞楚澤八九盡，氣壓巫峽羣山低。", "大峯聯娟爭媚嫵，蒼壁徙倚供遊嬉。", "巴東巴峽古所重，作雲作雨今胡爲。", "有情飛鳶送迎客，無數棹歌來去時。", "昔日畫圖曾見者，何意忽此今逢茲。", "邇來豐碑在人口，已與流水爭東馳。", "政用中和得大體，智出毫末非全施。", "不與英聲流上國，已有詩卷傳江湄。", "狼烽長閒士鼓腹，耕隴不見愁生眉。", "都門髣髴記分袂，蜀道脩阻常支頤。", "持謁見公敢論舊，撫髀顧我清無緇。", "樽俎頻開閑共話，歌謳聊與民同嘻。", "忽然晨旦往東壁，但見山月來峨嵋。", "行吟何獨壯三峽，在處山林來乞詩。"]'),
('c615427f-2901-41b1-b5a4-0ffe1e29ccae','行鄉','李揆','宋','宋诗','song-poetry','','[]','園林二月春纔半，朝日曈矓天氣暖。',144,'全唐诗/poet.song.157000.json','["園林二月春纔半，朝日曈矓天氣暖。", "東風放盡柳梢青，已有黄鸝嬌睍睆。", "波翻嫩麥綠連坡，露入夭桃紅滿眼。", "筍輿乘興入招提，苾蒭留我炊香飯。", "山泉煮茗味更長，又得禪林半朝款。", "突兀豐碑三百年，古人事蹟今苔蘚。", "臨風抖擻簿書塵，倚杖須臾歸已晚。", "耕夫夾道看長官，百錢贈汝聊旌勸。", "從容後騎毋疾驅，要數前山蒼翠點。"]'),
('1545673f-310d-4349-8e15-3b1d599673ba','登縣樓  其一','李揆','宋','宋诗','song-poetry','','[]','一水中分南北市，插天蒙末有佳山。',32,'全唐诗/poet.song.157000.json','["一水中分南北市，插天蒙末有佳山。", "太平官府原無事，聊放衰翁半日閒。"]'),
('86ae9ef2-d365-4275-9f4c-f4785d64ec88','登縣樓  其二','李揆','宋','宋诗','song-poetry','','[]','見說南樓秋氣多，夜凉槐蔭影婆娑。',32,'全唐诗/poet.song.157000.json','["見說南樓秋氣多，夜凉槐蔭影婆娑。", "滿懷風月成辜負，奈此青州從事何。"]'),
('ada678c5-178b-4a00-9f06-194d01b27517','元夕雨','李揆','宋','宋诗','song-poetry','','[]','山縣逢元夕，東風雨濺燈。',48,'全唐诗/poet.song.157000.json','["山縣逢元夕，東風雨濺燈。", "漁篝臨遠浦，鬼火附寒藤。", "酒市可羅雀，官僚皆曲肱。", "狂歌吾老矣，猶記舊時能。"]'),
('a39d2b8c-2383-42fe-b4ba-5f8707ef7b6a','寒食出郊三首  其一','李揆','宋','宋诗','song-poetry','','[]','寒食深山路，桃花雨裏開。',48,'全唐诗/poet.song.157000.json','["寒食深山路，桃花雨裏開。", "可憐傳檄出，不爲踏青來。", "泥滑竹岡下，雞鳴田舍隈。", "邱園二十里，松檟有餘哀。"]'),
('2510ba3d-5024-4478-801c-aeb0e05e5643','寒食出郊三首  其二','李揆','宋','宋诗','song-poetry','','[]','春事遽如許，勞人渾不知。',48,'全唐诗/poet.song.157000.json','["春事遽如許，勞人渾不知。", "柳垂山闕處，花發雨來時。", "薄宦祗憔悴，故園成別離。", "多情睇啼鳥，獨與寸心違。"]'),
('a66fd666-8b4a-43ea-9789-cb0016fcd09c','寒食出郊三首  其三','李揆','宋','宋诗','song-poetry','','[]','往歲逢寒食，青鞋踏落花。',48,'全唐诗/poet.song.157000.json','["往歲逢寒食，青鞋踏落花。", "題詩山寺壁，沽酒野人家。", "草長春無際，身閒意自遐。", "時時縣亭畔，畫遍水邊沙。"]'),
('51386e8f-2fb1-40df-a6a5-3b828e0609af','吉祥寺','李揆','宋','宋诗','song-poetry','','[]','带雨溪雲重，依山石路斜。',48,'全唐诗/poet.song.157000.json','["带雨溪雲重，依山石路斜。", "聊乘阮孚屐，徑入梵王家。", "接竹引流水，栽籬護野花。", "簿書有期會，無地老烟霞。"]'),
('ebed2c72-636e-4151-8a05-52c787a70ca4','遊石門','王度','宋','宋诗','song-poetry','','[]','石門深鎖氣何雄，那得羣仙採藥蹤。',64,'全唐诗/poet.song.157000.json','["石門深鎖氣何雄，那得羣仙採藥蹤。", "列嶂時時看過鳥，懸崖歷歷長游龍。", "一書未學嵇中散，十日聊陪邴曼容。", "擬向錦屏題姓字，簫臺端的是元功。"]'),
('dc9035d3-fb2a-472a-b294-33e547800cd9','句  其一','王度','宋','宋诗','song-poetry','','[]','雲生坐來石，風掩讀殘書。',12,'全唐诗/poet.song.157000.json','["雲生坐來石，風掩讀殘書。"]'),
('5b67e581-32ce-43d0-8241-c213e573edd0','句  其二','王度','宋','宋诗','song-poetry','','[]','危紅賒晚景，漲綠上平沙。',12,'全唐诗/poet.song.157000.json','["危紅賒晚景，漲綠上平沙。"]'),
('9e138ad2-1db4-4adf-86a5-d8fd2e61f424','句  其三','王度','宋','宋诗','song-poetry','','[]','鴉分供餘食，鴿亂著殘棋。',12,'全唐诗/poet.song.157000.json','["鴉分供餘食，鴿亂著殘棋。"]'),
('cc1ddd71-0e2a-49f9-9364-ff1e7a31a0a5','句  其四','王度','宋','宋诗','song-poetry','','[]','樵斧和雲斫，漁蓑带雪披。',12,'全唐诗/poet.song.157000.json','["樵斧和雲斫，漁蓑带雪披。"]'),
('ef044672-db1e-4b52-bf1e-8dfb932a205c','望海石','胡融','宋','宋诗','song-poetry','','[]','枯藤拄苔磴，長嘯淩秋風。',96,'全唐诗/poet.song.157000.json','["枯藤拄苔磴，長嘯淩秋風。", "天空白露下，碧落摩青銅。", "夜半見海日，發軔扶桑紅。", "黄支與流求，出沒白浪中。", "久誇坎井見，始知天壤空。", "招手喚海童，寄書蓬萊宮。", "我欲蹲此石，投竿慕任公。", "巨鼇儻可得，持壓江之東。"]'),
('4ed1688a-6c91-49c2-b72e-50eb09ca098a','鍊丹井','胡融','宋','宋诗','song-poetry','','[]','荒巔有野井，古意豁冥搜。',96,'全唐诗/poet.song.157000.json','["荒巔有野井，古意豁冥搜。", "蘚石已摧剝，雲蘿閟清幽。", "憶昔抱朴翁，煉液棲高丘。", "朝飲井中泉，暮濯井下流。", "丹成已蟬蛻，巖花幾春秋。", "但見虎豹蹏，印跡碧甃頭。", "舉瓢酌寒泉，一飲銷百憂。", "日暮洞恍惚，攀桂聊淹留。"]'),
('796fd68a-8f6e-40a2-9dc7-a9e535b88064','墨池','胡融','宋','宋诗','song-poetry','','[]','吾聞逸少筆，人手銛如戈。',96,'全唐诗/poet.song.157000.json','["吾聞逸少筆，人手銛如戈。", "結廬在華頂，鑿池派天河。", "書將鬼汗寫，墨遣神手磨。", "掞藻卧白雲，禿兔堆成坡。", "臨池日月遠，素流變玄波。", "咨嗟撫遺蹟，寒猨啼薜蘿。", "搏壁尋瘞鶴，入洞求換鵞。", "長松落青蔭，石巘空摩挲。"]'),
('ed26bdd4-27ec-42e0-b80a-0103a8a835c7','書堂','胡融','宋','宋诗','song-poetry','','[]','右軍本清真，名題列仙籍。',96,'全唐诗/poet.song.157000.json','["右軍本清真，名題列仙籍。", "朝披赤城霞，憑崖望南極。", "不讀人閒書，誅茅近東壁。", "松窗拂青靄，石架橫野色。", "草聖天仙求，竹扇山猨覓。", "不有鐵石心，敢邇虎豹跡。", "高歌振林木，上與霄漢迫。", "時有太一星，擁杖照几席。"]'),
('1fb15578-3dbc-4532-8a9a-68c56cc64d29','黄經洞','胡融','宋','宋诗','song-poetry','','[]','平生山水癖，遐往心獨歖。',96,'全唐诗/poet.song.157000.json','["平生山水癖，遐往心獨歖。", "採秀凌丹丘，忽遇白雲子。", "腰劍蒼龍活，野袂青霞起。", "邀我石洞行，共坐啗石髓。", "架有黄庭經，猶是東晉紙。", "粲若錐畫沙，其字大如指。", "口傳却老術，長跪與進履。", "吾心在魏闕，焉得給薪水。"]'),
('1e90f8b7-be66-4df5-a14a-0e9727b5e8cf','伏虎壇','胡融','宋','宋诗','song-poetry','','[]','顗公天人師，猛虎屢欲瞋。',72,'全唐诗/poet.song.157000.json','["顗公天人師，猛虎屢欲瞋。", "形體掘槁木，鷙心化爲仁。", "猥厠龍象側，而作貓犬馴。", "礪齒怖天魔，掉尾迎山君。", "西伯困羑里，仲尼畏匡人。", "人心害賢聖，寧與猛虎鄰。"]'),
('d537440f-5dcc-4e9c-80b7-03fa21524308','葛仙茗園','胡融','宋','宋诗','song-poetry','','[]','絕巘匿精廬，蒼煙路孤迥。',96,'全唐诗/poet.song.157000.json','["絕巘匿精廬，蒼煙路孤迥。", "草秀仙翁園，春風坼幽茗。", "野僧四五人，腦紺瞳子炯。", "携壺汲飛瀑，呼我烹石鼎。", "風濤瀉江灘，松籟起林嶺。", "七椀鏖郝源，一水鬭雙井。", "我雖冠屨縛，心樂祇園靜。", "濯足卧禪扃，幽夢墮蒙頂。"]'),
('29d42a45-ec71-4551-b0ed-ac2cd07a7f66','葛仙宅','胡融','宋','宋诗','song-poetry','','[]','仙翁卧雲日，種松藥爐東。',72,'全唐诗/poet.song.157000.json','["仙翁卧雲日，種松藥爐東。", "千載鱗鬣古，突兀成老龍。", "蛻骨入霄漢，橫身飲長風。", "上有玄鶴巢，下有白蟻宮。", "先生昔羽化，雞犬盡淩空。", "如何刀圭妙，失此十八公。"]'),
('d173fd6c-a271-49ce-b568-b0102e3e476a','桐柏山','胡融','宋','宋诗','song-poetry','','[]','清曉騎白鹿，直上桐柏山。',108,'全唐诗/poet.song.157000.json','["清曉騎白鹿，直上桐柏山。", "山環若城郭，琪樹鬰參天。", "青猨導我路，如入崆峒巔。", "瑶草被阪綠，瓊蕊凌霜繁。", "旁瞰老子宮，玲瓏隠林閒。", "堊棟天馬出，絳柱彫龍盤。", "歖與冥寂士，共談秋水篇。", "散髮松下嘯，拂霞石上眠。", "贈我玄玉膏，相期淩紫煙。"]'),
('f4546eac-12eb-48ff-93e1-994c08719706','瓊臺','胡融','宋','宋诗','song-poetry','','[]','璿臺插中天，仙聖展游眺。',96,'全唐诗/poet.song.157000.json','["璿臺插中天，仙聖展游眺。", "亭亭珠玕樹，蒙日光照曜。", "上有天樂鳴，嘈雜聲要妙。", "浮丘倚巖聽，玉女排雲笑。", "茲游償夙心，時聞八鸞嘯。", "搴莖茹金芝，援藟愛青峭。", "琅琊失孤岫，渤海播圓嶠。", "抵掌嗤客星，石瀨坐投釣。"]'),
('7e5c3bda-b185-4ca7-896a-f172bd6390e4','雙闕','胡融','宋','宋诗','song-poetry','','[]','朝游雙闕下，遂登雙闕上。',96,'全唐诗/poet.song.157000.json','["朝游雙闕下，遂登雙闕上。", "峻壁束清溪，石扇闔奔嶂。", "旁通風雲氣，下蓄關鍵狀。", "高踰劍閣竦，狹過彭門壯。", "我行季秋月，霜飆掃霾瘴。", "崖枯水還壑，巴峽失清漲。", "矯步凌丹梯，陟嶮神愈王。", "作書遺家人，咋指悔狂妄。"]'),
('c7b94697-9b6e-4f58-a333-6e7ada44edd0','玉霄峰','胡融','宋','宋诗','song-poetry','','[]','青冥玉霄頂，靜夜無纖埃。',84,'全唐诗/poet.song.157000.json','["青冥玉霄頂，靜夜無纖埃。", "手携赤松子，拂石坐蒼苔。", "舉瓢呼海月，長虹貫金罍。", "挂劍桂樹枝，洗手天河洄。", "我欲鏟崖嶂，涉海登蓬萊。", "要觀中州碑，鼓枻雲濤堆。", "風波雖可越，長鯨正崔嵬。"]'),
('50eb0ffe-f3ac-4941-b578-7194fb48fc3d','桐柏碑','胡融','宋','宋诗','song-poetry','','[]','韓公在大曆，高名懸日月。',96,'全唐诗/poet.song.157000.json','["韓公在大曆，高名懸日月。", "游戲翰墨場，八分獨奇絕。", "遥嗤程邈鈍，近鄙伯喈拙。", "我來桐柏巔，洗眼見碑碣。", "峍屼挾風霜，鐘簴粲成列。", "龜跗閟琳宇，鐵畫照清越。", "至今氈墨工，石本走胡越。", "引袖拂台山，山盡字乃滅。"]'),
('13852c2d-885e-45ed-992d-8904746f02dd','登石臺山與劉次皋李揆王度周仲卿聯句','胡融','宋','宋诗','song-poetry','','[]','璇臺插中天，乾坤發端倪。',288,'全唐诗/poet.song.157000.json','["璇臺插中天，乾坤發端倪。", "荆榛夾險道，自古誰攀躋。", "嘉予二三友，乘興同杖藜。", "行行陟其巔，一遊手自携。", "上摩白兔宮，下躡青雲梯。", "傲晲羣動間，太倉米一稊。", "俯瞰萬家邑，戶牖開蜜脾。", "羣巒盡東騖，駛若萬驥馳。", "馬秦忽破碎，象島尤瑰琦。", "杜鵑狀雄尊，白鯉波連漪。", "視城橫朱鳥，秀連秋水湄。", "崟崟摘星嶺，上可捫南箕。", "羽人煉丹丘，迄今有遺基。", "維西控桐柏，巖壑爭獻奇。", "鴈蕩直括蒼，勢自金庭□。", "奔雷三十六，趕起龍鳳姿。", "繼北際四明，塢嶴非人窺。", "天門何蕩蕩，香巖獨嵬嵬。", "帽峰冠朝霞，髻山染夕霏。", "眼闊浮世狹，身高衆山低。", "清遊慨俗子，險語驚山魑。", "持盃迭獻酬，磨石共鎸題。", "短李才調逸，手力拔象犀。", "髯胡詩之豪，鼻息干雲霓。"]'),
('6f7c1192-0f57-463b-a240-4844a445f395','句','蕭國梁','宋','宋诗','song-poetry','','[]','名傳玉陛星辰曉，澤霈金枝雨露春。',16,'全唐诗/poet.song.157000.json','["名傳玉陛星辰曉，澤霈金枝雨露春。"]'),
('cae04e6b-3502-4220-a43a-91fe74e6d98a','效朱公叔絕交詩','薛澄','宋','宋诗','song-poetry','','[]','東山有梟，不祥其名。',90,'全唐诗/poet.song.157000.json','["東山有梟，不祥其名。", "惡木是息，惡聲是鳴。", "食不棄腐，飲不擇清。", "宜飛求伏，以晦爲明。", "凶殘滿志，嗜欲惟攖。", "伸頸招鳳，使鳳自驚。", "豈有鳳口，而和梟聲。", "奈何伊人，弗審物情。", "請從此別，各自謀生。"]'),
('bacbc391-cd1d-463d-a077-fff522130735','賦得一年將盡夜','薛澄','宋','宋诗','song-poetry','','[]','可惜惟茲夕，須臾即舊年。',48,'全唐诗/poet.song.157000.json','["可惜惟茲夕，須臾即舊年。", "人間歲窮處，客館夜分邊。", "應逐銀缸謝，聊憑玉漏延。", "曉風雖未至，殘臘幾時天。"]'),
('038e967e-a1ca-42da-b142-5670d99d5610','立夏','薛澄','宋','宋诗','song-poetry','','[]','漸覺風光燠，徐看樹色稠。',48,'全唐诗/poet.song.157000.json','["漸覺風光燠，徐看樹色稠。", "蠶新教織綺，貂敝豈辭裘。", "酷有烟波好，將圖荷芰遊。", "田間讀書處，新笋萬竿抽。"]'),
('b7fdefba-fb87-49cd-b383-74acc23dc8cb','題石䂬','黄希','宋','宋诗','song-poetry','','[]','誰賦阿房未霽虹，祇誇複道峭淩空。',64,'全唐诗/poet.song.157000.json','["誰賦阿房未霽虹，祇誇複道峭淩空。", "那知海石驅來處，都在巖花晏坐中。", "鯨背遠衝千嶂雨，鼇頭高占一天風。", "漫郎更有中興頌，倩把蒼崖仔細礱。"]'),
('dff498f9-7fc0-438a-824e-6c04ac552884','黄漿山','黄鵬舉','宋','宋诗','song-poetry','','[]','清泉徹底瑩無泥，喚作黄漿恐未宜。',32,'全唐诗/poet.song.157000.json','["清泉徹底瑩無泥，喚作黄漿恐未宜。", "若見洞仙還寄語，佳名當喚碧琉璃。"]'),
('a29e2984-6f51-4689-9a08-80082b55fb3b','北堂  其一','黄公槐','宋','宋诗','song-poetry','','[]','瞻彼北堂，在彼永陽。',20,'全唐诗/poet.song.157000.json','["瞻彼北堂，在彼永陽。", "白雲之下，通化之鄉。"]'),
('b078c441-74e2-457a-aeaf-0c5705e78ecd','北堂  其二','黄公槐','宋','宋诗','song-poetry','','[]','瞻彼北堂，在彼永水。',20,'全唐诗/poet.song.157000.json','["瞻彼北堂，在彼永水。", "白雲之下，新豐之里。"]'),
('3fd1cfc6-c8ff-4929-af54-8b0ba8c824bf','北堂  其三','黄公槐','宋','宋诗','song-poetry','','[]','北堂有子，其實三兮。',20,'全唐诗/poet.song.157000.json','["北堂有子，其實三兮。", "仲焉此去，其心慘兮。"]'),
('f1f500a6-9acc-4ad1-b417-adec5f829f80','挽呂東萊先生  其一','黄人傑','宋','宋诗','song-poetry','','[]','夫子來天上，儒宗第一人。',48,'全唐诗/poet.song.157000.json','["夫子來天上，儒宗第一人。", "英材歸樂育，聖學發沉堙。", "正路方資闢，澆風未及醇。", "斯文何遽喪，詩筆絕生民。"]'),
('67935643-7da8-4052-b4b6-025cf9c125c7','挽呂東萊先生  其二','黄人傑','宋','宋诗','song-poetry','','[]','盛德光華閥，高風動九垓。',48,'全唐诗/poet.song.157000.json','["盛德光華閥，高風動九垓。", "群英傾斗仰，一旦駭山頹。", "吾道無綱紐，熙朝乏鼎梅。", "明招涵夜月，忍聽曉猿哀。"]'),
('5020eb9f-6f86-4e43-b2ea-b1b2b4fd9432','挽呂東萊先生  其三','黄人傑','宋','宋诗','song-poetry','','[]','天意高難問，胡爲奪巨賢。',48,'全唐诗/poet.song.157000.json','["天意高難問，胡爲奪巨賢。", "後生安取正，聖道不容傳。", "感意悲風木，傷心慘暮烟。", "翩翩丹旐去，徒有淚潸然。"]'),
('6a4bc691-75c4-4d14-bb2c-0a23afdec836','挽呂東萊先生  其四','黄人傑','宋','宋诗','song-poetry','','[]','憶昨飄零日，徒爲梁父吟。',48,'全唐诗/poet.song.157000.json','["憶昨飄零日，徒爲梁父吟。", "一時辱輕信，千里示佳音。", "方講門人禮，蒙嘉國士臨。", "一朝遽千古，難保見知心。"]'),
('37703de9-8ec7-4401-8c3f-56282e100995','挽呂東萊先生  其五','黄人傑','宋','宋诗','song-poetry','','[]','萍迹來京闕，逾涯辱意隆。',48,'全唐诗/poet.song.157000.json','["萍迹來京闕，逾涯辱意隆。", "劇談銷客氣，終月坐春風。", "豈謂十旬別，俄成千歲終。", "哀哉不復見，天闊恨無窮。"]'),
('11e5e6e2-b289-498e-8e4d-0af577600f1a','峽中山高巳牌方見日色','黄人傑','宋','宋诗','song-poetry','','[]','上峽扁舟穩，灘平水不波。',48,'全唐诗/poet.song.157000.json','["上峽扁舟穩，灘平水不波。", "山高見日晚，谷遠受雲多。", "亂石爭奇怪，幽禽自嘯歌。", "若無詩寫興，柰此景佳何。"]'),
('7228f8aa-63e9-4a88-bb18-736b6066f252','溫泉','黄人傑','宋','宋诗','song-poetry','','[]','離火自天爍，溫泉由地生。',24,'全唐诗/poet.song.157000.json','["離火自天爍，溫泉由地生。", "我來需曉汲，聊用濯塵纓。"]'),
('04add8d4-472d-44c3-92ab-94d1bb2edbc1','次袁尚書巫山十二峰二十五韻','黄人傑','宋','宋诗','song-poetry','','[]','文昌老仙絕俗姿，愛山成癖非兒癡。',396,'全唐诗/poet.song.157000.json','["文昌老仙絕俗姿，愛山成癖非兒癡。", "胸中况自有丘壑，檻結瑰異常恐遲。", "坤維謀畧出分閫，江山致助爭出奇。", "尋幽選勝上巫峽，斷崖怪石懸參差。", "十二峯前弭征楫，枝藤直上窮所之。", "雲煙變態千萬狀，過眼神動驚天隨。", "人疑躋攀欲力盡，公自樂此良不疲。", "瑶華真妃似夙駕，風馬晝下揚旛旗。", "層巒好處起蒼壁，丹霞望門開赤帷。", "登壇定可拾瑶翠，却老未應無玉枝。", "仰天一笑晲寥廓，俯視培塿丘陵低。", "頗疑遊龍出飛躍，恍若栖鳳猶娛嬉。", "喬松跨鶴遠近集，雲雨濟人朝暮爲。", "壇羅野翠有餘潤，泉拖修帛無窮時。", "一經盼睞便改觀，陽臺價重當由茲。", "惜哉牙纛不久駐，鷁首未轉檣烏馳。", "輕縑素練欲摹寫，畫師難著五色施。", "筆端機杼始潜運，悠然寄興滄洲湄。", "章成密簡繡衣使，繡衣翰墨今白眉。", "珠酬玉唱兩相尚，三嘆盡解騷人頤。", "好刊蒼珉示千古，磨而不磷涅不緇。", "紛紛我輩小巫耳，健讀數過徒噫嘻。", "待從兩公奠西極，安南嶷，收關河百二之險，劖岷峨萬仞之嵋。", "大書有宋中興頌，東還更和巫山詩。"]'),
('a1400d59-392e-4815-b222-89c08b720169','官舍苦雨','黄人傑','宋','宋诗','song-poetry','','[]','漫空數日雨傾盆，老屋淋漓瓦縫穿。',64,'全唐诗/poet.song.157000.json','["漫空數日雨傾盆，老屋淋漓瓦縫穿。", "七月不虛爲巧月，今年頼得是豐年。", "泥塗滑滑妨行客，煙隴陰陰礙種田。", "我欲乘風干造化，盡披雲霧覩青天。"]'),
('60625c5a-a578-474e-aecd-4cecf561ddfa','句','黄人傑','宋','宋诗','song-poetry','','[]','亂山圍楚塞，平野落荆州。',12,'全唐诗/poet.song.157000.json','["亂山圍楚塞，平野落荆州。"]'),
('264258fa-caff-451b-ae3a-90f388a379c7','示郭仲達  其一','葉時亨','宋','宋诗','song-poetry','','[]','撮髮從遊成潦倒，拍肩話舊歎蹉跎。',64,'全唐诗/poet.song.157000.json','["撮髮從遊成潦倒，拍肩話舊歎蹉跎。", "年來對酒詩狂減，老去傷時愁緒多。", "顧我曳裙今尚爾，念君求祿竟如何。", "不應例合俱窮躓，造化兒癡故作魔。"]'),
('c2bed83d-4d21-4616-938d-d6db2c87c583','示郭仲達  其二','葉時亨','宋','宋诗','song-poetry','','[]','男子升沉雖繫天，風花高下亦俄然。',64,'全唐诗/poet.song.157000.json','["男子升沉雖繫天，風花高下亦俄然。", "功名未老終歸手，富貴須時小著鞭。", "落魄羈懷長道路，蒼茫客面染風煙。", "張儀此舌欣無恙，談笑封侯會有年。"]'),
('206006ae-3af2-41aa-b381-dffb883281c7','泛舟松江','葉時亨','宋','宋诗','song-poetry','','[]','短棹夷由落照間，不堪凝望發愁端。',64,'全唐诗/poet.song.157000.json','["短棹夷由落照間，不堪凝望發愁端。", "雁行影沒暮天闊，蘋葉香殘秋水寒。", "朝市觸塗成險棘，風波投足却輕安。", "白鷗盟在容尋理，急辦煙簑與釣竿。"]'),
('3fa40ef2-c4a6-400e-86fe-30d2c9da4e50','丹霞嶼','林宗臣','宋','宋诗','song-poetry','','[]','笑憑詩句說丹霞，城郭人民數萬家。',32,'全唐诗/poet.song.157000.json','["笑憑詩句說丹霞，城郭人民數萬家。", "禮接紫陽風俗厚，學傳東魯道源賒。"]'),
('66499b6d-c70d-4e56-95b5-2f300b81b119','次韵盧彥德學宮詩','楊輔','宋','宋诗','song-poetry','','[]','頗怪諸生籍奉常，寂寥科目歲年長。',64,'全唐诗/poet.song.157000.json','["頗怪諸生籍奉常，寂寥科目歲年長。", "只今五桂名猶在，恐有孤桐曲未忘。", "學校規模新壯麗，江山意氣久徊翔。", "分光膚使青瑶句，收拾風霆喚阿香。"]'),
('bf085816-3d90-4e8d-bdcc-11b90b3beb46','和經略煥章朱公千葉白梅詩','胡長卿','宋','宋诗','song-poetry','','[]','天憐素質太柔輕，不奈西風雪片凝。',64,'全唐诗/poet.song.157000.json','["天憐素質太柔輕，不奈西風雪片凝。", "故與紅顔如美玉，尚餘清影似寒冰。", "黄香僅可追多葉，重萼堪憐只兩層。", "欲問園官分此貼，宜樓深遠歎難應。"]'),
('3d2f96b2-8d2a-48bd-9cb1-eaca0202b92b','禁煙日陪經略煥章丈遊白龍洞得所賦新詩次韵以呈','胡長卿','宋','宋诗','song-poetry','','[]','懸崖怪石水潺潺，宜有神龍隠此間。',64,'全唐诗/poet.song.157000.json','["懸崖怪石水潺潺，宜有神龍隠此間。", "窮勝不妨穿險洞，尋春那止看羣山。", "攀龍行即天邊去，躍馬聊同野外還。", "好景良辰適相會，一尊且共水雲閑。"]'),
('c846f7cb-2201-4495-932f-2cdfd110b9cc','容州聞雁','胡長卿','宋','宋诗','song-poetry','','[]','舊聞雁不到衡陽，今復南飛入瘴鄉。',32,'全唐诗/poet.song.157000.json','["舊聞雁不到衡陽，今復南飛入瘴鄉。", "天闊隨陽皆可去，未應爲界限瀟湘。"]'),
('8c9f2251-37fc-409b-8170-e387984b50a3','句','胡長卿','宋','宋诗','song-poetry','','[]','聞道嘉魚出火山，我來那得一鱗看。',16,'全唐诗/poet.song.157000.json','["聞道嘉魚出火山，我來那得一鱗看。"]'),
('3e400708-9377-4f77-87ec-cbc91963eb1b','化成巖','趙善堅','宋','宋诗','song-poetry','','[]','低帽白蕉衫，跨馬北巖路。',120,'全唐诗/poet.song.157000.json','["低帽白蕉衫，跨馬北巖路。", "爲我撤炎歊，時有清風度。", "投策躡遊屐，捫蘿窮幽趣。", "怪石鳴瘦筇，狹徑窘危步。", "雲間啟深洞，玲瓏天巧露。", "僧侶羅上下，鐘聲答晨暮。", "長笑排翠謁，圍棋驚振鷺。", "陶寫屏絲竹，恐爲風景污。", "拂蘚題蒼崖，縱橫醉中句。", "茲遊豈易得，載酒莫辭屢。"]'),
('9a7c6d2a-25d8-4f29-9e08-7b254633ea18','盤齋','嚴嘉賓','宋','宋诗','song-poetry','','[]','孔明天下士，當年卧南陽。',84,'全唐诗/poet.song.157000.json','["孔明天下士，當年卧南陽。", "一室儻已足，未害志四方。", "盤齋誠有餘，輾轉意味長。", "攢書以爲娛，殖蘭以爲芳。", "四友置左右，聖賢味中央。", "要爲陋巷回，抑作干祿張。", "何當膏吾車，相從以徜徉。"]'),
('13ee1300-8457-4ff8-8412-61c4864f5437','離鐔津','劉志行','宋','宋诗','song-poetry','','[]','公事無多早散衙，蜀中寧有寄來茶。',64,'全唐诗/poet.song.157000.json','["公事無多早散衙，蜀中寧有寄來茶。", "龍光下照三江水，燕子重尋百姓家。", "疇昔買漿曾得玉，只今作飯類蒸沙。", "寄言道士玄都客，好種劉郎去後花。"]'),
('d8c623de-4834-4c38-bc11-52572a849bbf','藤江','劉志行','宋','宋诗','song-poetry','','[]','驛使何曾寄嶺梅，古藤花下小徘徊。',64,'全唐诗/poet.song.157000.json','["驛使何曾寄嶺梅，古藤花下小徘徊。", "無名異果自成樹，沒字殘碑半是苔。", "木杪山雞知旦晝，江心仙島欠樓臺。", "灘神憑險成遺廟，笑我何因到此來。"]'),
('ce747a34-d2fb-4123-bc6b-c003a9be1821','堯山冬雪','劉志行','宋','宋诗','song-poetry','','[]','洪濛一判天地曉，萬古茲山青未了。',64,'全唐诗/poet.song.157000.json','["洪濛一判天地曉，萬古茲山青未了。", "朔南聲教本一源，大地圖輿古無考。", "玄冥此來事遊戯，剪水作花南到地。", "臘前不識豐年瑞，翻令粵犬雲間吠。"]'),
('b74154ac-6887-480d-8de9-aed34a7b5e3b','舜洞秋風','劉志行','宋','宋诗','song-poetry','','[]','當年大駕巡南中，薰兮時兮歌南風。',64,'全唐诗/poet.song.157000.json','["當年大駕巡南中，薰兮時兮歌南風。", "太音九奏鳳凰集，真與塵世開盲聾。", "重華遠矣成飛仙，湘靈灑淚秋風前。", "天荒地老不可詰，秋風滿樹淒寒蟬。"]'),
('1509717b-b771-4784-8d48-7a525f0e69b2','鳳山','俞豐','宋','宋诗','song-poetry','','[]','老樹蕭蕭吹古風，滿階落葉鳴寒蛩。',64,'全唐诗/poet.song.157000.json','["老樹蕭蕭吹古風，滿階落葉鳴寒蛩。", "插天殿閣雲不鎖，挺柱石筍擎太空。", "鳳去臺空秋寂寂，瑶草離離自青碧。", "玉簫吹徹渺遺音，十二闌干空月色。"]'),
('011e4537-d87d-4f5b-8d76-84af47088fcb','忠孝亭','周洎','宋','宋诗','song-poetry','','[]','晉鼎臲卼姦人窺，孰謀國者如兒嬉。',226,'全唐诗/poet.song.157000.json','["晉鼎臲卼姦人窺，孰謀國者如兒嬉。", "陷穽弗設延虎貔，虓闞搏噬嬰者摧。", "羣公奔潰不敢誰，卞公力疾起督師。", "謂事迫矣奚生爲，以肉餧虎吁可悲。", "公則死矣二子隨，偉哉忠孝萃一時。", "維公忠義天所資，向來謀國如蓍龜。", "不用吾言至于斯，爲社稷死則死之。", "冶城之麓江之湄，荒冢突兀餘豐碑。", "半生讀史長歔欷，拜公之墳涕霑頤。", "死者可作吾誰歸，嗟哉江左固多士。", "往往所欠惟一死，元規兒輩何足罪。", "王公偪仄石頭裏，氣息奄奄有如泉下鬼。", "蘇武之節不如是，視公胡不顙有泚。", "男子之死一言耳，死而不亡公父子。"]'),
('d6e7bfdd-4168-4ecd-a838-304474650d67','宗忠簡公畫像贊','陳炳','宋','宋诗','song-poetry','','[]','平生孔明，稱慕莫及。',60,'全唐诗/poet.song.157000.json','["平生孔明，稱慕莫及。", "像見忠簡，懦夫有立。", "橫流砥柱，萬里長城。", "欲奮空弮，以植危傾。", "猛將歛手，氣指目使。", "誰知此公，亦裳布士。"]'),
('4771b8cc-b289-44b8-badb-9dd6172f743f','巢湖神母廟詩','陳炳','宋','宋诗','song-poetry','','[]','舟之來兮風高，蕩汩潏兮帆招。',145,'全唐诗/poet.song.157000.json','["舟之來兮風高，蕩汩潏兮帆招。", "燎薰在堂兮潔涓牲牢，望神儼然兮歛袵，願速濟我兮不崇朝。", "舟之去兮風微，波渺瀰兮迅于，飛帆拂兮茫無涯。", "眼眩膽栗兮將安之，我有願兮惟神焉依。", "秋深兮木落，葭葦蕭騷兮清日薄。", "神兮今焉在，吞吐月星兮獨處廓。", "神甚仁兮寧以爲禍，愚有弗虔兮幸賁過。", "天地一葉兮相繼，神無波濤兮駭我。"]'),
('914e757d-3c1a-40be-a5fe-a6f00d91c2ce','望黄山詞','陳炳','宋','宋诗','song-poetry','','[]','望黄山兮峨峨，見接天以葱青。',242,'全唐诗/poet.song.157000.json','["望黄山兮峨峨，見接天以葱青。", "紛羣峰兮怪奇，眩百變兮幽明。", "朱砂湯兮山椒，下白龍兮甚靈。", "襲深潭兮百尺，夜有光兮晶熒。", "山中泉兮娛嬉，坐蛇虺兮隠形。", "歲徂夏兮不雨，農失望兮麕驚。", "禾稼鬰兮滿野，垂槁死兮無成。", "訴哀恫兮神祠，牲豆陳兮芬馨。", "巫誇詡兮後先，龍跧處兮皇寧。", "合歸雲兮九霄，麾雷公兮震霆。", "前豐隆兮戒路，叱雨師兮建瓴。", "予朅來兮江東，元礱竅兮儲瓶。", "井邑荒兮窮谷，門兩版兮常扃。", "汎襏襫兮良勤，幾視日兮占星。", "粟升斗兮莫飽，將填壑兮鰥煢。", "官吾卑兮何求，職水旱兮憂矜。", "願時以雲兮又以雨，黄之田兮世世可耕。"]'),
('480f91aa-0385-49e8-9948-99d29b49dba8','泛秋浦辭','陳炳','宋','宋诗','song-poetry','','[]','九華北兮瀨東，石畏硊兮屈盤。',298,'全唐诗/poet.song.157000.json','["九華北兮瀨東，石畏硊兮屈盤。", "誰此遊兮萬頃，初禹鑿兮何年。", "窈其深兮莫測，微波湧兮淪漣。", "民連甍兮渚居，矗百雉兮造天外。", "涵青青兮幾城，混金碧兮中邊。", "羌予行兮酷暑，修途邈兮回邅。", "埃迷目兮眵昏，僕馬瘦兮躓顛。", "若有人兮扁舟，破菱荷以徑前。", "接予袂兮俱往，欲駕我兮登仙。", "與汝釣兮空明，魚雜龍兮藻荇青。", "與汝浴兮靚深，悲風度兮秋濤生。", "與汝遊兮嵌巖，駭鷗鳬兮爭翾。", "與汝望兮茫冥，若有無兮飛煙。", "水一去兮入海，問此程兮數千。", "指蓬萊兮一髮，有安期兮偓佺。", "紫貝闕兮珠宮，笑紛卑兮塵寰。", "沆瀣飲兮芝餐，盍輕舉兮蛻蟬。", "嗟吾生兮窮屯，履平地兮奔湍。", "心炯炯兮猶在，願脫屣兮人間。", "青楓老兮欲丹，露溥溥兮山寒。", "吾何歸兮日暮，寄此懷兮江之南。"]'),
('c7c16534-34d3-4d22-b135-d260c1434920','翠微寺','陳炳','宋','宋诗','song-poetry','','[]','麻衣休作獅子吼，門外泉聲正拍空。',32,'全唐诗/poet.song.157000.json','["麻衣休作獅子吼，門外泉聲正拍空。", "三十六峰渾不見，翠微真在有無中。"]'),
('440f01f7-2d3f-42d8-86b1-e9629da88d46','栲栳山','章潛','宋','宋诗','song-poetry','','[]','秀色團團如栲栳，孤高端可壓羣山。',32,'全唐诗/poet.song.157000.json','["秀色團團如栲栳，孤高端可壓羣山。", "藏雲蓄雨無蹤跡，怨鶴啼猿自往還。"]'),
('a1762d71-b681-4556-9f52-ab3551ae6fd6','秋夜賞桂','王寧','宋','宋诗','song-poetry','','[]','秋風吹天香，先著桂枝裏。',72,'全唐诗/poet.song.157000.json','["秋風吹天香，先著桂枝裏。", "更挹月露清，芬馥喚睡起。", "攬衣夜未央，泉喧不入耳。", "有來蕊珠仙，黄袂翠蓋底。", "豈無碧雲腴，爲君一啟齒。", "醉卧金粟間，絕勝佩蘭芷。"]'),
('5f4786f0-7299-4dc1-b464-e44198c2d627','和樓守浮遠堂留題','王寧','宋','宋诗','song-poetry','','[]','久去鄉關始一來，竹輿行樂亦佳哉。',64,'全唐诗/poet.song.157000.json','["久去鄉關始一來，竹輿行樂亦佳哉。", "還尋童子釣游處，又趁史君旌騎迴。", "風物于人隨意好，江山如畫得天開。", "向來紀勝歸名筆，喜爲重鑱置石崖。"]'),
('227a2490-da06-43a5-95ff-950170bdddad','句','吳瓌','宋','宋诗','song-poetry','','[]','飽看七寶山頭月，慣聽三茅觀裏鐘。',16,'全唐诗/poet.song.157000.json','["飽看七寶山頭月，慣聽三茅觀裏鐘。"]'),
('e5b66a04-4fba-461b-8a2b-3abd6b538180','大滌洞天留題  其一','謝岳甫','宋','宋诗','song-poetry','','[]','朝乘雲氣上蓬萊，九鎖仙峰翠作堆。',32,'全唐诗/poet.song.157000.json','["朝乘雲氣上蓬萊，九鎖仙峰翠作堆。", "可惜洞天閑日月，人生能得幾回來。"]'),
('a29ec033-908d-4fe2-8ed8-686242329f82','大滌洞天留題  其二','謝岳甫','宋','宋诗','song-poetry','','[]','天然奇石聳雲端，下浸龍泓一掬寒。',32,'全唐诗/poet.song.157000.json','["天然奇石聳雲端，下浸龍泓一掬寒。", "靜聽潺湲眠未得，不妨乘月依闌干。"]'),
('e3c7eefb-4ea2-4ad7-ad97-3416020f62c0','大滌洞天留題  其三','謝岳甫','宋','宋诗','song-poetry','','[]','入山細問山中事，紺宇瓊居八百年。',64,'全唐诗/poet.song.157000.json','["入山細問山中事，紺宇瓊居八百年。", "五洞潛通誰縮地，一峰突起解擎天。", "眼前去馬來牛債，夢裏驂鸞跨鵠緣。", "却羨黄冠無一事，卧聽簫吹落雲邊。"]'),
('2f1e62ad-0a06-487f-a8c4-a2f5d7cc0628','鳴山','馬覺','宋','宋诗','song-poetry','','[]','我來方自噤，投宿寓鳴山。',24,'全唐诗/poet.song.157000.json','["我來方自噤，投宿寓鳴山。", "立仗古所戒，對山空厚顔。"]'),
('b034a230-49b9-4d33-bb89-c06e778879c7','許由','呂祖謙','宋','宋诗','song-poetry','','[]','許由不耐事，逃堯獨參寥。',72,'全唐诗/poet.song.157000.json','["許由不耐事，逃堯獨參寥。", "行至箕山下，盈耳康衢謠。", "謂此汙我耳，臨流洗塵囂。", "水中見日馭，勞苦如堯朝。", "堯天接山際，堯雲抹山椒。", "誰云能避世，處處悉逢堯。"]'),
('d20d3f8c-1861-4683-a81c-cb8c3da8915b','清曉出郊','呂祖謙','宋','宋诗','song-poetry','','[]','落月窺甕牖，殷勤喚人醒。',120,'全唐诗/poet.song.157000.json','["落月窺甕牖，殷勤喚人醒。", "蓐食治野裝，行行向郊坰。", "林端橫宿靄，未放羣山青。", "藕花斷復續，莫辨浦與汀。", "初聞露花香，一洗廛市腥。", "清景竟難挽，晨光著郵亭。", "留眼數天際，尚餘三四星。", "車塵駕暑氣，白汗如翻瓶。", "凉燠一機耳，慍喜誰使令。", "泠然解其會，冰壺在中扃。"]'),
('fab33000-c67c-471c-b7ad-4f5add2d910a','城樓','呂祖謙','宋','宋诗','song-poetry','','[]','城峻先迎月，簾疎不隔風。',48,'全唐诗/poet.song.157000.json','["城峻先迎月，簾疎不隔風。", "棋聲傳下界，鴈影沒長空。", "島嶼秋光裏，樓臺海氣中。", "登臨故待晚，雨外夕陽紅。"]'),
('9915a907-5111-46f1-a5de-45d1f103911c','西興道中二首  其一','呂祖謙','宋','宋诗','song-poetry','','[]','鳬鶩迎船似有情，隨波故起綠粼粼。',32,'全唐诗/poet.song.157000.json','["鳬鶩迎船似有情，隨波故起綠粼粼。", "野花照水開無主，誰信春歸已兩旬。"]'),
('1755c0e5-47a9-4291-8f5c-73886d866442','西興道中二首  其二','呂祖謙','宋','宋诗','song-poetry','','[]','桑麻張王不知春，帝恐鶑花太斷魂。',32,'全唐诗/poet.song.157000.json','["桑麻張王不知春，帝恐鶑花太斷魂。", "東岸紅霞西岸綠，却將景色爲平分。"]'),
('8d9fe09a-be71-4653-b477-2c4be3984277','晚望','呂祖謙','宋','宋诗','song-poetry','','[]','獨立荒亭數過帆，橫林疎處見滄灣。',32,'全唐诗/poet.song.157000.json','["獨立荒亭數過帆，橫林疎處見滄灣。", "故知不入豪華眼，送與鳬鷗自在看。"]'),
('26c72671-c296-4460-ade5-352727cf3c5a','春日七首  其一','呂祖謙','宋','宋诗','song-poetry','','[]','江梅已過杏花初，尚怯春寒著萼疎。',32,'全唐诗/poet.song.157000.json','["江梅已過杏花初，尚怯春寒著萼疎。", "待得重來幾枝在，半隨蝶翅半蜂鬚。"]'),
('a87b435d-5120-42de-94d6-92c07725cf6f','春日七首  其二','呂祖謙','宋','宋诗','song-poetry','','[]','短短菰蒲綠未齊，汀洲水暖鴈行低。',32,'全唐诗/poet.song.157000.json','["短短菰蒲綠未齊，汀洲水暖鴈行低。", "柳陰小艇無人管，自送流花下別溪。"]'),
('dea41b99-0021-4f9b-a0f5-2163957d0691','春日七首  其三','呂祖謙','宋','宋诗','song-poetry','','[]','岸容山意兩溶溶，便是東皇第一功。',32,'全唐诗/poet.song.157000.json','["岸容山意兩溶溶，便是東皇第一功。", "春色平鋪人不見，却將醉眼認繁紅。"]'),
('63e7b6b2-a20e-4c0d-a9ff-314c77d8037d','春日七首  其四','呂祖謙','宋','宋诗','song-poetry','','[]','春波無力未勝鷗，夾岸山光翠欲流。',32,'全唐诗/poet.song.157000.json','["春波無力未勝鷗，夾岸山光翠欲流。", "若使畫成驚顧陸，更教吟出壓曹劉。"]'),
('c88220ac-a46f-45c4-b46f-2aa084540a92','春日七首  其五','呂祖謙','宋','宋诗','song-poetry','','[]','絡石寒毛澗底明，春來綠徧小崢嶸。',32,'全唐诗/poet.song.157000.json','["絡石寒毛澗底明，春來綠徧小崢嶸。", "憑誰再續平泉記，爲定芸蘭孰弟兄。"]'),
('c65d77a1-ccd7-4d29-9ec6-4dc81fe23bc7','春日七首  其六','呂祖謙','宋','宋诗','song-poetry','','[]','一川曉色鷺分去，兩岸煙光鶑带來。',32,'全唐诗/poet.song.157000.json','["一川曉色鷺分去，兩岸煙光鶑带來。", "徑欲卜居從釣叟，綠楊缺處竹門開。"]'),
('b109f12b-33a2-4da4-a124-3c3ea67d5a97','春日七首  其七','呂祖謙','宋','宋诗','song-poetry','','[]','簷鐸無聲鳥語稀，徑深鐘梵出花遲。',32,'全唐诗/poet.song.157000.json','["簷鐸無聲鳥語稀，徑深鐘梵出花遲。", "日長徧遶溪南寺，未信東風屬酒旗。"]'),
('19de312b-9c2f-47be-beed-32d1c96e6d9c','登八詠樓有感','呂祖謙','宋','宋诗','song-poetry','','[]','仲舒舊事無人記，家令風流一世傾。',32,'全唐诗/poet.song.157000.json','["仲舒舊事無人記，家令風流一世傾。", "天下何曾識真吏，古來幾許尚虛名。"]'),
('5986b1a4-3e30-4c27-aa79-aba16559ece9','富陽舟中夜雨','呂祖謙','宋','宋诗','song-poetry','','[]','萬頃煙波一葉舟，已將心事付溟鷗。',32,'全唐诗/poet.song.157000.json','["萬頃煙波一葉舟，已將心事付溟鷗。", "蓬籠夜半蕭蕭雨，探借幽人八月秋。"]'),
('1c7b537a-1bd6-42d4-b360-1ce5c8eba1b4','野步','呂祖謙','宋','宋诗','song-poetry','','[]','石梁俯清流，苔髮明可數。',48,'全唐诗/poet.song.157000.json','["石梁俯清流，苔髮明可數。", "茅簷春晝長，寂寂亭陰午。", "鳥啼花徑深，風絮浩無主。", "幽人不可親，棋聲時出戶。"]'),
('66d3a9d4-9c59-4698-9da7-c91823bd5232','晚春二首  其一','呂祖謙','宋','宋诗','song-poetry','','[]','卷地狂風殿晚春，落花蓋水欲成雲。',32,'全唐诗/poet.song.157000.json','["卷地狂風殿晚春，落花蓋水欲成雲。", "向人不改故時面，惟有蒼官與此君。"]'),
('697e0eda-3976-4ea3-a41a-1a1ee5ae0bc3','晚春二首  其二','呂祖謙','宋','宋诗','song-poetry','','[]','風絮流花一任渠，北窗高卧綠陰初。',32,'全唐诗/poet.song.157000.json','["風絮流花一任渠，北窗高卧綠陰初。", "閉門春色閒中老，爲謝平生董仲舒。"]'),
('f4c5f053-17fc-4e4f-80c9-13a755f1db79','明招雜詩四首  其一','呂祖謙','宋','宋诗','song-poetry','','[]','鳥聲報僧眠，鐘聲報僧起。',48,'全唐诗/poet.song.157000.json','["鳥聲報僧眠，鐘聲報僧起。", "靜中輕白日，邈視東流水。", "風月有逢迎，出門聊徙倚。", "傳徧南北村，松間橫屐齒。"]'),
('4ccffb5b-0e90-47df-8173-f625bbdf20f5','明招雜詩四首  其二','呂祖謙','宋','宋诗','song-poetry','','[]','前山雨退花，餘芳棲老木。',48,'全唐诗/poet.song.157000.json','["前山雨退花，餘芳棲老木。", "卷藏萬古春，歸此一窗竹。", "浮光泛軒檻，秀色若可掬。", "豐腴當夕餐，大勝五鼎肉。"]'),
('22a988b7-c94c-4c2a-98ec-0d24eb155200','明招雜詩四首  其三','呂祖謙','宋','宋诗','song-poetry','','[]','牆竹生夏陰，風荷留宿露。',24,'全唐诗/poet.song.157000.json','["牆竹生夏陰，風荷留宿露。", "解衣一盤礴，此豈不足付。"]'),
('dbd0350f-25e7-4de2-bfdc-17ec90602255','明招雜詩四首  其四','呂祖謙','宋','宋诗','song-poetry','','[]','風簷裊茶煙，銅瓶語相泣。',24,'全唐诗/poet.song.157000.json','["風簷裊茶煙，銅瓶語相泣。", "清陰一疎箔，不礙飛花入。"]'),
('8ca62d88-9f94-4a34-9a4c-37aecf123c2f','遊絲','呂祖謙','宋','宋诗','song-poetry','','[]','遊絲浩蕩醉春光，倚頼微風故故長。',32,'全唐诗/poet.song.157000.json','["遊絲浩蕩醉春光，倚頼微風故故長。", "幾度鶑聲留欲住，又隨飛絮過東牆。"]'),
('047fcf3c-6c05-4929-bc61-37bf5c5f7f80','夏日','呂祖謙','宋','宋诗','song-poetry','','[]','階前水樂元無譜，簷外風琴不用絃。',32,'全唐诗/poet.song.157000.json','["階前水樂元無譜，簷外風琴不用絃。", "待喚青奴與黄嬭，爲君極意作今年。"]'),
('3e4fa727-5a09-4f5c-b5e3-4d5b92d24b2d','鄭武子刪定挽章二首  其一','呂祖謙','宋','宋诗','song-poetry','','[]','博洽推諸老，胸中幾石渠。',48,'全唐诗/poet.song.157000.json','["博洽推諸老，胸中幾石渠。", "暮年終反約，精義本無餘。", "羲易忘言後，楞伽絕筆初。", "長歸應不憾，舊學盡成書。"]'),
('40688bc0-0410-4c94-903d-3e310ccfc899','鄭武子刪定挽章二首  其二','呂祖謙','宋','宋诗','song-poetry','','[]','古汴豪英海，追隨不厭勤。',48,'全唐诗/poet.song.157000.json','["古汴豪英海，追隨不厭勤。", "廛中識梅福，簾下得嚴君。", "培養逢原學，堙沈濟世勳。", "定知千載後，下馬董生墳。"]'),
('84faddef-78d8-4898-b22d-7962960aeb4d','又二首  其一','呂祖謙','宋','宋诗','song-poetry','','[]','平生丈人行，每語盡箴規。',48,'全唐诗/poet.song.157000.json','["平生丈人行，每語盡箴規。", "問字揚雄宅，談經董相帷。", "壺觴陪勝踐，杖屨及深期。", "誰料南歸日，墳前宿草衰。"]'),
('134fcb99-a04e-4eb6-a4c2-50ea6f10e8a2','又二首  其二','呂祖謙','宋','宋诗','song-poetry','','[]','公未陪經幄，還應典奉常。',48,'全唐诗/poet.song.157000.json','["公未陪經幄，還應典奉常。", "如何便沈沒，不使少翺翔。", "幽壤千年閉，名山萬卷藏。", "升堂多俊彥，築室繞高岡。"]'),
('27449330-7bda-4838-8667-40e239131c9c','陳庭堅聘君挽章二首  其一','呂祖謙','宋','宋诗','song-poetry','','[]','沙尾三家市，人聲半米鹽。',48,'全唐诗/poet.song.157000.json','["沙尾三家市，人聲半米鹽。", "悠然搔短髮，忽此見長髯。", "觴詠歡初合，溪山氣已添。", "豐城埋劍夜，太史定先占。"]'),
('203d628b-feb4-4028-8938-619ae107e868','陳庭堅聘君挽章二首  其二','呂祖謙','宋','宋诗','song-poetry','','[]','大門三世舊，是邑兩公同。',48,'全唐诗/poet.song.157000.json','["大門三世舊，是邑兩公同。", "易策它年絕，詩筒去歲空。", "朱簾豹隠雨，白馬虎谿風。", "好在慈恩塔，亭亭翠靄中。"]'),
('60b6fba1-1570-4ae7-8bdb-69bef619a790','鞏采若府推母錢夫人挽章二首  其一','呂祖謙','宋','宋诗','song-poetry','','[]','內助功推冠，名成父子間。',48,'全唐诗/poet.song.157000.json','["內助功推冠，名成父子間。", "中原遺俗盡，舊族素風還。", "石窌天開邑，宮門日綴班。", "光華竟何許，夕照在西山。"]'),
('83301db8-3b99-4955-8fc2-4c24b5774d0c','鞏采若府推母錢夫人挽章二首  其二','呂祖謙','宋','宋诗','song-poetry','','[]','歷歷稱觴地，悲凉騎省園。',48,'全唐诗/poet.song.157000.json','["歷歷稱觴地，悲凉騎省園。", "風枝今日恨，露葉去年痕。", "鸞翥昏遺鏡，魚枯泣舊軒。", "曲湖春色滿，不到北堂萱。"]'),
('bfc7e69f-908a-4ce0-aa37-83cba6c62008','葉子山右史父宣義挽章二首  其一','呂祖謙','宋','宋诗','song-poetry','','[]','經笥深無底，高談一座傾。',48,'全唐诗/poet.song.157000.json','["經笥深無底，高談一座傾。", "置身初濩落，有子晚光榮。", "命服鄉閭賀，安輿里巷迎。", "風枝何不定，忽忽到佳城。"]'),
('1c8053a2-50b5-4ed6-9ec0-05fd07e676ec','葉子山右史父宣義挽章二首  其二','呂祖謙','宋','宋诗','song-poetry','','[]','諸父烏衣集，公時預往還。',48,'全唐诗/poet.song.157000.json','["諸父烏衣集，公時預往還。", "涼秋同出郭，勝日共尋山。", "電掣流年速，舟移古岸閒。", "又成丹旐去，衰涕不勝潸。"]'),
('f7ca38c0-3c97-4785-932e-68a4193f41d8','寄章冠之','呂祖謙','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','章侯平生一詩囊，酬風酢月徧四方。',184,'全唐诗/poet.song.157000.json','["章侯平生一詩囊，酬風酢月徧四方。", "浩歌姑熟酒淋浪，醉呼太白同舉觴。", "遂登浮玉臨渺茫，江濤挾筆益怒張。", "沙頭倚檣樂未央，興闌忽上秋浦航。", "門前槐花日夜黄，閉門琢詩聲繞梁。", "白袍紛紛渠自忙，飄然邂逅非所望。", "自言久厭世鎖韁，合眼已夢廬山蒼。", "君才甚碩氣方剛，身雖欲隠文則彰。", "江湖故人半朝行，左推右挽摩天翔。", "而我戢翼甘摧藏，不能與俗相迎將，徑當行前掃山房。", "俟君功成還故鄉，却駕柴車迎路傍。"]'),
('e2515814-48ed-42c9-911f-a73c96de40d6','送柳嚴州解官趨朝','呂祖謙','宋','宋诗','song-poetry','','[]','一葉初秋已趣裝，璽書屢下駐歸艎。',64,'全唐诗/poet.song.157000.json','["一葉初秋已趣裝，璽書屢下駐歸艎。", "少留北闕三年最，多借西州半歲强。", "身外寵榮元自薄，眼前凋瘵故難忘。", "書囊知有朝天草，不是中和樂職章。"]'),
('d34b21d9-358d-49dc-bbc4-2b185847bcdc','送宋子華通判長沙','呂祖謙','宋','宋诗','song-poetry','','[]','騷人故悲秋，九辨播三楚。',168,'全唐诗/poet.song.157000.json','["騷人故悲秋，九辨播三楚。", "宋公舊題壁，文采照潭府。", "千載得君侯，遥遥接華緒。", "還當初秋天，又進湖湘艣。", "當家多勝事，此役可兼取。", "江山日日新，似若相勞苦。", "木脫獻群峰，雲生失前浦。", "况持別乘權，光華動徒旅。", "元戎下分庭，百吏羣趨廡。", "後車載仁風，習習被南土。", "預知潢池盜，無復驚桴皷。", "政當勸賣劍，不必禁挾弩。", "嶺頭鏡面平，論賞駢圭組。", "臨分一盃酒，不爲離愁舉。"]'),
('72e30d59-5188-4642-8dad-e4a0011f8428','東陽郭彥明挽章','呂祖謙','宋','宋诗','song-poetry','','[]','小試威名蓋一鄉，卷藏韜畧付農桑。',64,'全唐诗/poet.song.157000.json','["小試威名蓋一鄉，卷藏韜畧付農桑。", "傳家籤軸書盈幄，擇壻簪纓笏滿牀。", "置邑萬家開兆域，送車千兩塞康莊。", "正須今代如椽筆，盡發潜光著石章。"]'),
('1748c286-e42f-45a8-a27f-66555a94a6ea','李粹伯侍御母夫人挽章','呂祖謙','宋','宋诗','song-poetry','','[]','對仗峩冠日，鯨牙洶九淵。',48,'全唐诗/poet.song.157000.json','["對仗峩冠日，鯨牙洶九淵。", "堂萱不改色，臺柏故參天。", "共識吾君聖，今知此母賢。", "丁寧劉子□，□事一時編。"]'),
('f8561283-34da-4b34-ae16-6cab37e58dcf','王龜齡詹事挽章二首  其一','呂祖謙','宋','宋诗','song-poetry','','[]','諸老收聲盡，佳城又到公。',48,'全唐诗/poet.song.157000.json','["諸老收聲盡，佳城又到公。", "蒼天那可問，吾道竟成窮。", "旌卷莆田雨，簫橫霅浦風。", "今年襟上淚，三哭萬夫雄。"]'),
('d207ad4d-2b5c-40fa-a98c-365043e42028','王龜齡詹事挽章二首  其二','呂祖謙','宋','宋诗','song-poetry','','[]','大使交旃日，元戎解甲秋。',48,'全唐诗/poet.song.157000.json','["大使交旃日，元戎解甲秋。", "先鳴驚衆寐，孤憤壓羣咻。", "羽翼新鴻鵠，聲華舊斗牛。", "斷橋亡恙否，落月照寒流。"]'),
('10e59c14-9e07-46a4-8aa2-8150e6c06e03','尚書汪公得請奉祠餞者十有四人分韵賦詩某得敢字','呂祖謙','宋','宋诗','song-poetry','','[]','鼎食味苦濃，藿食味苦淡。',192,'全唐诗/poet.song.157000.json','["鼎食味苦濃，藿食味苦淡。", "同生不同嗜，羊棗與昌歜。", "孰能游其間，進退兩無憾。", "尚書古仙伯，雅尚本真澹。", "禁涂履星辰，講厦席氈毯。", "將升閒槐棘，忽去亂葭菼。", "太清奉虛皇，奎壁手可攬。", "舉以華其歸，光耀極鉛槧。", "向來功名人，勇進忘坎窞。", "聽誦歸來辭，掩耳謝不敢。", "寧知達士胸，萬牛眇難撼。", "清風滿後車，一洗世氛黕。", "祖帳將軍園，寒枝紅綴糝。", "公歸寧久闊，別意不成慘。", "金華訪舊學，和羹待醯醓。", "政恐牧笛清，終換街鼓紞。"]'),
('216619a6-a185-4a61-b73f-070aff86ec9b','送丘宗卿博士出守嘉禾以視民如傷爲韵  其一','呂祖謙','宋','宋诗','song-poetry','','[]','槜李國西門，道里去天咫。',48,'全唐诗/poet.song.157000.json','["槜李國西門，道里去天咫。", "訟庭人摩肩，客館舟銜尾。", "涼燠變須臾，怵聽復駭視。", "心平理自見，周道本如砥。"]'),
('2342529a-65c8-44ec-9449-15d38d28e6f3','送丘宗卿博士出守嘉禾以視民如傷爲韵  其二','呂祖謙','宋','宋诗','song-poetry','','[]','堂下萬休戚，堂上一笑嚬。',48,'全唐诗/poet.song.157000.json','["堂下萬休戚，堂上一笑嚬。", "是心苟不存，對面越與秦。", "豚魚尚可孚，况此能言民。", "君看津頭柳，葉葉皆相親。"]'),
('136fa088-7db2-4344-99b3-9afc91af1a1f','送丘宗卿博士出守嘉禾以視民如傷爲韵  其三','呂祖謙','宋','宋诗','song-poetry','','[]','奮髯疾抵几，解衣徐探雛。',48,'全唐诗/poet.song.157000.json','["奮髯疾抵几，解衣徐探雛。", "古來多快士，氣吞兩輪朱。", "簿書高沒人，迎筆風摧枯。", "自許豈不豪，歲晏終何如。"]'),
('41d053e5-5dee-4e53-a669-e28150566620','送丘宗卿博士出守嘉禾以視民如傷爲韵  其四','呂祖謙','宋','宋诗','song-poetry','','[]','折肱稱良醫，識病由身傷。',48,'全唐诗/poet.song.157000.json','["折肱稱良醫，識病由身傷。", "開府事如麻，豈盡昔所嘗。", "平生老農語，易置復難忘。", "麥黄要經雪，橘黄要經霜。"]'),
('5f4d9970-fe91-43ba-8fc0-3809926a14cd','魏元履國錄挽章二首  其一','呂祖謙','宋','宋诗','song-poetry','','[]','麻衣見天子，拜疏不知休。',48,'全唐诗/poet.song.157000.json','["麻衣見天子，拜疏不知休。", "落落山林氣，拳拳畎畝憂。", "極知千載遇，政用一身酬。", "繞舍閩溪水，朝宗日夜流。"]'),
('7e775548-c5b5-446f-94b3-ef5b17e9cfb4','魏元履國錄挽章二首  其二','呂祖謙','宋','宋诗','song-poetry','','[]','羣公祖疏傅，多士送陽城。',48,'全唐诗/poet.song.157000.json','["羣公祖疏傅，多士送陽城。", "短棹非前約，長亭及此行。", "深留移白日，共語只蒼生。", "會續山陽賦，鄰人笛未橫。"]'),
('0d4d4306-c4fd-40e5-a4b4-b16be95e8c5a','祭酒芮公既歿四年門人呂某始以十詩哭之  其一','呂祖謙','宋','宋诗','song-poetry','','[]','少年把筆便班揚，咳唾珠璣落四方。',32,'全唐诗/poet.song.157000.json','["少年把筆便班揚，咳唾珠璣落四方。", "歲晚寒窗渾忘却，瓦爐香細雨聲長。"]'),
('29e9557e-9aaa-4861-8bb7-07a26123abd4','祭酒芮公既歿四年門人呂某始以十詩哭之  其二','呂祖謙','宋','宋诗','song-poetry','','[]','際野塵埃撲面來，萬人蟻聚撥難開。',32,'全唐诗/poet.song.157000.json','["際野塵埃撲面來，萬人蟻聚撥難開。", "手中杓柄長多少，蟄盡饑腸十月雷。"]'),
('7fc0d090-2157-427f-8dba-947f411a971f','祭酒芮公既歿四年門人呂某始以十詩哭之  其三','呂祖謙','宋','宋诗','song-poetry','','[]','小醉初醒日半昏，森森赤棒遶籬門。',32,'全唐诗/poet.song.157000.json','["小醉初醒日半昏，森森赤棒遶籬門。", "慨然投袂無難色，不識從來獄吏尊。"]'),
('d57448aa-3064-40c0-b4f6-5c58ad419fdf','祭酒芮公既歿四年門人呂某始以十詩哭之  其四','呂祖謙','宋','宋诗','song-poetry','','[]','交廣歸來里巷迎，破囊又比去時輕。',32,'全唐诗/poet.song.157000.json','["交廣歸來里巷迎，破囊又比去時輕。", "何須更酌廉泉水，夫子胸中萬斛清。"]'),
('67438145-7daa-4f89-ad5a-6059ef7354ab','祭酒芮公既歿四年門人呂某始以十詩哭之  其五','呂祖謙','宋','宋诗','song-poetry','','[]','殿前拜疏閲羣公，獻替從違各異同。',32,'全唐诗/poet.song.157000.json','["殿前拜疏閲羣公，獻替從違各異同。", "陛楯諸郎自相語，白頭祭酒最由衷。"]'),
('2444519a-9266-4f97-a1d0-ff7d95ceea93','祭酒芮公既歿四年門人呂某始以十詩哭之  其六','呂祖謙','宋','宋诗','song-poetry','','[]','出祖津頭六館空，帽簷齊側掛帆風。',32,'全唐诗/poet.song.157000.json','["出祖津頭六館空，帽簷齊側掛帆風。", "吳興盛事人能數，直自胡公到芮公。"]'),
('fe92270c-4a79-4354-84a6-157f9ccf8831','祭酒芮公既歿四年門人呂某始以十詩哭之  其七','呂祖謙','宋','宋诗','song-poetry','','[]','聞人有善己伸眉，倒廩傾囷更不疑。',32,'全唐诗/poet.song.157000.json','["聞人有善己伸眉，倒廩傾囷更不疑。", "菶菶萋萋竟何許，卷阿空老鳳皇枝。"]'),
('cb4901d9-25e0-4962-865f-98bffa6ccfdc','祭酒芮公既歿四年門人呂某始以十詩哭之  其八','呂祖謙','宋','宋诗','song-poetry','','[]','胸懷北海與南溟，却要涓涓一勺清。',32,'全唐诗/poet.song.157000.json','["胸懷北海與南溟，却要涓涓一勺清。", "相對蹴然如重客，無人信道是門生。"]'),
('831971f5-ebe0-4aaa-9ce3-045e29e21532','祭酒芮公既歿四年門人呂某始以十詩哭之  其九','呂祖謙','宋','宋诗','song-poetry','','[]','璧水經年奉宴居，天和襲物自舒徐。',32,'全唐诗/poet.song.157000.json','["璧水經年奉宴居，天和襲物自舒徐。", "憑誰寄謝朱公掞，纔向春風坐月餘。"]'),
('ce191173-65e3-4454-811e-b4f937e5e4b7','祭酒芮公既歿四年門人呂某始以十詩哭之  其一○','呂祖謙','宋','宋诗','song-poetry','','[]','先生墓木綠成圍，弟子摧頹晝掩扉。',32,'全唐诗/poet.song.157000.json','["先生墓木綠成圍，弟子摧頹晝掩扉。", "大雪繁霜心已死，有時清夢尚摳衣。"]'),
('3edeb057-bb2f-4e27-a21a-d7e79a00a4c8','送朱叔賜赴閩中幕府二首  其一','呂祖謙','宋','宋诗','song-poetry','','[]','止戈堂上屐聲閒，飛蓋相追杳靄間。',32,'全唐诗/poet.song.157000.json','["止戈堂上屐聲閒，飛蓋相追杳靄間。", "君到定知難入眼，倚天灊霍是家山。"]'),
('4e8a6ce7-2b0c-4cf8-8a2e-566ef0bb4d38','送朱叔賜赴閩中幕府二首  其二','呂祖謙','宋','宋诗','song-poetry','','[]','路逢十客九衿青，半是同窗舊弟兄。',32,'全唐诗/poet.song.157000.json','["路逢十客九衿青，半是同窗舊弟兄。", "最憶市橋燈火靜，巷南巷北讀書聲。"]'),
('5184d581-d1f5-4da9-ae83-03fe1e56dff0','周堯夫主管挽章','呂祖謙','宋','宋诗','song-poetry','','[]','五柳傳觴地，風流魏晉前。',48,'全唐诗/poet.song.157000.json','["五柳傳觴地，風流魏晉前。", "曾探孝先笥，慣坐廣文氈。", "身世渾如夢，功名莫問天。", "從今風雪夜，不上剡溪船。"]'),
('92e32387-9439-4b55-af51-4e5f84ba1443','周表卿尚書挽章','呂祖謙','宋','宋诗','song-poetry','','[]','奏篇曾用牘三千，晚歲回翔日月邊。',64,'全唐诗/poet.song.157000.json','["奏篇曾用牘三千，晚歲回翔日月邊。", "眼看四朝諸老盡，身兼五福幾人全。", "清臺課歷遺書在，晝寢凝香舊政傳。", "竹馬館前寒月白，當時轍迹故依然。"]'),
('40f1d110-13c7-4538-81f3-7ccfcf8b7e3a','楊信伯郎中挽章二首  其一','呂祖謙','宋','宋诗','song-poetry','','[]','象魏三千法，瀛洲十八人。',48,'全唐诗/poet.song.157000.json','["象魏三千法，瀛洲十八人。", "南宮占列宿，少海近重輪。", "聞道清羸極，猶有職業親。", "榴皮餘屋壁，零落獨無神。"]'),
('1236f06c-ef31-4b9a-aff4-d37a0616fa46','楊信伯郎中挽章二首  其二','呂祖謙','宋','宋诗','song-poetry','','[]','並舍游從舊，同朝分義深。',48,'全唐诗/poet.song.157000.json','["並舍游從舊，同朝分義深。", "時時墜書札，得得到山林。", "北去先移棹，南來後盍簪。", "死生離合地，搔首一悲吟。"]'),
('84e40548-d9fd-4932-9ac7-d589c1264cbb','蔣世修祕書父朝奉挽章','呂祖謙','宋','宋诗','song-poetry','','[]','太一青藜子舍光，命書頻歲到高堂。',64,'全唐诗/poet.song.157000.json','["太一青藜子舍光，命書頻歲到高堂。", "深居物外風煙老，靜看人間日月忙。", "繞舍圖書千載韵，映階蘭玉四時芳。", "逝舟休歎東流水，餘慶源流衮衮長。"]'),
('8cf20883-bb06-49ce-ba8e-ad5a209eb2d5','蘇仁仲計議挽章二首  其一','呂祖謙','宋','宋诗','song-poetry','','[]','幽棲略具便休官，帝遣蒲輪喚不還。',64,'全唐诗/poet.song.157000.json','["幽棲略具便休官，帝遣蒲輪喚不還。", "大似文元居道院，又如退傅過香山。", "夢回帷幄青冥上，醉墮風波浩蕩間。", "向使胸中有榮辱，那能八十鬢毛班。"]'),
('3b4e5a16-a348-4e77-8398-05f1f2817120','蘇仁仲計議挽章二首  其二','呂祖謙','宋','宋诗','song-poetry','','[]','登門疇昔奉從容，婺越之間一水通。',64,'全唐诗/poet.song.157000.json','["登門疇昔奉從容，婺越之間一水通。", "今日江東無賀老，去年牀下拜龐公。", "舊來論議多遺落，新出傳聞或異同。", "已矣從誰判真贋，汗青連屋未施功。"]'),
('8212010a-a8f6-4c2a-a6f6-02d1ff34b230','向運使挽章','呂祖謙','宋','宋诗','song-poetry','','[]','戟衣翻戶映庭槐，使節州符未展才。',64,'全唐诗/poet.song.157000.json','["戟衣翻戶映庭槐，使節州符未展才。", "文獻定知丞相似，淵源還自洛陽來。", "異端惑世濃於酒，古學違時冷若灰。", "從此湖人識喪禮，凜然治命手親裁。"]'),
('08a81706-2f90-446b-8a74-1077a1e4554d','酬上饒徐季益學正','呂祖謙','宋','宋诗','song-poetry','','[]','吾家紫微翁，獨守固窮節。',216,'全唐诗/poet.song.157000.json','["吾家紫微翁，獨守固窮節。", "金鑾罷直歸，朝飯尚薇蕨。", "峩峩李杜壇，總角便高躡。", "暮年自誓齋，銘几深刻責。", "名章與俊語，掃去秋一葉。", "冷淡靜工夫，槁乾迂事業。", "有來媚學子，隨叩無不竭。", "辭受去就間，告戒意尤切。", "典刑自耆老，護持何敢闕。", "嗟予生苦晚，名在諸孫列。", "拊頭雖逮事，提耳未親接。", "徐侯南州秀，少也嘗鼓篋。", "示我百篇詩，照坐光玉雪。", "因之理前話，講繹霏談屑。", "兩都弟子員，家法嚴城堞。", "取善則未周，守舊猶有說。", "同門風雨散，孤學絲桐絕。", "懷哉五馬橋，寒逕尋遺屧。"]'),
('a1224f11-6c14-4846-ae89-c80e8cdd7ee2','何茂恭母王夫人挽章','呂祖謙','宋','宋诗','song-poetry','','[]','南朝人物盛諸何，壽母皤然樂事多。',64,'全唐诗/poet.song.157000.json','["南朝人物盛諸何，壽母皤然樂事多。", "堂下無憂萱弄色，天邊有信桂交柯。", "黄金籝滿經方重，白玉樓成恨未磨。", "空誦安仁舊時賦，版輿零落故山阿。"]'),
('07c7d629-0539-4f9a-a02b-56deeb7eac0f','夜宿浦城魚梁徐刪定子出示林謙之挽其父二詩時謙之方按刑廣東有懷次韵  其一','呂祖謙','宋','宋诗','song-poetry','','[]','五年不說空山雨，今夜魚梁著釣船。',32,'全唐诗/poet.song.157000.json','["五年不說空山雨，今夜魚梁著釣船。", "爲問故人今健否，桄榔葉暗瘴江邊。"]'),
('b97fd43e-f048-4fa8-a26b-fd6a3895aaf6','夜宿浦城魚梁徐刪定子出示林謙之挽其父二詩時謙之方按刑廣東有懷次韵  其二','呂祖謙','宋','宋诗','song-poetry','','[]','兩章宛轉復清哀，讀到魚梁首重迴。',32,'全唐诗/poet.song.157000.json','["兩章宛轉復清哀，讀到魚梁首重迴。", "便使短牋無姓字，也應知自艾軒來。"]'),
('f6558d7d-82a9-4e79-853d-41ecbc446667','題劉氏綠映亭二首  其一','呂祖謙','宋','宋诗','song-poetry','','[]','涼葉翻翻不受塵，芒鞋藤杖及清晨。',32,'全唐诗/poet.song.157000.json','["涼葉翻翻不受塵，芒鞋藤杖及清晨。", "開窗小放前溪入，澄綠光中獨岸巾。"]'),
('2543ba87-2431-4a7d-b105-494a560a3ad8','題劉氏綠映亭二首  其二','呂祖謙','宋','宋诗','song-poetry','','[]','鷺浴魚跳在鏡屏，摇青浮碧太鮮明。',32,'全唐诗/poet.song.157000.json','["鷺浴魚跳在鏡屏，摇青浮碧太鮮明。", "牆東種得陰成幄，隔葉看來却有情。"]'),
('88cdc6f7-b1dc-4b8c-a5d1-85aa7c9727f3','題歸菴','呂祖謙','宋','宋诗','song-poetry','','[]','雲壁開蒼峽，風林卷翠濤。',48,'全唐诗/poet.song.157000.json','["雲壁開蒼峽，風林卷翠濤。", "諸松皆老大，一嶂獨孤高。", "發興雖公等，尋幽許我曹。", "秋光端可賦，不是楚人騷。"]'),
('f6b7f333-a160-46c6-baf7-aa0c41f05f8a','王通直挽章','呂祖謙','宋','宋诗','song-poetry','','[]','近來南國冢，半是北人墳。',48,'全唐诗/poet.song.157000.json','["近來南國冢，半是北人墳。", "異縣誰憐我，同鄉又失君。", "深居傳雅尚，堅坐挹清芬。", "日落長安第，三槐拂暮雲。"]'),
('ea6205ab-6f82-47ba-afda-a300a6fe73e1','劉梧州挽章','呂祖謙','宋','宋诗','song-poetry','','[]','駟馬高車照路光，幡然改轍興何長。',64,'全唐诗/poet.song.157000.json','["駟馬高車照路光，幡然改轍興何長。", "空山猿鶴驚無恙，同社雞豚樂未央。", "祗見歲華來冉冉，不知耆舊去堂堂。", "北邙道上麒麟冢，誰得歸休十載强。"]'),
('7bcf55f8-7896-4753-a2ec-4589014fd837','許著作挽章','呂祖謙','宋','宋诗','song-poetry','','[]','清文麗藻百川增，窘步追隨愧不能。',64,'全唐诗/poet.song.157000.json','["清文麗藻百川增，窘步追隨愧不能。", "麟趾差肩臺岌岌，鴈飛聯翼塔層層。", "蓴鱸歸興都門酒，薤露悲歌大隧燈。", "獨向梁間誦遺句，寒松衰菊繞崚嶒。"]'),
('604c9eb8-6961-4e35-ba4c-710207351ea2','次韵葉丞相陳尚書游南園','呂祖謙','宋','宋诗','song-poetry','','[]','樂事良辰古所難，三分春色一分寬。',64,'全唐诗/poet.song.157000.json','["樂事良辰古所難，三分春色一分寬。", "潤花雨過紅裙濕，倚竹風斜翠袖寒。", "自有南堂誰舉白，可無東絹爲施丹。", "兩翁醉墨曾題品，便作平泉草木看。"]'),
('e840d399-1952-4987-a90b-a4546cfb5050','宣城李君嘗遊東湖居士之門袖詩見過次韵以謝','呂祖謙','宋','宋诗','song-poetry','','[]','人去湖空古豫章，溪蓀水荇換年芳。',64,'全唐诗/poet.song.157000.json','["人去湖空古豫章，溪蓀水荇換年芳。", "聞風我是通家舊，覓句君猶弟子行。", "鬚髮蒼浪休歎老，齒牙沆瀣尚生香。", "宛陵自昔詩人國，今日誰升小謝堂。"]'),
('032de539-2170-4fb6-8b4b-1063e1f99806','何叔京挽章二首  其一','呂祖謙','宋','宋诗','song-poetry','','[]','濮州以諫死，何氏得其真。',48,'全唐诗/poet.song.157000.json','["濮州以諫死，何氏得其真。", "天下中庸義，人間父子親。", "再傳猶易簡，小出復逡巡。", "埋骨雖南土，傾心向北辰。"]'),
('1bd6cfd8-0718-47b2-9622-cb6c8ad76be2','何叔京挽章二首  其二','呂祖謙','宋','宋诗','song-poetry','','[]','傾蓋黄亭夜，翛然澗壑姿。',48,'全唐诗/poet.song.157000.json','["傾蓋黄亭夜，翛然澗壑姿。", "倚天唯直榦，到地絕旁枝。", "亹亹今何許，悠悠只自知。", "寒碑卧風雨，千載有深期。"]'),
('be189eb3-71e7-4731-bbf1-09bd27a4e4f2','魯少卿挽章','呂祖謙','宋','宋诗','song-poetry','','["\u6ed5\u738b\u9601"]','慶源衮衮接天流，老桂傳香次第秋。',64,'全唐诗/poet.song.157000.json','["慶源衮衮接天流，老桂傳香次第秋。", "人物西都九卿選，光華南國十州遊。", "翛然徑下滕王閣，已矣長懷范蠡舟。", "身後楚騷誰著錄，靈光舊草合兼收。"]'),
('c5af9e4d-a0a7-4c03-8b8a-edfe2d5d4925','蕭果卿祭酒挽章二首  其一','呂祖謙','宋','宋诗','song-poetry','','[]','虛心觀世態，實行播鄉評。',48,'全唐诗/poet.song.157000.json','["虛心觀世態，實行播鄉評。", "璧玉中邊厚，冰壺表裏清。", "家聲到蕭傅，人望似陽城。", "殄瘁無窮恨，湘江日夜傾。"]'),
('823ccd7a-af6c-4971-a066-c622e68123c2','蕭果卿祭酒挽章二首  其二','呂祖謙','宋','宋诗','song-poetry','','[]','摩揣誠斯薄，雕鎸質自銷。',48,'全唐诗/poet.song.157000.json','["摩揣誠斯薄，雕鎸質自銷。", "平生但真樸，直上絕枝條。", "氛霧終澄霽，丘山亦動摇。", "朝陽舊時鳳，聲人舜簫韶。"]'),
('4c4cc372-b36f-417e-a929-68e4d25a26cd','送喻叔奇通判會稽','呂祖謙','宋','宋诗','song-poetry','','[]','鳴騶前日餞出使，椎鼓今日送作州。',96,'全唐诗/poet.song.157000.json','["鳴騶前日餞出使，椎鼓今日送作州。", "會稽別駕官尚薄，道傍羨者何其稠。", "版輿有親餘九十，東南之美供甘柔。", "先春鑄牙入午啜，破臘箭茁充晨羞。", "况復詩壇執牛耳，所至風月相獻酬。", "千巖萬壑徧題品，會有采者人名遒。"]'),
('983ecfff-7ac0-4b7f-9db6-d4b08e2b3263','與同館遊張氏園分韵得日字','呂祖謙','宋','宋诗','song-poetry','','[]','出門厭囂塵，入門倦佔畢。',108,'全唐诗/poet.song.157000.json','["出門厭囂塵，入門倦佔畢。", "駕言城北園，滯思頓覺失。", "方池環修篁，廣陌衛行栗。", "先雪梅已苞，後霜草猶茁。", "上躋極高明，旁穿復深密。", "主人真喜事，秀句屢盈帙。", "招呼文字飲，及此三餘日。", "山林與鐘鼎，零茂本非匹。", "斯遊豈偶然，書板記甲乙。"]'),
('39119825-b859-4d83-9a7b-a7cb6cc3566d','送胡子遠著作知漢州分韵得行字','呂祖謙','宋','宋诗','song-poetry','','[]','定交不在蚤，意合蓋已傾。',204,'全唐诗/poet.song.157000.json','["定交不在蚤，意合蓋已傾。", "胡侯西南來，兩載同書檠。", "與人徐有味，於世初無營。", "虛舟澹容與，未易寵辱驚。", "魚龍同一波，中有千丈清。", "道氣自深穩，名言常簡明。", "南宮接東觀，天衢勢方亨。", "夢回得遠信，窺簷渚鴻鳴。", "開書見連環，歸興浩已盈。", "子政方校錄，令伯俄陳情。", "都門日轂擊，雜襲炎凉并。", "誰知此麾蓋，獨爲思親行。", "夾道皆歎息，始識真重輕。", "古來聚散地，雪野天崢嶸。", "別袖不可挽，宿昔洲渚生。", "君臣有大義，忠孝相持衡。", "勉哉楙明德，清廟須棟甍。"]'),
('f0579399-d1a0-4ee0-8e7e-6116565d4350','薛叔雲左史母方夫人挽章二首  其一','呂祖謙','宋','宋诗','song-poetry','','[]','彤管傳遺範，形容欲付誰。',48,'全唐诗/poet.song.157000.json','["彤管傳遺範，形容欲付誰。", "初年柏舟賦，晚歲艾軒詩。", "□□□□□，□金□赤墀。", "莆中稱壽母，不獨蔡三司。"]'),
('c11a6157-3c66-4530-968c-97bb9555578a','薛叔雲左史母方夫人挽章二首  其二','呂祖謙','宋','宋诗','song-poetry','','[]','往在西雍日，從容許拜親。',48,'全唐诗/poet.song.157000.json','["往在西雍日，從容許拜親。", "杏花壇壝古，萱草戶庭春。", "曾是升堂客，應爲執紼人。", "壺公天一角，吹淚灑車塵。"]'),
('68da3d60-fb0b-4878-a810-ee34347e8280','端明汪公挽章二首  其一','呂祖謙','宋','宋诗','song-poetry','','[]','異時憂世士，太息恨才難。',48,'全唐诗/poet.song.157000.json','["異時憂世士，太息恨才難。", "每見公身健，猶令我意寬。", "彫零竟何極，回復豈無端。", "此理終難解，天風大隧寒。"]'),
('e3043eb7-66ed-408f-a2f3-cd21947d4227','端明汪公挽章二首  其二','呂祖謙','宋','宋诗','song-poetry','','[]','四海膺門峻，親承二紀中。',48,'全唐诗/poet.song.157000.json','["四海膺門峻，親承二紀中。", "論交從父祖，受教自兒童。", "山嶽千尋上，江河萬折東。", "微言藏肺腑，欲吐與誰同。"]'),
('ad8af69c-d2a8-4cf7-91c4-cc27b001ec4d','趙路分挽章二首  其一','呂祖謙','宋','宋诗','song-poetry','','[]','魯衛封雖近，原顔室自貧。',48,'全唐诗/poet.song.157000.json','["魯衛封雖近，原顔室自貧。", "一家唯四壁，九族自三春。", "子舍龍頭貴，佳城馬鬣新。", "升堂如昨日，南望涕沾巾。"]'),
('40c574a9-f546-4423-9e53-10a8c0b9f8b6','趙路分挽章二首  其二','呂祖謙','宋','宋诗','song-poetry','','[]','晨昏生死際，至性極民彝。',48,'全唐诗/poet.song.157000.json','["晨昏生死際，至性極民彝。", "巨孝東都傳，劬勞小雅詩。", "固應爲世表，何止秀天枝。", "令子傳遺緒，纍然不自持。"]'),
('a8888f5c-ec4f-4660-908c-799cb9c122bf','陳能之少卿挽章二首  其一','呂祖謙','宋','宋诗','song-poetry','','[]','往在西臺日，調娛用力艱。',48,'全唐诗/poet.song.157000.json','["往在西臺日，調娛用力艱。", "善人終有恃，公道亦徐還。", "既去言方白，重來鬢已班。", "清名配詹事，千載赤城山。"]'),
('74195140-2140-466e-9df8-355f8dff3c6b','陳能之少卿挽章二首  其二','呂祖謙','宋','宋诗','song-poetry','','[]','二父官曹接，諸郎硯席通。',48,'全唐诗/poet.song.157000.json','["二父官曹接，諸郎硯席通。", "流年何鼎鼎，見日每匆匆。", "馬走誰憐我，麟書近得公。", "又成交臂失，楚些鐸聲中。"]'),
('fa859d62-1ba6-4b15-87a7-dbc7d13d7fde','恭和御製秋日幸祕書省近體詩','呂祖謙','宋','宋诗','song-poetry','','[]','麟閣龍旂日月章，中興再見赭袍光。',64,'全唐诗/poet.song.157000.json','["麟閣龍旂日月章，中興再見赭袍光。", "仰觀焜燿人文盛，始識扶持德意長。", "功利從今卑管晏，浮華自昔陋盧王。", "願將實學酬天造，敢效明河織女襄。"]'),
('47f97fd1-e1df-4416-9a67-276b87f2bbe0','賀車駕幸祕書省二首  其一','呂祖謙','宋','宋诗','song-poetry','','[]','麟臺高柳識雕輿，共記中興幸省初。',64,'全唐诗/poet.song.157000.json','["麟臺高柳識雕輿，共記中興幸省初。", "黄道再傳天子蹕，青編重入史臣書。", "需雲下際君恩盛，晨露高張樂節舒。", "若寫鴻猷參大雅，定非周鼓頌田漁。"]'),
('e5c6b29a-b1c5-48c2-96b9-50c791402da4','賀車駕幸祕書省二首  其二','呂祖謙','宋','宋诗','song-poetry','','[]','紫清丹極與天鄰，闔闢乾坤繫笑嚬。',64,'全唐诗/poet.song.157000.json','["紫清丹極與天鄰，闔闢乾坤繫笑嚬。", "獨爲斯文回一顧，坐令吾道重千鈞。", "先王舊物參差見，列聖明謨次第陳。", "墨客區區感榮遇，豈知深意在彝倫。"]'),
('aabb1db8-13aa-46a2-9afe-b416a452f4da','題真覺僧房蘆','呂祖謙','宋','宋诗','song-poetry','','[]','何人夜折苕溪雪，吹落山堂寄清絕。',128,'全唐诗/poet.song.157000.json','["何人夜折苕溪雪，吹落山堂寄清絕。", "夢回軒檻非人間，一岸扶疎碎殘月。", "秋風索索秋意晚，葉外參差明疊巘。", "頗似江南短棹歸，平沙鴈落汀洲遠。", "蒼濤遶窗碧玉寒，中有漁父千古閑。", "知君胸次五湖闊，波聲髣髴游杏壇。", "少林之孫韵枮木，避世避人何用逐。", "渭川謾復千畝多，江上由來一葦足。"]'),
('27182d0c-2e5c-4540-b55d-d0c775c2589d','再賦真覺僧房蘆三首  其一','呂祖謙','宋','宋诗','song-poetry','','[]','湖山近減江湖趣，寂歷頹垣仲蔚蒿。',32,'全唐诗/poet.song.157000.json','["湖山近減江湖趣，寂歷頹垣仲蔚蒿。", "縱有秋風何處著，遶籬無葉起蒼濤。"]'),
('6c834273-6892-40bc-ba97-77c05650c5d6','再賦真覺僧房蘆三首  其二','呂祖謙','宋','宋诗','song-poetry','','[]','屋角清渠瀨淺沙，風斜雨重倒蒼葭。',32,'全唐诗/poet.song.157000.json','["屋角清渠瀨淺沙，風斜雨重倒蒼葭。", "沙鷗不下投前浦，塞雁重來失舊花。"]'),
('73a6cd3b-5d6e-44be-9c6b-92dd13fb54a2','再賦真覺僧房蘆三首  其三','呂祖謙','宋','宋诗','song-poetry','','[]','清曉霜鍾喚客興，餘聲知度幾稜層。',32,'全唐诗/poet.song.157000.json','["清曉霜鍾喚客興，餘聲知度幾稜層。", "烟霞深處無人到，時見憑欄一兩僧。"]'),
('4aceed65-4a28-4b07-b0ef-38d56d1f0ccc','漢銅弩機歌','呂祖謙','宋','宋诗','song-poetry','','[]','甘泉宮中烽火催，武庫掣鏁殷春雷。',224,'全唐诗/poet.song.157000.json','["甘泉宮中烽火催，武庫掣鏁殷春雷。", "山西都尉部千弩，意氣欲壓天山摧。", "朔風慘慘隨旗尾，角聲滿天日色死。", "眼吞單于方發機，南風不競羽倒飛。", "血視空弮尚思戰，邊庭無竹可續箭。", "斷絃已作塞上塵，零落銅牙時一見。", "土花蝕盡繆篆青，千年遺恨今未平。", "雕鞍過盡不回首，落身几案依書檠。", "蘚苔暗淡生古色，中有少卿千斛力。", "從漢至今無大黄，婦翫兒嬉固其職。", "長平箭頭豪士憐，赤壁折戟傳青篇。", "古來慷慨共如此，脫畧形器求天全。", "是機雖缺神凜然，想成風沙射鵰天。", "徑欲匹馬南山邊，何必一臂三十絭。"]'),
('2deb8439-12aa-4ea9-ab9d-ca4bf221f858','晚步溪上','呂祖謙','宋','宋诗','song-poetry','','[]','疎疎屐齒印平堤，露著烏紗客未知。',64,'全唐诗/poet.song.157000.json','["疎疎屐齒印平堤，露著烏紗客未知。", "別浦歸舟爭占岸，橫林宿鳥自分枝。", "開張漁父胸中趣，漏泄騷人句外悲。", "會與清溪約長夏，風簾水簟答漣漪。"]'),
('8799750f-f0b8-4955-9e1f-a0f413a86019','秋日','呂祖謙','宋','宋诗','song-poetry','','[]','堂下梧桐樹，清陰欲滿簾。',48,'全唐诗/poet.song.157000.json','["堂下梧桐樹，清陰欲滿簾。", "風前數葉落，枝外幾山添。", "世故真難犯，幽棲不用占。", "新凉入書幌，好在鄴侯籤。"]'),
('f6099bbb-ac3b-4619-94af-54359e8e3691','夏夜','呂祖謙','宋','宋诗','song-poetry','','[]','晚市收聲盡，虛堂一味凉。',48,'全唐诗/poet.song.157000.json','["晚市收聲盡，虛堂一味凉。", "炎蒸渠酷吏，閒靜我羲皇。", "露沐疎螢濕，風梳細草長。", "典移無定在，隨月轉胡床。"]'),
('f3949725-7642-42f1-acb3-3d1bdc05add8','應春坊輓章','呂祖謙','宋','宋诗','song-poetry','','[]','鉛槧青燈夜，韜鈐紫塞秋。',48,'全唐诗/poet.song.157000.json','["鉛槧青燈夜，韜鈐紫塞秋。", "請纓雖拜疏，投筆未封侯。", "幃白風煙慘，旗丹霧雨愁。", "從來桑梓接，助輓不成謳。"]'),
('fb31bd5a-294f-4d3d-ab9a-e649eba57cb2','和虞仲逸初夏懷黄巖村居','呂祖謙','宋','宋诗','song-poetry','','[]','幾曲江村雨外明，釣磯漁屋入新晴。',64,'全唐诗/poet.song.157000.json','["幾曲江村雨外明，釣磯漁屋入新晴。", "參天喬木淺深綠，蓋水圓荷先後生。", "歸夢每煩春鳥喚，故林可忍曉猿驚。", "功成共祖東門道，不負溪山舊主盟。"]'),
('f0205610-f81d-4e65-9722-62cf61586495','次前韵答石秀才','呂祖謙','宋','宋诗','song-poetry','','[]','幽軒返照可窗明，政用高談答晚晴。',64,'全唐诗/poet.song.157000.json','["幽軒返照可窗明，政用高談答晚晴。", "共聽銅瓶秋雨急，不知石鼎曉雲生。", "清詩未讀心先醉，別日無多夢已驚。", "聞道烏衣盛文史，祇愁異姓後宗盟。"]'),
('242b574b-9602-4f13-a0f7-56a60d238667','效進士作三年通一經','呂祖謙','宋','宋诗','song-poetry','','[]','歲月去如矢，橫經徒慨然。',72,'全唐诗/poet.song.157000.json','["歲月去如矢，橫經徒慨然。", "誰能通一藝，真不負三年。", "用意窺園外，收功刻楮邊。", "幽光回蠹簡，新意出陳編。", "上相黄金重，諸儒白首鮮。", "同聲不同調，嘆息伯牙絃。"]'),
('69e67d30-292d-4a23-9a14-c06f172ebc29','過九江贈同舍陳伯秀','呂祖謙','宋','宋诗','song-poetry','','[]','異時夫子門，論交心獨可。',180,'全唐诗/poet.song.157000.json','["異時夫子門，論交心獨可。", "晨窗並几案，莫檠共燈火。", "同升大宗伯，道阻山砐硪。", "淡墨濕棲鴉，天開棘闈鎖。", "高張三百丈，徧數不及我。", "咫尺判飛沈，鵬摶笑鳶墮。", "音塵兩疎闊，歲月悉箭笴。", "風吹樊口帆，雨繫潯陽柁。", "故人尚一尉，旌旗穿紫邏。", "相逢話舊游，撥置朱墨夥。", "握手忘寒溫，屈指半轗軻。", "官居岸平湖，波濤日舂簸。", "飽看五老面，此計殊未左。", "山房舊聞名，欲往輒不果。", "須君發其藏，萬卷書繞坐。"]'),
('2119d018-a5c7-4e27-93f7-e60482058070','睢陽五老圖贊','呂祖謙','宋','宋诗','song-poetry','','[]','同支派別胄遥遥，南渡衣冠尚北朝。',64,'全唐诗/poet.song.157000.json','["同支派別胄遥遥，南渡衣冠尚北朝。", "千載畫圖文獻在，兩朝開濟政明昭。", "公卿倡和遵皇運，嗣子傳家念祖饒。", "幸得慶源流自遠，匡扶人世釋塵囂。"]'),
('464d3dbf-36fe-496b-855a-ba44b9b33eef','方齋行','呂祖謙','宋','宋诗','song-poetry','','[]','世皆尚圓君獨方，富貴可取君不忙。',96,'全唐诗/poet.song.157000.json','["世皆尚圓君獨方，富貴可取君不忙。", "閉門讀書聲琅琅，舊書重疊堆在牀。", "點勘同異分邊旁，運精竭思心力彊。", "十年足不離僧房，荒山野路秋水長。", "客雖欲至嫌路妨，幽蘭無人爲君芳。", "采菊落英充餱糧，客即不來有餘香。"]'),
('73fe6245-c7eb-4e28-8979-62652dc67231','遊上天竺','呂祖謙','宋','宋诗','song-poetry','','[]','浄域何虛寂，居然隔市喧。',48,'全唐诗/poet.song.157000.json','["浄域何虛寂，居然隔市喧。", "僧來混不語，吾亦欲忘言。", "至樂存簞食，浮名類觸藩。", "行行返初服，賁趾老邱樊。"]'),
('2ab31c27-79cd-4537-abfc-e390641410e3','夜坐觀書','廖行之','宋','宋诗','song-poetry','','[]','風露氣凄清，秋堂燈火夕。',72,'全唐诗/poet.song.157000.json','["風露氣凄清，秋堂燈火夕。", "開編對聖賢，窮理貫今昔。", "豈無侯門裾，俛仰無顔色。", "豈無終南路，矯詐虧名實。", "萃耕渭釣人，樂道貴自得。", "青紫與金珠，從渠儻來物。"]'),
('b54fb7f0-6271-4662-9994-e325eba54792','重九後菊未開','廖行之','宋','宋诗','song-poetry','','[]','靈根何許來，初春首移植。',132,'全唐诗/poet.song.157000.json','["靈根何許來，初春首移植。", "封培極膏壤，灌溉勤朝夕。", "惟知人力勝，可與天工敵。", "侵尋度重九，荏苒復旬日。", "含芳似慳吝，細蓓猶的歷。", "得非司花神，不爲狥世習。", "閉關存清高，後時養介僻。", "不然蓐妝靈，護持莫庸釋。", "未容遽爛熳，留作秋歸憶。", "胡爲倚牆隈，向人殊寂寞。", "雖非彭澤長，汝勿余於惜。"]'),
('2501b120-3718-45a2-accd-0c8ea7445d2e','贈別羅舜舉','廖行之','宋','宋诗','song-poetry','','[]','憶昔相從游，往往嘗繼晷。',192,'全唐诗/poet.song.157000.json','["憶昔相從游，往往嘗繼晷。", "論文在肺肝，商確到肌體。", "一從悵分携，鳧鴈慣居徙。", "相望兩川間，別夢縈百里。", "向來故園思，歸興動行李。", "奔馳快一見，舍館渠暇理。", "疇昔夜過門，明月耿相視。", "一尊邀躊躇，嘯詠天風起。", "朝來得秀句，惜別語盈紙。", "所愧才空疎，雅意孰稱是。", "塵勞喜驅人，遣我輪善柅。", "明當問歸途，馬足莫西指。", "男兒結交情，聚散今乃爾。", "誰論十日惡，懷抱好無幾。", "活活郴江流，此去下湘水。", "慇懃儻懸情，願言寄雙鯉。"]'),
('3f148078-1b9b-49bb-a1e9-1dbf1232f1d6','寄舅氏','廖行之','宋','宋诗','song-poetry','','[]','北山結齋處，爽塏非囂塵。',96,'全唐诗/poet.song.157000.json','["北山結齋處，爽塏非囂塵。", "開軒尋丈間，四座情誾誾。", "君無挾長態，我亦忘等倫。", "終朝究道藝，得趣何其真。", "一從分携去，聲跡如參辰。", "相望遠十舍，誨席無由親。", "秋高鼇峰秀，得助尤清新。", "明珠不分錫，何以慰吾貧。"]'),
('8a60c0e5-5bf9-4022-9fa8-73fed93d0ee0','和劉寺簿韵就述丐祠意','廖行之','宋','宋诗','song-poetry','','[]','衡湘風物佳，微産亦豐美。',144,'全唐诗/poet.song.157000.json','["衡湘風物佳，微産亦豐美。", "清腴足秔稻，雋永到梨柿。", "一飽自有餘，此樂渠有涘。", "况逢使君賢，公餘多燕喜。", "新詩且間作，健筆時一泚。", "形骸了區別，肝膽洞遐邇。", "言論斯靄如，旨意不忘起。", "梧檟良栽培，稂莠早耘耔。", "我愚莫孰何，流輩敢倫儗。", "每聞循循誘，敢愧空空鄙。", "高堂有白髮，富貴寧羨彼。", "丐公成此心，萬事歡菽水。"]'),
('2c6cc2a0-d6a2-4c08-a6ce-fee5cda02ca5','從三舅氏携兒姪遊向園分韵得買字','廖行之','宋','宋诗','song-poetry','','[]','廛居遠囂塵，市隠渺湖海。',252,'全唐诗/poet.song.157000.json','["廛居遠囂塵，市隠渺湖海。", "閑窗理書卷，樂事供戲綵。", "蕭然萬慮忘，恬爾四時改。", "青山滿郊園，未省費錢買。", "客來笑迂拙，我乃厭機械。", "今朝起遨遊，歡意與天會。", "光風挾霽月，璇宇掃氛靄。", "茲游發吾舅，慫恿及流輩。", "扁舟凌湘波，步屧更東邁。", "名園展良覿，珍賞皆勝槩。", "松筠矗高節，花草足芳佩。", "化工自無私，物理欣有待。", "從渠春爛熳，壯我胸磊磈。", "招邀坐莓苔，取次列鮭菜。", "真成脫邊幅，底用見奇怪。", "酒闌發深省，事往憶初載。", "經營賦歸田，想像古賢宰。", "騎箕久汗漫，種木今猥大。", "安能耽燕翫，頗復念興廢。", "信美非吾廬，高興忽天外。", "歸來且長哦，它時續詩話。"]'),
('164113dc-ec71-46a2-be45-3df165944f4a','自中都歸題勝業寺古柏','廖行之','宋','宋诗','song-poetry','','[]','昔聞南山下，有柏古且奇。',168,'全唐诗/poet.song.157000.json','["昔聞南山下，有柏古且奇。", "書癡守寒窗，一見嗟無期。", "歸從軟紅塵，乃識蒼虬姿。", "青青十畝蔭，凜凜千年枝。", "山靈日守護，斧斤誰侵欺。", "孤根久盤踞，珍幹分逶迤。", "飄蕭爽氣生，蓊蔚祥雲低。", "九龍出同穴，宛轉猶相持。", "高標足古意，貞操長遐栖。", "豈無金芝秀，瑣瑣誇一時。", "豈無豫章靈，屑屑關興衰。", "何如此嘉樹，毀譽無欣悲。", "傳聞禹所植，往事誰能稽。", "安得子墨卿，寫作無聲詩。"]'),
('cea713b6-f1c1-43a8-a910-5ef48186de4c','醉中紀事題辰州浄因寺','廖行之','宋','宋诗','song-poetry','','[]','山城春半時，底事風作惡。',156,'全唐诗/poet.song.157000.json','["山城春半時，底事風作惡。", "小隠杜書帷，暗想花蕭索。", "命駕訪林藪，尋芳到叢薄。", "漫山粲百英，隨分有餘樂。", "縈迴度城陰，徙倚步禪閣。", "山僧正齋餘，茗椀快新瀹。", "壁間有佳句，一誦喜且愕。", "登堂陳盃盤，痛飲自諧謔。", "新詩恣賡酬，郢匠成妙斲。", "忘機物不疑，屋山下烏啄。", "松風動豪氣，號怒響林壑。", "顧我亦楚狂，高興復誰托。", "揮毫屬同遊，聊共題新堊。"]'),
('5ef2189d-8dcc-4aad-96c8-cc742135bab8','代遊西湖分韵得香字','廖行之','宋','宋诗','song-poetry','','["\u897f\u6e56"]','永嘉有儒宗，學古源流長。',192,'全唐诗/poet.song.157000.json','["永嘉有儒宗，學古源流長。", "未施經國手，姑綰祠嶽章。", "豈惟禮秩重，正遣文教昌。", "從遊者誰子，秀異推荆楊。", "潛君春秋學，三傳可束藏。", "君章湘中傑，况有今黄香。", "羣賢集董帷，幸甚同翺翔。", "吾邦一何遇，石鼓分餘光。", "坐令士氣振，聞者皆激昂。", "今朝過封胡，三英璨琳琅。", "乘興訪蕭寺，草草羅酒漿。", "吾儕亦縱臾，十駕隨飛黄。", "亢宗頼季子，未數彥道狂。", "讀禮不敢過，養晦須名揚。", "旁觀且袖手，代斲愧不臧。", "聊補分韵篇，一笑薰風凉。"]'),
('5d75651f-3c51-4365-b958-ace62efd7814','送岳陽陳倅秩滿還朝八首  其一','廖行之','宋','宋诗','song-poetry','','[]','千古太丘長，風流世淳龐。',48,'全唐诗/poet.song.157000.json','["千古太丘長，風流世淳龐。", "衮衮多公卿，他姓渠可雙。", "祇今廩賢雋，半刺均麾幢。", "朝天建長策，致主新周邦。"]'),
('6430014c-836c-4216-88c0-413ac97f5d02','送岳陽陳倅秩滿還朝八首  其二','廖行之','宋','宋诗','song-poetry','','[]','閩爲多士鄉，三山最英特。',48,'全唐诗/poet.song.157000.json','["閩爲多士鄉，三山最英特。", "問學可經世，文章更華國。", "公維太宰出，宅相有令德。", "無忌獨何人，猶能弭凶慝。"]'),
('795663b1-58d8-4be4-9797-c154ad6993ab','送岳陽陳倅秩滿還朝八首  其三','廖行之','宋','宋诗','song-poetry','','[]','先漢郡有丞，選置不浪取。',48,'全唐诗/poet.song.157000.json','["先漢郡有丞，選置不浪取。", "次公在河南，吏嚴而獨不。", "皇家重監郡，小試煩大手。", "上方求寬和，淹外詎容久。"]'),
('dfbc6eeb-19c6-4f6b-a8b8-afdb3ab57559','送岳陽陳倅秩滿還朝八首  其四','廖行之','宋','宋诗','song-poetry','','[]','岳陽古建郡，不但樓觀雄。',48,'全唐诗/poet.song.157000.json','["岳陽古建郡，不但樓觀雄。", "英英范公記，百世揚清風。", "斯文行益遠，雅意言非空。", "懷哉久登臨，所期憂樂同。"]'),
('de11a3eb-5f90-4f97-ba6a-e670383d7c64','送岳陽陳倅秩滿還朝八首  其五','廖行之','宋','宋诗','song-poetry','','[]','重湖昔苦兵，流亡動輕別。',48,'全唐诗/poet.song.157000.json','["重湖昔苦兵，流亡動輕別。", "幾年費勞來，經旱復騷屑。", "有底田多稼，民情洽歡悅。", "洋洋康頼歌，今無愧前哲。"]'),
('b02901d0-6e98-4b0e-a46d-0f6966d8b3a8','送岳陽陳倅秩滿還朝八首  其六','廖行之','宋','宋诗','song-poetry','','[]','湖山政俗殊，疆理罕憑藉。',48,'全唐诗/poet.song.157000.json','["湖山政俗殊，疆理罕憑藉。", "壤賦無定書，民田互欺詐。", "所急井田均，爭心詎難化。", "入告今其時，公行毋俟駕。"]'),
('7fa6a49d-6c90-498b-b6de-1c765b7d7321','送岳陽陳倅秩滿還朝八首  其七','廖行之','宋','宋诗','song-poetry','','[]','舍人趣治裝，驅車將東之。',48,'全唐诗/poet.song.157000.json','["舍人趣治裝，驅車將東之。", "兩載賢轍淹，一朝萬里馳。", "洪惟德器遠，自是廊廟姿。", "寧須佩刀祝，已動宣室思。"]'),
('74702cf5-4294-46fb-87cf-c087aa26836a','送岳陽陳倅秩滿還朝八首  其八','廖行之','宋','宋诗','song-poetry','','[]','少陵不作威，恐墮趨走中。',48,'全唐诗/poet.song.157000.json','["少陵不作威，恐墮趨走中。", "而今巴丘吏，所遭更途窮。", "力緜何以振，敢意鄠縣功。", "慨歎薛長史，誰其繼高風。"]'),
('2d69cbce-6e92-4a24-8586-b9e483866804','壽湖南宗憲五首  其一','廖行之','宋','宋诗','song-poetry','','[]','梅餘傲雪香，柳欲摇金絲。',48,'全唐诗/poet.song.157000.json','["梅餘傲雪香，柳欲摇金絲。", "隆冬如許清，真宰渠物私。", "居然風景殊，鍾此賢傑姿。", "政須鴻鈞播，天意扶民彜。"]'),
('902c837e-c3b8-4be3-bd9f-b80ac803af43','壽湖南宗憲五首  其二','廖行之','宋','宋诗','song-poetry','','[]','斯文不于政，體用方殊觀。',48,'全唐诗/poet.song.157000.json','["斯文不于政，體用方殊觀。", "頗聞罷謀曹，渠肯先學官。", "而公獨古意，首欲尊儒冠。", "果哉此道振，善俗良非難。"]'),
('794d68c0-0400-4033-a7f7-b49dbd73a92e','壽湖南宗憲五首  其三','廖行之','宋','宋诗','song-poetry','','[]','湘俗日窳敝，嗜惡甘如飴。',48,'全唐诗/poet.song.157000.json','["湘俗日窳敝，嗜惡甘如飴。", "良心豈初然，物欲或迫之。", "經正則民興，靡事窮誅夷。", "桑麻遂生業，四海治可推。"]'),
('d159b406-5948-4883-8f74-56536e5c197a','壽湖南宗憲五首  其四','廖行之','宋','宋诗','song-poetry','','[]','伊洛有真派，淵源洙泗宗。',48,'全唐诗/poet.song.157000.json','["伊洛有真派，淵源洙泗宗。", "蜀張日益遠，言行將無同。", "於公見事業，吾黨知適從。", "坐令千載下，竟識儒者功。"]'),
('ea885295-45b5-481e-9da2-f034e667bfec','壽湖南宗憲五首  其五','廖行之','宋','宋诗','song-poetry','','[]','欲壽人之情，而仁獨也正。',48,'全唐诗/poet.song.157000.json','["欲壽人之情，而仁獨也正。", "有能用其力，盡性以致命。", "公誠格物意，心靜無不敬。", "却笑彼談仙，區區較功行。"]'),
('73d6038c-811f-4500-891d-b6b0adb88fe5','壽湖南管倉五首  其一','廖行之','宋','宋诗','song-poetry','','[]','齊卿善高奚，爲治孰過之。',48,'全唐诗/poet.song.157000.json','["齊卿善高奚，爲治孰過之。", "到今民受賜，微管嗟吾其。", "宜哉世祀昌，有此廊廟姿。", "功名方鼎來，端亞蕭與伊。"]'),
('874a77bd-6c81-47f9-aeec-8c33031ad844','壽湖南管倉五首  其二','廖行之','宋','宋诗','song-poetry','','[]','敬仲始鹽筴，豐財此權輿。',48,'全唐诗/poet.song.157000.json','["敬仲始鹽筴，豐財此權輿。", "端能佐經費，農末深相須。", "惟皇敘八政，國裕民無癯。", "誰其制低昂，江左今夷吾。"]'),
('1a8358f6-941d-4220-9513-ae9200c7d103','壽湖南管倉五首  其三','廖行之','宋','宋诗','song-poetry','','[]','平糴慮國深，公囷匪邦積。',48,'全唐诗/poet.song.157000.json','["平糴慮國深，公囷匪邦積。", "自古斯有年，寖遠失初意。", "今年出緡錢，樂歲怨狼戾。", "此法竟施行，農民等蒙惠。"]'),
('d2f04bbc-d4c1-4a70-a160-77c5eeba9edd','壽湖南管倉五首  其四','廖行之','宋','宋诗','song-poetry','','[]','古人重繇使，竭作唯追胥。',48,'全唐诗/poet.song.157000.json','["古人重繇使，竭作唯追胥。", "兩稅已復役，三倍將何如。", "洪惟愛基本，幸甚均慘舒。", "周親今閭閻，民情力有餘。"]'),
('56d7453c-c58b-45bf-8da2-f6c0f632e937','壽湖南管倉五首  其五','廖行之','宋','宋诗','song-poetry','','[]','歲寒萬本怯，表立蒼官榮。',48,'全唐诗/poet.song.157000.json','["歲寒萬本怯，表立蒼官榮。", "相看琅玕碧，更對梅玉清。", "得能三友佳，來壽千載英。", "慶事未渠央，高標自天成。"]'),
('20e7c45a-a326-46c8-9f12-54aea8d51593','挽劉監廟','廖行之','宋','宋诗','song-poetry','','[]','去歲與君別，高談氣如虹。',204,'全唐诗/poet.song.157000.json','["去歲與君別，高談氣如虹。", "酒酣出三詩，遺我意何窮。", "歸塗度黄花，偶遇衡人東。", "問君無恙否，報言近已終。", "聞之駭且疑，期君後凋松。", "分携數月耳，鷄年何遽逢。", "還家僅弛擔，走哭悲填胸。", "夫君鄉評高，孝友古人同。", "一第晚乃得，權門肯投蹤。", "暫出不少留，翩翩若冥鴻。", "力學老不倦，進得新有功。", "惜哉幹國資，已矣浮雲空。", "最憐親白髮，行路爲慘容。", "頼是有子賢，接踵翔蟾宮。", "朝來哀笳發，湘江雨濛濛。", "月嶺挂寒斗，霜林號凄風。", "斯人重難見，夜臺情得通。"]'),
('a938ee35-5c05-4e99-bd77-1ab56d9a3155','送鄧彥霄','廖行之','宋','宋诗','song-poetry','','[]','四海一畎畝，萬事均農桑。',132,'全唐诗/poet.song.157000.json','["四海一畎畝，萬事均農桑。", "汙萊儻輟功，饁餉安取償。", "斯言愧田叟，爲吏輕官常。", "悠悠但愒日，往往俱亡羊。", "鄧侯獨古意，枳棘寧鸞凰。", "所懷將志行，身詘庸何傷。", "高士豈徇俗，濟時乃褰裳。", "功名始一邑，圖籍皆甘棠。", "古人正如是，遠業詎可量。", "薰風入虞絃，萬宇須阜康。", "行矣食人食，勿謂吾言狂。"]'),
('6586416a-7f17-48e9-b01a-b556c066c9ba','題族兄耐軒','廖行之','宋','宋诗','song-poetry','','[]','乾坤一覆育，日月恒回旋。',180,'全唐诗/poet.song.157000.json','["乾坤一覆育，日月恒回旋。", "百川滾滾流，晝夜不舍旃。", "豈無桃杏姿，孰與松筠堅。", "物理耐則勝，人事敗以獧。", "君看伯禹功，手足甘胝胼。", "苟無尼父志，緇磷多夤緣。", "躁輕易與耳，頑頓終安然。", "吾宗伯也亢，學世其家傳。", "韜藏第懷寶，穮蔉須豐年。", "雙扉儼庭牖，一字深韋絃。", "此意當竟成，永言願無愆。", "吾聞約與樂，仁者斯兩全。", "君能處以一，我見成皆天。", "伊傅終佐時，吳鄧徒多錢。", "他時軒中人，更耐官九遷。"]'),
('3be1597c-25a0-4f0d-b9a0-59f7df20b8b2','題君子亭','廖行之','宋','宋诗','song-poetry','','[]','疏池種瓊瑶，築屋看雲錦。',48,'全唐诗/poet.song.157000.json','["疏池種瓊瑶，築屋看雲錦。", "愛渠花種賢，佳處心自領。", "我愛池中花，花中有君子。", "相看亭上人，其人亦如是。"]'),
('9d9bf84f-7dfb-40e5-b797-2dcd0c207ec2','和苦熱喜雨','廖行之','宋','宋诗','song-poetry','','[]','吾聞和陰陽，古人喻調鼎。',288,'全唐诗/poet.song.157000.json','["吾聞和陰陽，古人喻調鼎。", "四時有節適，萬類自紓窘。", "神哉洪鈞播，妙自元氣涬。", "寒暑遞推遷，日月互光炯。", "隆冬生流金，酷熱啟冰井。", "由來積以漸，其究勢莫競。", "沿流盍尋源，循踵良自寧。", "天功果其全，人事或可請。", "民咨思圖易，牛喘戒用猛。", "于焉貴調燮，持以濟炎冷。", "今年苦煩蒸，六月無息影。", "晴曦煽赫赫，卒歲憂懔懔。", "無何陰鳥鳴，恍若商羊騁。", "濃雲潑黛合，飛電與天等。", "誰爲投壺戲，多謝一笑肯。", "疾雷正晝發，隠隠連夜永。", "羣龍挾雨飛，霶霈浹四境。", "豈惟蘇槁苗，已足潤頑礦。", "歡呼到田稚，揚泊亂池黽。", "熱惱變清凉，造化祇俄頃。", "如痛乃遽定，若醉而倏醒。", "人情競欣欣，我寐獨耿耿。", "帝力今何知，誰其發深省。", "古來禹稷志，要在饑溺拯。"]'),
('6d79ca7a-d6de-4633-b7dd-2ea3ae59ffc5','壽岳陽林倅','廖行之','宋','宋诗','song-poetry','','["\u6cf0\u5c71", "\u897f\u6e56", "\u6d1e\u5ead\u6e56"]','南風舞山木，幾日天好晴。',288,'全唐诗/poet.song.157000.json','["南風舞山木，幾日天好晴。", "驟雨洗空翠，當暑氣倏清。", "湖光散瀰𣾜，宇鑑浮青冥。", "魚龍戲吹浪，草木摇芳馨。", "祥氛郁華居，喜色生緹屏。", "緹屏一何喜，別駕今甫申。", "丰神稟崧嶽，仙骨標蓬瀛。", "間世出王佐，生賢果天心。", "當時三更月，尚記七莢蓂。", "居然熊羆夢，况乃星宿熒。", "堂堂問禮家，豈但工梅吟。", "西湖耿澄澈，泰山愧崢嶸。", "德器重九鼎，材猷冠千英。", "鳴絃了巖邑，展驥開修程。", "岳陽千乘邦，樓觀萬古名。", "形勝以人重，民安須政平。", "誰問蕃宣功，正藉太守丞。", "要令范公記，亹亹增清芬。", "十行東北來，六月西南征。", "心源不受暑，王命無留行。", "邦人徯膏澤，邑尉覘車塵。", "斂板慰所慕，執鞭欣且榮。", "匪私一身遇，所冀千里均。", "佳辰迫開府，善頌騰歡聲。"]'),
('0d2cacac-0b56-4a19-8476-860b6fb283aa','題舅氏耕隠圖','廖行之','宋','宋诗','song-poetry','','[]','平生澤物心，不計飽一吻。',144,'全唐诗/poet.song.157000.json','["平生澤物心，不計飽一吻。", "中年厭道路，回首荒二頃。", "有口不自餬，誰其識莘尹。", "天子閔斯勞，祠官養閑冷。", "庶人乃敢召，往役義唯謹。", "兩手不袖藏，扶犁遍畦畛。", "云胡三百廛，正可一笑哂。", "置之他勿問，樂此果何慍。", "能敬師冀缺，弗治謝楊惲。", "深思鹵莽報，寧憚作勞愍。", "拳拳畎畝志，尚願國多稔。", "長哦七月篇，知公非素隠。"]'),
('853b1f8b-ce29-468d-a68b-09a2ff4ea36b','書懷寄黄夢立','廖行之','宋','宋诗','song-poetry','','[]','荆山之璞天下奇，韞藏待價其誰知。',96,'全唐诗/poet.song.157000.json','["荆山之璞天下奇，韞藏待價其誰知。", "楚庭已作再獻客，楚國未識連城姿。", "世間萬事乃如此，遇否在天而已矣。", "龍螭尚爾困泥蟠，可是紛紛肆蚖虺。", "人生安可論窮通，失馬有時同塞翁。", "會須決起凌雲志，高摶九萬扶摇風。"]'),
('72d00ef7-4310-432e-a060-dec29b35d3ec','夏夜大雨','廖行之','宋','宋诗','song-poetry','','[]','西風響樹聲颾颾，暮雲勢作蛟龍逃。',96,'全唐诗/poet.song.157000.json','["西風響樹聲颾颾，暮雲勢作蛟龍逃。", "玄冥夜半挽銀漢，翻寫到地奔驚濤。", "萬聲傳空震且怒，草木股慄皆悲號。", "吾聞閔民望歲者，辛勤必與豐年遭。", "即今麥孕苗欲秀，得失相去懸秋毫。", "沛然一雨決豐歉，誰謂天鑒徒高高。"]'),
('5b0cf0af-c331-4236-a83e-cdceb020164b','和湯無邪','廖行之','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','東風習習初春天，流澌凍解興魚潜。',384,'全唐诗/poet.song.157000.json','["東風習習初春天，流澌凍解興魚潜。", "池波生綠紋漪漣，和氣已覺彌天淵。", "人間佳處不獨此，我有嘉客稱世賢。", "懷歸不肯依劉表，滿懷貯月清光皎。", "君行天下眼力高，泰山自見秋毫小。", "往時祖烈通帝震，凜凜奚啻霜松清。", "力扶彜倫正皇極，精貫日月伊忠誠。", "聲彌宇宙身卑下，貪天下願羣龍駕。", "功高德厚愈流光，誰信幽潜空厚夜。", "吾聞丹穴多祥鸞，正論世濟非論官。", "慙卿慙長彼何事，五公四世嗤新安。", "欣然如君食舊德，瀾翻自詭真奇特。", "瀟湘江上忽相逢，遨遊遠自蠶叢國。", "詩豪氣俠負家傳，平生重義不重錢。", "千金萬鎰隨手盡，南來祗有兩臂全。", "且言昔與吾兄別，相勉相期皆遠業。", "六年萬里天西南，歷井捫參淅今接。", "故人已作騎箕英，顦顇倦游誰可倫。", "風波險阻厭蜀道，恨不澤國歸垂綸。", "如今豈乏資身策，家在吳江天一域。", "牀頭金盡何足言，氣干牛斗心金石。", "不須伍舉談班荆，開心見膽須真情。", "交游衮衮半朝露，家有諫省真難兄。", "聽君話言坐未定，投我新篇富嘲咏。"]'),
('4fcdc1e1-43bd-4b24-8e35-d0cf38e5b1b6','再酬湯無邪','廖行之','宋','宋诗','song-poetry','','[]','少陵自嘆休問天，高歌杜曲希陶潜。',384,'全唐诗/poet.song.157000.json','["少陵自嘆休問天，高歌杜曲希陶潜。", "兩翁潔身如清漣，流行坎止停則淵。", "不肯相邀事趣走，相望異世俱稱賢。", "又如雙鶴立表表，長庚共月相輝皎。", "人言兩翁皆大才，頗恨當時用之小。", "太微別垣環紫宸，台符烱烱光太清。", "天心愛君見于世，生賢賚弼何其誠。", "那知局促多轅下，詭轡竊御誇覂駕。", "懷哉朝秣玉山禾，徐趨可刷幽并夜。", "我聞此馬如翔鸞，不比羣蛙私復官。", "馴轅妥策服黄道，御輿君子何其安。", "豈其力稱稱以德，谷量謾富馿騾特。", "乃知市駿等掄材，畢竟多賢重王國。", "湯君謂我祖有傳，非獨中選如張錢。", "誅姦發策自其手，亟使國步臻安全。", "忠言信與紛紛別，大啟羣公扶帝業。", "退然寧肯自賢功，錫馬無心晝三接。", "青編自有聲飛英，笑唾當年石季倫。", "高風盛節位不稱，獨抱此志虛經綸。", "君言濟世非無策，太息神臯猶異域。", "會令桂海一冰天，却鎸浯頌燕然石。", "吾儂瑣碎如棘荆，聽君忠憤猶含情。", "可憐有志不得展，三嘆失我金昆兄。", "人生萬事皆前定，試聽滄浪清濁詠。"]'),
('7942619d-7d32-4889-9517-7f26691b174e','春日途中','廖行之','宋','宋诗','song-poetry','','[]','人家二月燕始歸，春陰還近清明期。',64,'全唐诗/poet.song.157000.json','["人家二月燕始歸，春陰還近清明期。", "我行東指來江上，傑木夾徑如旌旗。", "驅馳不憚百里遠，解后時醉青帘垂。", "懸知故人隠山市，相見甫邇黄生眉。"]'),
('c3fe77fc-2114-4b27-9b95-033502891a90','山棗道中','廖行之','宋','宋诗','song-poetry','','[]','疾雷將雨風怒號，夜半破屋聲嘈嘈。',64,'全唐诗/poet.song.157000.json','["疾雷將雨風怒號，夜半破屋聲嘈嘈。", "平明野水一犂滿，浮雲忽散青山高。", "三湘歸來故清絕，半載何事徒捐勞。", "可憐辜負春已晚，鶑老花殘空濁醪。"]'),
('0e8308fc-74c7-4c1a-9180-4d98fab008f5','西郊即事三首  其一','廖行之','宋','宋诗','song-poetry','','[]','唐年斗酒價三百，苦貴已起詩翁言。',64,'全唐诗/poet.song.157000.json','["唐年斗酒價三百，苦貴已起詩翁言。", "那知三倍猶痛飲，可知此老空煩冤。", "風煙澒洞攪霜信，雲日黯淡浮天根。", "此世有酒須爛醉，貴賤瑣瑣寧當論。"]'),
('599b45ab-cb43-4ff1-a433-fc9e43b7fed2','西郊即事三首  其二','廖行之','宋','宋诗','song-poetry','','[]','秋老那復雨初晴，我行西郊賞西成。',64,'全唐诗/poet.song.157000.json','["秋老那復雨初晴，我行西郊賞西成。", "蘆花飛空訝舞絮，楓葉滿徑紛吹萍。", "香秔幸愜一飽願，晚菊亦吐三秋英。", "陂池更作嗣歲計，帝力浩浩仁羣生。"]'),
('35e6ac5c-f2ae-410c-8651-6c08752d2c67','西郊即事三首  其三','廖行之','宋','宋诗','song-poetry','','[]','曉行出日歸流螢，二童一馬塵蒙纓。',64,'全唐诗/poet.song.157000.json','["曉行出日歸流螢，二童一馬塵蒙纓。", "道傍老翁笑相語，道上夫子真勞生。", "有田觀我奉甘旨，無技聳世難公卿。", "從渠自嗤我自樂，天風振木哦詩聲。"]'),
('25097354-047d-447a-9aa3-e97c4d96df2a','又次韵三首  其一','廖行之','宋','宋诗','song-poetry','','[]','昔人逢秋每悲思，往往推本騷人言。',64,'全唐诗/poet.song.157000.json','["昔人逢秋每悲思，往往推本騷人言。", "安知四時皆足樂，但願一切長無冤。", "山林朝市等昔夢，榮悴開落俱陳根。", "不如沉醉了萬事，春蘭秋菊誰能論。"]'),
('1641b74f-e131-42ad-96aa-7f0f4d5d755d','又次韵三首  其二','廖行之','宋','宋诗','song-poetry','','[]','養禾欲雨稼欲晴，閔閔此事須天成。',64,'全唐诗/poet.song.157000.json','["養禾欲雨稼欲晴，閔閔此事須天成。", "湘田是處可穫稻，村酒縱飲無幾萍。", "老農歡喜自舉白，俗士觸縮誰飛英。", "如今祇合謀一醉，功名富貴從浮生。"]'),
('87e9e927-33bb-4e63-a441-2d4dca867124','又次韵三首  其三','廖行之','宋','宋诗','song-poetry','','[]','一年好景今露螢，試問誰濯滄浪纓。',64,'全唐诗/poet.song.157000.json','["一年好景今露螢，試問誰濯滄浪纓。", "隨時動遭不事謗，潔己自覺太清生。", "西風常次樂郊路，好酒不博當朝卿。", "浩然十里馬蹄疾，未到城門打鼓聲。"]'),
('93edad94-661a-4a2d-bd03-a33ada38efbf','夜夢得一句云老樹拜風窗影亂因伸其語爲一絕','廖行之','宋','宋诗','song-poetry','','[]','夢魂栩栩塵緣掃，風拜月窗春樹老。',32,'全唐诗/poet.song.157000.json','["夢魂栩栩塵緣掃，風拜月窗春樹老。", "一枕驚回得句時，清奇未遜池塘草。"]'),
('5cc9085e-c7b1-472e-b7ff-dc4ef14981a2','江皋即事','廖行之','宋','宋诗','song-poetry','','[]','霜肅寒空晴意力，江清一带玻璃碧。',96,'全唐诗/poet.song.157000.json','["霜肅寒空晴意力，江清一带玻璃碧。", "微波漾日光浮浮，萬頃無聲流寂寂。", "灣頭輕舠一葉微，篙工急刺馳如飛。", "饑鴉見人自驚去，未若鷗鳥能忘機。", "船頭午後炊烟起，颯颯微風掠蘋尾。", "江皋有客意何如，獨立無言望江水。"]'),
('52c3eb33-4e33-4f0b-8ad0-072b7917cc71','再次前韵','廖行之','宋','宋诗','song-poetry','','[]','午日晴明軒眼力，煙浮波面融融碧。',96,'全唐诗/poet.song.157000.json','["午日晴明軒眼力，煙浮波面融融碧。", "隔溪誰家鷄一聲，人在叢篁更深寂。", "纖鱗弄暖吹波微，饑鴈爲作低回飛。", "漁翁可是生涯闊，放漾終日忘塵機。", "心旌忽爲家山起，遥憶瀟湘鱠鱸尾。", "誰能一席助清風，歸去蒸江弄蒸水。"]'),
('22eb79f1-233a-4e05-ad68-e31ef377e3be','書湘陰驛壁','廖行之','宋','宋诗','song-poetry','','[]','舍舟湖頭煙水昏，假榻郵傳猶柴門。',32,'全唐诗/poet.song.157000.json','["舍舟湖頭煙水昏，假榻郵傳猶柴門。", "可能濁酒澆客吻，莫厭明月撩詩魂。"]'),
('af2b780c-b6be-49f0-b920-213646b40b1f','溪流','廖行之','宋','宋诗','song-poetry','','[]','溪流一作神仙遇，歲歲桃花落復開。',64,'全唐诗/poet.song.157000.json','["溪流一作神仙遇，歲歲桃花落復開。", "誰控空巖守奇鬼，豈唯塵俗到雲來。", "彭澤昌黎一是非，悠悠千古謾傳疑。", "蒼崖何物扃巖竇，獨許當時漁父知。"]'),
('1e3e2c96-6d69-4fb0-896d-d6bab53ecf34','和喜雨詩','廖行之','宋','宋诗','song-poetry','','[]','夏畦雲稼憂芳蕤，炎官火傘烘晴曦。',64,'全唐诗/poet.song.157000.json','["夏畦雲稼憂芳蕤，炎官火傘烘晴曦。", "何人半夜起龍蟄，慰我卒歲豐年期。", "吾生正作一飽計，天意似憫三農時。", "椎牛釃酒樂村社，帝力於爾其誰知。"]'),
('ab2d4a50-f648-4498-864b-b1d47256c3b1','和陳必强韵','廖行之','宋','宋诗','song-poetry','','[]','三旌之位不足貴，萬鍾於我其何加。',64,'全唐诗/poet.song.157000.json','["三旌之位不足貴，萬鍾於我其何加。", "誰如日飲無骨相，底用眼眩鳩盤茶。", "哦詩清籟助蕭爽，角壯餘子空雄誇。", "東洋北若不汝較，望嘆自失無津涯。"]'),
('10d4789c-50e7-4f0b-b272-b5645ef747d0','和楊公維二首  其一','廖行之','宋','宋诗','song-poetry','','[]','子雲家無儋石儲，日有載酒過門閭。',64,'全唐诗/poet.song.157000.json','["子雲家無儋石儲，日有載酒過門閭。", "道丰澤衍今甫大，天理報施寧欺予。", "我慚投李得珍貺，俗眼快覩真璠璵。", "何當急走問奇字，報語姑以先勤渠。"]'),
('a3979914-be7c-4956-a04f-e1a4b8740edd','和楊公維二首  其二','廖行之','宋','宋诗','song-poetry','','[]','楊侯胸中萬卷書，瀾翻騷興軋三閭。',64,'全唐诗/poet.song.157000.json','["楊侯胸中萬卷書，瀾翻騷興軋三閭。", "文成素藁富柱腹，詞有餘鋒須賈予。", "俊逸進追新軌轍，溫純端擬古璠璵。", "我漸不作池塘夢，徒羨清溝愧濁渠。"]'),
('814cc451-9a1e-4ea5-930e-65a3bbe82fac','和游子歎','廖行之','宋','宋诗','song-poetry','','[]','前年春種方萌蘗，我喜君來屐幾折。',96,'全唐诗/poet.song.157000.json','["前年春種方萌蘗，我喜君來屐幾折。", "今年湖田農正忙，君從伯氏聽漁榔。", "平生四海饒足力，到處哦詩不虛日。", "高懷一笑無心雲，暮秣燕冀朝吳餐。", "從渠小知但莽蒼，羈馽維絡游龍顙。", "男兒遇合自有秋，此志寧爲溫飽休。"]'),
('38b0d827-6e81-4520-bd2f-4f51eaccb32d','呈武氏表兄','廖行之','宋','宋诗','song-poetry','','[]','我家蒸湘東復東，君嘗過我從嫗翁。',288,'全唐诗/poet.song.157000.json','["我家蒸湘東復東，君嘗過我從嫗翁。", "我時總角君未冠，相與遊戲如鴻濛。", "無何君作十年別，遠指沅水云能窮。", "兒時豈識銷黯事，聚散過眼回頭空。", "衡陽以西大酉麓，其間不及馬牛風。", "向來往往二十載，音問無計隨鱗鴻。", "吾翁得官夜郎郡，盡室隨牒溪山中。", "故應喜近栖碧老，豈謂一疾銘幽宮。", "箕裘頼有七男子，華萼競秀階庭豐。", "爾來得得步相訪，磊落玉樹何玲瓏。", "固知乃翁已無憾，有子足勝王家戎。", "團圞夜話得相屬，幸勿別去輕匆匆。", "即今山城二月半，李花能白桃能紅。", "陽和薰蒸著草木，駘蕩天冶春融融。", "繁華不足悅我眼，獨以文字忻磨礱。", "男兒胸中負志業，聲價直欲高恒嵩。", "立身揚名我輩事，肯逐斥鷃甘蒿蓬。", "篇詩慇懃丐領畧，但愧骫骳言非工。"]'),
('b9af0274-5c1e-4308-866b-df3db3e78f66','呈四表兄求栖碧遺文','廖行之','宋','宋诗','song-poetry','','[]','詩亡自昔周之東，末乃頼有三閭翁。',288,'全唐诗/poet.song.157000.json','["詩亡自昔周之東，末乃頼有三閭翁。", "三閭避讒思去國，當時無人歌雨濛。", "忠懷義槩不見省，獨以文字塗幽窮。", "高情寓物發歎詠，憂深思遠言非空。", "富如渤澥産百怪，浩若九萬扶摇風。", "後來文士相繼出，思援弓繳隨冥鴻。", "二都以降更七代，浸墮侈靡淫哇中。", "新奇嫵媚乏典則，往往體制多稱宮。", "汗牛充棟號繁博，簡策冗長何其豐。", "至音寂寥風雅墜，天球何處求玲瓏。", "遼遼曠世一杜叟，粹出于正排夷戎。", "丁年天寶適倥傯，崎嶇奔走方匆匆。", "有我未始不憂國，豈若兒輩隨朱紅。", "瞻前無隣後無配，膏馥殘賸何豐融。", "少陵以來栖碧老，筆鋒閃閃矛新礱。", "九原已矣不可作，知有妙語齊烝嵩。", "生平寤寐祈一見，如垢未沐頭方蓬。", "君無恐我誤雌霓，研覈諷誦猶能工。"]'),
('8de9f344-13c1-495c-8323-05413e7e8d6c','次韵酬郭承禧','廖行之','宋','宋诗','song-poetry','','[]','黄鐘大呂非常器，清廟陳之乃其地。',128,'全唐诗/poet.song.157000.json','["黄鐘大呂非常器，清廟陳之乃其地。", "胡爲小用噎寸莛，猶遣咸韶有遺事。", "君才棲枳今何時，天意似欲昌吾詩。", "西山正爾朝氣爽，左手好在霜螯持。", "連牆顧我勞相過，徙舍羨君安宴坐。", "春蘭秋菊借芬馨，蚯蚓蒼蠅許賡和。", "彌明出語如笑嬉，喜悲思苦那能奇。", "便須起敬拜牀下，敢問所學真誰師。"]'),
('64755480-fbc3-43ba-b4a4-908e566c7792','賦壓波亭呈益陽趙宰','廖行之','宋','宋诗','song-poetry','','[]','當塗自詭譙中龍，長驅遠鬭矜餘鋒。',384,'全唐诗/poet.song.157000.json','["當塗自詭譙中龍，長驅遠鬭矜餘鋒。", "孫劉交合出奇計，一炬赤壁成三雄。", "荆州疇昔借資地，久假乃復相仇攻。", "是時熊湘介二國，北有蜀壘南吳牖。", "蠻爭觸競已千古，往事獨有江流東。", "人言此水自雲阜，聯引澬邵經夷中。", "崎嶇二梅壓盤束，擘裂千嶂煩奔衝。", "窮豪究勇力少縱，始得平隰流舂容。", "紆餘十里僅間暇，贔屭五渚俄衝從。", "潴爲渟淵産百怪，往往不宅馮夷宮。", "春霖夏潦故假藉，谷吐川灌資騰舂。", "陽侯客氣不自禁，驅脅罔象從羣凶。", "往時井邑困陵藉，欲已此患嗟無庸。", "英英忠定經國手，初日小試勤民功。", "不煩燃犀照奇鬼，正爾宴坐銷狂烽。", "築亭據勝俯百壑，坐使衮衮皆朝宗。", "投巫謾詫鄴中老，驅鱷未遜潮陽翁。", "橫流一旦復故道，精意要與神明通。", "吾聞祖龍制六合，欲以盛氣陵華戎。", "將遊會稽示汰侈，乃被濤浙還他從。", "區區水波豈云惡，要是暴戾神方恫。", "安知盛德雖邑宰，能轉造化回天工。", "爾來百有六十載，民得平土趨耕農。", "只今令尹亦公輩，惟有善政希高蹤。"]'),
('2efdaa82-66a2-4008-aeb7-da83dc1a4e06','送程正翁解官歸徽州','廖行之','宋','宋诗','song-poetry','','[]','夫君貌瘠中甚腴，萬卷抑塞蟠胸書。',208,'全唐诗/poet.song.157000.json','["夫君貌瘠中甚腴，萬卷抑塞蟠胸書。", "文章有神貴有骨，小住金馬論石渠。", "青雲可上不自喜，却下枳棘如棲梧。", "勾稽五載信留滯，澹泊一意忘奔趨。", "心研典墳畧鞶帨，腕脫牋牘疲鴻魚。", "諸公要人徧知己，爭欲迎致沾波餘。", "代來秩滿不得去，懇懇至挽桓君須。", "平生不願受知廣，高興忽動歌歸歟。", "湘江水落清徹底，桂棹可理真良圖。", "人生適意貴自得，懷土不爲西風鱸。", "一盃別酒聊復爾，千里明月非人殊。", "修身善世本一理，聚首分袂皆同區。", "它時用否猶故吾，寄書當道今何如。"]'),
('20d3c909-42a0-47d7-b06d-934349099a33','壽邵陽唐倅二首  其一','廖行之','宋','宋诗','song-poetry','','[]','君不見大士化身兜率天，地湧兩足雙金蓮。',195,'全唐诗/poet.song.157000.json','["君不見大士化身兜率天，地湧兩足雙金蓮。", "光明照耀十方界，至今猶記周昭年。", "當年剎利西王國，才見薰風入炎日。", "菩提廣轉大法輪，普現寶身千百億。", "即今應感湘江涯，一念甫爲羣生迷。", "誕彌猶是舊來日，塵世已覺心南移。", "宰官未向朝端去，暫作資陽大慈父。", "惟將四諦妙真來，一洗含靈愁嘆苦。", "海沂豈久淹王祥，沙堤指日催鳴璫。", "心華定力莫思議，福利四海爲津梁。", "斯民正頼覺空覺，應世因緣詎能度。", "椿齡永劫未渠央，會看優曇幾開落。"]'),
('c70de9f4-5fc3-4331-a85f-647954718bc8','壽邵陽唐倅二首  其二','廖行之','宋','宋诗','song-poetry','','[]','瑞蓂八葉開蕤賓，湘川當年生俊人。',128,'全唐诗/poet.song.157000.json','["瑞蓂八葉開蕤賓，湘川當年生俊人。", "天孫織裳雲錦新，下與聖世爲卿雲。", "妙齡材策趣金鑾，從橫禮樂波瀾翻。", "結知九重生羽翰，揚庭徑許陞朝班。", "姓名將啟金甌黄，海沂蹔此留王祥。", "朝來椒頌傳新章，青衫屬吏欣觀光。", "方瞳玉頰歌雲謠，醴泉爲酒𨟉斗杓。", "東方蟠桃三度實，安期瓜棗甘於蜜。"]'),
('59295460-22b3-448b-8f03-330116b4a933','代賀蘇鹽生朝','廖行之','宋','宋诗','song-poetry','','[]','斗杓酒携井絡墟，月蓂四莢隨盈除。',160,'全唐诗/poet.song.157000.json','["斗杓酒携井絡墟，月蓂四莢隨盈除。", "絪縕和氣掬宇宙，葱鬰瑞靄充門閭。", "門閭自是相家舊，許國勳閥今渠渠。", "公侯骨相奇表在，佛祖心諦羣疑袪。", "長材不憚剸煩劇，入贊樞庭還題輿。", "聲猷業履藹中外，使節榮畀東南如。", "三湘來領阜通計，九郡咸企澄清車。", "民言此地公蘧廬，當饋注想寧應徐。", "姓名行啟金甌書，公府入即潭潭居。", "方壺蓬島有壽域，安用九轉刀圭餘。"]'),
('ea4f5cca-45f0-462e-91c6-9c788cf6ede0','代人上父生朝詩','廖行之','宋','宋诗','song-poetry','','[]','杓携娵訾月華薄，瑞靄朝來溢簾幕。',64,'全唐诗/poet.song.157000.json','["杓携娵訾月華薄，瑞靄朝來溢簾幕。", "芙蓉猶解姹然紅，要與誕彌尋舊約。", "霞觴舉處金璀錯，壽祝莊椿與龜鶴。", "鯉庭請學熾昌詩，綵衣戲有承顔樂。"]'),
('5052ecbb-7e48-4bb0-a6fd-ad6457bb5717','將歸新城鄉舍邀賦詩贈行','廖行之','宋','宋诗','song-poetry','','[]','請君吟詩送我歸，我歸雖作半月期。',64,'全唐诗/poet.song.157000.json','["請君吟詩送我歸，我歸雖作半月期。", "馬頭黄埃且百里，村店白酒占雙旗。", "只今柳絲東城路，萬縷方作青青垂。", "歸來應未及飛絮，自取春色開修眉。"]'),
('513e5561-059d-4fd3-ad59-60c031c28e93','和阻風潜江以詩禱神','廖行之','宋','宋诗','song-poetry','','[]','江行幾日風打頭，江上客子添牢愁。',64,'全唐诗/poet.song.157000.json','["江行幾日風打頭，江上客子添牢愁。", "人言水神喜作祟，客欲精禱姑維舟。", "平生結習口語業，篇詩敢告波神休。", "欣然回首領此意，一息千里聊乘流。"]'),
('9b5d3955-f669-41fe-b560-a6b1bb2c1567','爲老人壽蘇鹽','廖行之','宋','宋诗','song-poetry','','[]','司寇家聲遠，開元相業尊。',264,'全唐诗/poet.song.157000.json','["司寇家聲遠，開元相業尊。", "亞燕推手筆，刺暴賦箎塤。", "無逸隋圖在，居延漢節存。", "二天公覆蓋，六印氣雄渾。", "美玉藍田裔，洪河積石源。", "人材鍾盛世，侯伯萃高門。", "龍集天津尾，杓携井絡坤。", "策加三卦候，蓂改四朝昏。", "兆夢熊羆喜，儀庭鸑鷟鶱。", "崧高真氣宇，佛祖是心原。", "標準儀中外，才猷剸劇煩。", "樞庭陪國論，江介輔侯藩。", "忠力宣僚寀，勳庸簡帝閽。", "皇華分使節，風采動輶軒。", "煮摘三湘富，澄清九郡恩。", "融融流叶氣，藹藹載謠言。", "望洽青氈舊，榮須錫馬蕃。", "金甌披姓字，芝詔下天垣。", "卿月當聯棘，王庭合簉鵷。", "蓬壺開壽域，斗柄挹芳樽。", "蟠實來仙木，松膏出老根。", "祝公千歲壽，带礪見調元。"]'),
('d58d2d4e-7558-408a-ae93-57f0296daf42','和劉晉父寒食日從郡掾遊花光相社祠絕江訪向園賞春韵三首  其一','廖行之','宋','宋诗','song-poetry','','[]','官事何時了，郊行亦興佳。',48,'全唐诗/poet.song.157000.json','["官事何時了，郊行亦興佳。", "不因修佛供，端爲憶詩家。", "歌櫂浮春浦，吟筇倚暮花。", "翻思紅蘂句，想像怨年華。"]'),
('6744217c-9cc4-48a4-b8b8-04e5f0ccf331','和劉晉父寒食日從郡掾遊花光相社祠絕江訪向園賞春韵三首  其二','廖行之','宋','宋诗','song-poetry','','[]','不作春遊去，那能詩思佳。',48,'全唐诗/poet.song.157000.json','["不作春遊去，那能詩思佳。", "春山長在眼，白酒不謀家。", "泛泛一簑釣，冥冥幾樹花。", "相從有真趣，無夢到京華。"]'),
('b87f5cb9-82dd-40fc-87d3-0953ef73dc5c','和劉晉父寒食日從郡掾遊花光相社祠絕江訪向園賞春韵三首  其三','廖行之','宋','宋诗','song-poetry','','[]','寒食江頭去，精藍景象佳。',48,'全唐诗/poet.song.157000.json','["寒食江頭去，精藍景象佳。", "懷人悲往事，得句念無家。", "飄泊苦多病，顛狂因惱花。", "那知三百載，崇祀有光華。"]'),
('1c971aab-0e6a-478a-b024-84133e665dce','和春睡','廖行之','宋','宋诗','song-poetry','','[]','持底賞春晴，清眠自爽魂。',48,'全唐诗/poet.song.157000.json','["持底賞春晴，清眠自爽魂。", "據梧銷白日，高枕未黄昏。", "蝴蝶飛何樂，華胥夢可溫。", "周公應不遠，心事得深論。"]'),
('0e677be1-3adb-416c-896b-035c2dd2d3bc','和羅舜舉三首舜舉夢中得臘酒催詩處春幡剪綵時二句足成四韵屬余和之  其一','廖行之','宋','宋诗','song-poetry','','[]','世態醯雞舞，塵緣野馬馳。',48,'全唐诗/poet.song.157000.json','["世態醯雞舞，塵緣野馬馳。", "眼中惟俗物，夢裏是真知。", "綵筆神傳夜，春池句得時。", "渠儂未應愧，百世與風期。"]'),
('3565a9b7-cc03-49c0-9d3f-89a54c1a050b','和羅舜舉三首舜舉夢中得臘酒催詩處春幡剪綵時二句足成四韵屬余和之  其二','廖行之','宋','宋诗','song-poetry','','[]','日月遊駒迅，光陰激箭馳。',48,'全唐诗/poet.song.157000.json','["日月遊駒迅，光陰激箭馳。", "自應憐未遇，誰解語先知。", "消息春來好，功名夢到時。", "更憑詢造物，無作戯人期。"]'),
('5db0555a-3e67-4fe8-9310-0db72444cbd6','和羅舜舉三首舜舉夢中得臘酒催詩處春幡剪綵時二句足成四韵屬余和之  其三','廖行之','宋','宋诗','song-poetry','','[]','世無良樂久，驥足謾驅馳。',48,'全唐诗/poet.song.157000.json','["世無良樂久，驥足謾驅馳。", "尚喜心無愧，渠憂人未知。", "塵埃渾瞇目，魂夢識佳時。", "好在張儀舌，男兒詎可期。"]'),
('acca249c-5cff-41ee-886b-1308ed97174c','贈勝業老了謐','廖行之','宋','宋诗','song-poetry','','[]','客行半吳楚，人與詩皆窮。',48,'全唐诗/poet.song.157000.json','["客行半吳楚，人與詩皆窮。", "得公三昧語，示我五言工。", "南山足佳氣，古剎長清風。", "應餘錦囊句，還許蓮社同。"]'),
('118fafc0-58b8-4371-ba68-271d8eacc7a8','和前韵  其一','廖行之','宋','宋诗','song-poetry','','[]','有賦爲招隠，無文可送窮。',48,'全唐诗/poet.song.157000.json','["有賦爲招隠，無文可送窮。", "郢歌應寡和，齊瑟自難工。", "好在南山霧，高眠北牖風。", "此心奚所得，要與古人同。"]'),
('e06c6c74-0630-4cf0-9c6e-11551be73d37','和前韵  其二','廖行之','宋','宋诗','song-poetry','','[]','久雨送春晚，倦游憐客窮。',48,'全唐诗/poet.song.157000.json','["久雨送春晚，倦游憐客窮。", "不因人事謬，安得詩篇工。", "鶑語喚昨夢，雞聲驚曉風。", "此時無好句，愁絕有誰同。"]'),
('ed476e2b-9e0c-4044-a9c1-19dff23553cd','和前韵  其三','廖行之','宋','宋诗','song-poetry','','[]','詩源渺萬頃，衮衮來無窮。',48,'全唐诗/poet.song.157000.json','["詩源渺萬頃，衮衮來無窮。", "定應遊戯爾，豈事雕琢工。", "三章見囊穎，一讀清頭風。", "貧兒獲茲富，往往至寶同。"]'),
('e21746d0-9e44-44dd-9c05-6b8ae7d54583','暮春偶成四首  其一','廖行之','宋','宋诗','song-poetry','','[]','殘花自開落，遲日半晴陰。',48,'全唐诗/poet.song.157000.json','["殘花自開落，遲日半晴陰。", "翡翠山容暗，蒲萄江漲深。", "綠楊渾作絮，黄鳥欲成瘖。", "春事今如許，誰能著酒斟。"]'),
('7923ef87-fce6-4715-994c-9f42fb2e5978','暮春偶成四首  其二','廖行之','宋','宋诗','song-poetry','','[]','蒲渚生新漲，花蹊長綠陰。',48,'全唐诗/poet.song.157000.json','["蒲渚生新漲，花蹊長綠陰。", "微風將暑至，一雨共春深。", "强聒燕何吻，卑喧蛙未瘖。", "有懷無可奈，吟興發清斟。"]'),
('317e49a8-9b64-4b83-bf35-ca2d3db91d91','暮春偶成四首  其三','廖行之','宋','宋诗','song-poetry','','[]','小雨纖纖潤，輕雲淡淡陰。',48,'全唐诗/poet.song.157000.json','["小雨纖纖潤，輕雲淡淡陰。", "溪光清絕處，山影翠微深。", "蠶市朝何寂，牛歌晚不瘖。", "高吟憐節物，合把酒尊斟。"]'),
('94a462f2-9b5a-4c11-8c60-28450747634d','暮春偶成四首  其四','廖行之','宋','宋诗','song-poetry','','[]','春色堂堂去，雲容故故陰。',48,'全唐诗/poet.song.157000.json','["春色堂堂去，雲容故故陰。", "情連芳草遠，愁共碧波深。", "一雨能多久，鳴鳩只合瘖。", "杖頭方寂寞，那得濁醪斟。"]'),
('c5ba5c45-617f-4729-a2de-e47da9a6ac0a','雨中有懷  其一','廖行之','宋','宋诗','song-poetry','','[]','客裏春三月，江頭雨半旬。',48,'全唐诗/poet.song.157000.json','["客裏春三月，江頭雨半旬。", "囊空那得醉，吟苦未甘貧。", "愁逐花枝老，詩隨節物新。", "郴流去湘水，欲此寄雙鱗。"]'),
('03b23ad9-4522-45a8-bf02-82bda7d7b1f9','雨中有懷  其二','廖行之','宋','宋诗','song-poetry','','[]','春色無多日，匆匆度七旬。',48,'全唐诗/poet.song.157000.json','["春色無多日，匆匆度七旬。", "驅馳遊子態，蕭索旅中貧。", "酒薄愁那減，詩窮句轉新。", "誰能念牢落，涸轍有枯鱗。"]'),
('f806d0d4-aa5d-4cc2-855c-d07d8ed450cc','七夕','廖行之','宋','宋诗','song-poetry','','[]','目切雲垂望，心馳枕扇凉。',48,'全唐诗/poet.song.157000.json','["目切雲垂望，心馳枕扇凉。", "兩年違色養，七夕又他鄉。", "坐想斑衣戯，胡爲捧檄忙。", "何人翟方進，將母冠巖廊。"]'),
('c554d36c-35c7-4713-a863-452b8842082f','觀潮','廖行之','宋','宋诗','song-poetry','','["\u94b1\u5858\u6c5f"]','江接東溟闊，潮從八月高。',48,'全唐诗/poet.song.157000.json','["江接東溟闊，潮從八月高。", "祇應風捲浪，誰遣怒成濤。", "舟楫乘流迅，魚龍得意豪。", "瀛洲今不遠，好去釣金鰲。"]'),
('984fa907-2d8d-4731-8aa7-ae41ae92cbb1','宿田橋驛枕上口占','廖行之','宋','宋诗','song-poetry','','[]','屋敝漏疎星，魂清夢轉驚。',48,'全唐诗/poet.song.157000.json','["屋敝漏疎星，魂清夢轉驚。", "蛙鳴千百輩，鳥語兩三聲。", "意氣渾干斗，塵勞未解纓。", "平生四方志，安肯效蠅營。"]'),
('5d9445ae-3da0-455c-a822-000a70de5627','如新牆宿於劉叟逆旅','廖行之','宋','宋诗','song-poetry','','[]','一雨洗殘暑，初秋生嫩凉。',48,'全唐诗/poet.song.157000.json','["一雨洗殘暑，初秋生嫩凉。", "寸岑餘黛綠，多稼已雲黄。", "早覺宦情薄，可能詩興長。", "空慚賦囊粟，持底報君王。"]'),
('5d21c06e-2cfe-4192-90fd-3e2953140d79','向氏歸來園','廖行之','宋','宋诗','song-poetry','','[]','十畝江頭地，今時靖節園。',48,'全唐诗/poet.song.157000.json','["十畝江頭地，今時靖節園。", "輞川慚畫古，綠野謾名存。", "自有菊成徑，何須花滿原。", "是間無俗物，不用閉松門。"]'),
('3b332cac-414e-4196-8874-567b83add660','水仙','廖行之','宋','宋诗','song-poetry','','[]','擢擢瓊簪秀，盈盈玉頰新。',48,'全唐诗/poet.song.157000.json','["擢擢瓊簪秀，盈盈玉頰新。", "隴梅真季孟，洛浦是精神。", "好在臨江佩，遥憐步月塵。", "對花惱詩思，何必霅溪蓴。"]'),
('658663ae-770a-4272-b852-b9787591b1d3','歲晚寄羅舜舉','廖行之','宋','宋诗','song-poetry','','[]','歲晚旅懷惡，雲平東望賒。',48,'全唐诗/poet.song.157000.json','["歲晚旅懷惡，雲平東望賒。", "故人空眼底，別恨憶江涯。", "尺素形聲畫，萍蹤溷齒牙。", "襟期定何許，歸夢惱胡笳。"]'),
('82581d13-e7e4-4150-9958-ef37f141d99c','懷程正翁','廖行之','宋','宋诗','song-poetry','','[]','江上送君歸，燈前凝我思。',48,'全唐诗/poet.song.157000.json','["江上送君歸，燈前凝我思。", "源流嗟世遠，師友不吾欺。", "此道無今昔，人生易別離。", "江湖幾千里，從此尚心期。"]'),
('853adee5-dd37-4c3a-b701-c61cd2882a90','錢塘買舟西歸','廖行之','宋','宋诗','song-poetry','','[]','疇昔春江上，詩成感舊遊。',48,'全唐诗/poet.song.157000.json','["疇昔春江上，詩成感舊遊。", "重來正炎日，還復理扁舟。", "興逐輕帆遠，愁隨急雨收。", "三年四來往，依舊水東流。"]'),
('5931650c-7c0c-4929-b51e-db5b4a4ce3c9','戲詠白髮','廖行之','宋','宋诗','song-poetry','','[]','與愁添悴色，爲老出孤標。',48,'全唐诗/poet.song.157000.json','["與愁添悴色，爲老出孤標。", "髣髴生銀縷，依微散玉苗。", "摘除猶茁茁，晞沐更蕭蕭。", "相見函關路，應符物色邀。"]'),
('28bf1bb0-125c-4edf-8e72-c445d02d0a55','和益陽趙宰六首  其一','廖行之','宋','宋诗','song-poetry','','[]','爲邦何所急，勸學最留情。',48,'全唐诗/poet.song.157000.json','["爲邦何所急，勸學最留情。", "數仞新儒館，千年繼武城。", "梁間珍篆古，門外碧波平。", "會有明倫士，培風縱鶚橫。"]'),
('129652f3-fa14-4e75-80f0-3c657985a2f2','和益陽趙宰六首  其二','廖行之','宋','宋诗','song-poetry','','[]','食黮從吾化，安輿本若情。',48,'全唐诗/poet.song.157000.json','["食黮從吾化，安輿本若情。", "有能奔晉盜，何用築秦城。", "一邑誠天幸，三年頼政平。", "儒功固如許，儀舌漫縱橫。"]'),
('855943f0-3341-47a6-858f-7e00b5dfb104','和益陽趙宰六首  其三','廖行之','宋','宋诗','song-poetry','','[]','馭吏胡爲術，臨民若用情。',48,'全唐诗/poet.song.157000.json','["馭吏胡爲術，臨民若用情。", "兩難誠具美，雙璧重連城。", "威愛無偏舉，權衡自適平。", "吏忠民更樂，協氣日流橫。"]'),
('60993364-7a38-4dcc-b5f8-0104929e8660','和益陽趙宰六首  其四','廖行之','宋','宋诗','song-poetry','','[]','世治不忘兵，公深愛國情。',48,'全唐诗/poet.song.157000.json','["世治不忘兵，公深愛國情。", "雄張新漢壁，勢壓舊吳城。", "夜月鳴笳肅，秋風列燧平。", "農耕渾自適，是處畝從橫。"]'),
('202c8583-bdfa-4d53-9530-0421d6806197','和益陽趙宰六首  其五','廖行之','宋','宋诗','song-poetry','','[]','底事及幽冥，仁人惻隠情。',48,'全唐诗/poet.song.157000.json','["底事及幽冥，仁人惻隠情。", "憐渠猶旅骴，爲爾返鄉城。", "泚顙人應化，分香訟亦平。", "存亡俱惠澤，高義與雲橫。"]'),
('035f6279-d0b8-494e-bf1c-2e57c97105e8','和益陽趙宰六首  其六','廖行之','宋','宋诗','song-poetry','','[]','胸中涵萬象，江上漫怡情。',48,'全唐诗/poet.song.157000.json','["胸中涵萬象，江上漫怡情。", "突兀飛華屋，依微出化城。", "所欣逢歲有，此意樂時平。", "登覽多新句，何須馬槊橫。"]'),
('39f0aa72-feaf-4772-88fc-58a92d65c53e','無題','廖行之','宋','宋诗','song-poetry','','[]','州牧誰能舉，邦人願借情。',48,'全唐诗/poet.song.157000.json','["州牧誰能舉，邦人願借情。", "聲名簡宸扆，恩信著湘城。", "龐統才何陋，班超策故平。", "何如今別駕，膏澤與江橫。"]'),
('ce9cde4e-d26e-4fc8-9245-44572397b9ff','挽王倅','廖行之','宋','宋诗','song-poetry','','[]','政最方賢躅，公心得事情。',48,'全唐诗/poet.song.157000.json','["政最方賢躅，公心得事情。", "江湖多撫字，秦蜀佐廉平。", "族處歡群從，鄉評歎老成。", "西風非宰木，猶記手經營。"]'),
('dad13de6-06d8-4b83-9bab-53232c7a9ee0','挽周守','廖行之','宋','宋诗','song-poetry','','[]','姓氏標千佛，功名老一麾。',48,'全唐诗/poet.song.157000.json','["姓氏標千佛，功名老一麾。", "人皆嗟窘步，公不陋居夷。", "悃愊尤安靜，廉明且惠慈。", "窮陬天弗佑，三月逝如斯。"]'),
('5a0af2cb-3234-4a82-bf95-731d3f289b60','挽鄧彥霄  其一','廖行之','宋','宋诗','song-poetry','','[]','秀整文明早，精明吏事優。',48,'全唐诗/poet.song.157000.json','["秀整文明早，精明吏事優。", "聯登年正妙，再轉譽彌休。", "方展雲衢步，俄驚夜壑舟。", "平生如此友，零落向山丘。"]'),
('fcb15390-6ffb-49ff-8166-8f0539aec78a','挽鄧彥霄  其二','廖行之','宋','宋诗','song-poetry','','[]','仲氏懷聯璧，慈親念倚閭。',48,'全唐诗/poet.song.157000.json','["仲氏懷聯璧，慈親念倚閭。", "官遷身未享，子少室無儲。", "不料全家望，真成一夢虛。", "生材慳子壽，天意竟何如。"]'),
('da91074e-d088-416f-9937-29013b1933be','挽谷子長  其一','廖行之','宋','宋诗','song-poetry','','[]','仁壽渠應爾，爲君呼彼蒼。',48,'全唐诗/poet.song.157000.json','["仁壽渠應爾，爲君呼彼蒼。", "若人奚所恨，夫我謂難量。", "好學顔何泯，多才賈遽亡。", "乘除餘慶在，薿薿看諸郎。"]'),
('b3e96a0e-7731-40c6-81f5-d0c3fb9b66e4','挽谷子長  其二','廖行之','宋','宋诗','song-poetry','','[]','百歲三之日，如君乃若然。',48,'全唐诗/poet.song.157000.json','["百歲三之日，如君乃若然。", "謝庭凋玉樹，楚澤斃蘭荃。", "堂有雙親老，身無寸祿緣。", "英魂儻猶在，泣我此詩篇。"]'),
('f0ca940d-4f24-462c-b393-5ddde703a78a','挽谷子長  其三','廖行之','宋','宋诗','song-poetry','','[]','伊昔拜芝宇，詞場話俊游。',48,'全唐诗/poet.song.157000.json','["伊昔拜芝宇，詞場話俊游。", "一從分袂日，五閲鱠鱸秋。", "別夢思何極，長川逝莫留。", "盖棺俄隔世，空遣淚橫流。"]'),
('036e2224-6b92-4628-ba61-68229dcc036c','挽劉知府乘','廖行之','宋','宋诗','song-poetry','','[]','辛苦平生學，儒科志稍酬。',48,'全唐诗/poet.song.157000.json','["辛苦平生學，儒科志稍酬。", "路遥車折軸，夜半壑亡舟。", "士惜鴒原盡，親悲鶴髮留。", "傳家幸有子，門戶可無憂。"]'),
('5afd78c3-3ca3-45a9-8e05-3204bbcdd60a','挽鄧知縣友龍  其一','廖行之','宋','宋诗','song-poetry','','[]','文撼湘南國，才高月旦評。',48,'全唐诗/poet.song.157000.json','["文撼湘南國，才高月旦評。", "弟兄皆吏計，父子擅科名。", "綵服歡初浹，黄粱夢不驚。", "傷心見零落，埋玉閉佳城。"]'),
('652f6d4d-b60a-41ce-8bb8-345a828d0df7','挽鄧知縣友龍  其二','廖行之','宋','宋诗','song-poetry','','[]','別向巴丘去，歸從浙水來。',48,'全唐诗/poet.song.157000.json','["別向巴丘去，歸從浙水來。", "絕憐三益友，高卧九泉臺。", "清會成陳迹，明時失茂才。", "無因陪祖奠，風壑寄餘哀。"]'),
('139d7399-5705-4faa-9730-08a7a8d104e0','挽軍器監簿周公子及  其一','廖行之','宋','宋诗','song-poetry','','[]','人物丹丘秀，才華邁選優。',48,'全唐诗/poet.song.157000.json','["人物丹丘秀，才華邁選優。", "青藜行照坐，白玉遽成樓。", "數不登知命，言猶見告猷。", "詞林根柢在，三鳳看鳴啾。"]'),
('16b14b67-6e07-4233-80d3-4c1425929d12','挽軍器監簿周公子及  其二','廖行之','宋','宋诗','song-poetry','','[]','一經同鴈塔，再入並鴛行。',48,'全唐诗/poet.song.157000.json','["一經同鴈塔，再入並鴛行。", "方喜爲寮好，那知夢奠傷。", "學多應損壽，文富幸流芳。", "有士奇如此，雲溪奈閟藏。"]'),
('cf08733a-ec37-42fd-8c8c-9806d847040d','挽唐學錄頤  其一','廖行之','宋','宋诗','song-poetry','','[]','今代稱純孝，如公第一流。',48,'全唐诗/poet.song.157000.json','["今代稱純孝，如公第一流。", "事親惟婉順，厲志只操修。", "德行渾無間，功名略未酬。", "空遺千古恨，明月一山丘。"]'),
('177ad3ca-04db-4e48-8c8d-f1eb268b9d34','挽唐學錄頤  其二','廖行之','宋','宋诗','song-poetry','','[]','虎榜標名日，英聲四海聞。',48,'全唐诗/poet.song.157000.json','["虎榜標名日，英聲四海聞。", "傳家惟奧學，有子繼清芬。", "未熟黄粱夢，俄同冥漠君。", "哲人今已矣，無復更論文。"]'),
('d87fb2c5-2e9d-4023-9dc1-e97f3f29b85a','挽龔宣教世基  其一','廖行之','宋','宋诗','song-poetry','','[]','文物湘中盛，唯公獨最優。',48,'全唐诗/poet.song.157000.json','["文物湘中盛，唯公獨最優。", "麒麟來瑞世，鵬鶚快橫秋。", "桂籍名方著，燈窗志少酬。", "居鄉多令望，治國藴嘉猷。"]'),
('dab1ec02-3bb5-47e4-a1f0-2a1eee0ccd06','挽龔宣教世基  其二','廖行之','宋','宋诗','song-poetry','','[]','游刃雖餘地，棲鸞試未周。',48,'全唐诗/poet.song.157000.json','["游刃雖餘地，棲鸞試未周。", "僅伸三釜養，俄隔九泉幽。", "風樹悲難弭，蒿莪痛曷瘳。", "平生無恨處，有子襲箕裘。"]'),
('d4eb88a6-7e71-4390-9e32-e60cbc58c549','挽雍宣教知義  其一','廖行之','宋','宋诗','song-poetry','','[]','早擢蟾宮桂，聲名第一流。',48,'全唐诗/poet.song.157000.json','["早擢蟾宮桂，聲名第一流。", "下帷潛大業，擊楫志神州。", "修短林中木，浮沉水上漚。", "生芻今日奠，惻愴淚難收。"]'),
('fca69ff5-e51f-4582-966e-9622cf2415f7','挽雍宣教知義  其二','廖行之','宋','宋诗','song-poetry','','[]','憶昔居黌舍，曾陪戯綵斑。',48,'全唐诗/poet.song.157000.json','["憶昔居黌舍，曾陪戯綵斑。", "才華推粹美，功績嘆間關。", "有子能傳業，無丹可駐顔。", "哀詞臨隧路，明晦萬重山。"]'),
('79b05f89-fc01-4a2f-8e5d-7bf4c90b90fb','挽龔主簿蓋卿  其一','廖行之','宋','宋诗','song-poetry','','[]','當代文章伯，聲名屬太常。',48,'全唐诗/poet.song.157000.json','["當代文章伯，聲名屬太常。", "雲衢方奮立，薤露忽悲傷。", "郄桂榮賢嗣，萊衣遠北堂。", "蒼天竟何意，忍使哲人亡。"]'),
('d74c0b9e-e972-421b-a987-12426b77710d','挽龔主簿蓋卿  其二','廖行之','宋','宋诗','song-poetry','','[]','奇士如公少，居然得譽尊。',48,'全唐诗/poet.song.157000.json','["奇士如公少，居然得譽尊。", "績文追古作，獻策達修門。", "梁壞吾安仰，人亡道尚存。", "傷心南野路，天迥暮雲昏。"]'),
('07954833-93ca-42b1-b8c2-ca61e949f782','挽劉學諭玗  其一','廖行之','宋','宋诗','song-poetry','','[]','劍浦昔名族，湘川今世家。',48,'全唐诗/poet.song.157000.json','["劍浦昔名族，湘川今世家。", "簪纓方赫奕，里巷正光華。", "豈意有餘慶，翻成不足嗟。", "哀哉天道遠，福祿一何差。"]'),
('10afd271-5ef3-4b31-a756-2fe272e27cd0','挽劉學諭玗  其二','廖行之','宋','宋诗','song-poetry','','[]','詩禮家傳舊，箕裘世襲良。',48,'全唐诗/poet.song.157000.json','["詩禮家傳舊，箕裘世襲良。", "蚤同花萼秀，晚並桂椿芳。", "方恨違同氣，那知歎肯堂。", "斯文今已矣，繼踵屬賢郎。"]'),
('87d28106-a90b-4c02-a37c-0b4dfe317d54','挽劉學諭玗  其三','廖行之','宋','宋诗','song-poetry','','[]','聲猷驚俗舊，科第策名新。',48,'全唐诗/poet.song.157000.json','["聲猷驚俗舊，科第策名新。", "筮仕甫從志，辭官復爲親。", "誰期一朝患，遽殞百年身。", "平昔經綸事，而今已古人。"]'),
('69ffc5b9-5fd8-4724-a993-4f86c7b41ba6','挽劉學諭玗  其四','廖行之','宋','宋诗','song-poetry','','[]','學富猶無已，才雄非自成。',48,'全唐诗/poet.song.157000.json','["學富猶無已，才雄非自成。", "誨人真不倦，接物有餘情。", "僅有摳衣便，俄驚逝水傾。", "丹旌嗟莫挽，忍聽薤歌聲。"]'),
('508674f6-ec06-48b9-888e-ddd53ae8d2aa','挽劉宣教孝昌  其一','廖行之','宋','宋诗','song-poetry','','[]','夙世垂遺訓，書林早策勳。',48,'全唐诗/poet.song.157000.json','["夙世垂遺訓，書林早策勳。", "敬誠躋至善，師友富多聞。", "棠棣兩玉筍，閨門萬石君。", "九原那可作，惆悵哽飛雲。"]'),
('24b11504-7c18-4432-894a-3d4abd8e4266','挽劉宣教孝昌  其二','廖行之','宋','宋诗','song-poetry','','[]','暫出伸三釜，歸安菽水心。',48,'全唐诗/poet.song.157000.json','["暫出伸三釜，歸安菽水心。", "立言存絕筆，遺子勝籝金。", "肝腑真堪託，情親久亦深。", "交朋忘一鑑，哀淚滿衣襟。"]'),
('605a6ea5-5df7-465d-979f-d9b673336576','唁陳頤剛頤大二兄','廖行之','宋','宋诗','song-poetry','','[]','陳子吾爲友，別來今甫春。',48,'全唐诗/poet.song.157000.json','["陳子吾爲友，別來今甫春。", "孔庭歌壞木，竇樹失靈椿。", "誰謂有餘慶，幾成無告民。", "天涯一携手，涕出爲悲辛。"]'),
('a47c7cd0-dcf7-478f-8203-a00ffdfb4300','和遊歸來園韵  其一','廖行之','宋','宋诗','song-poetry','','[]','咄咄柴桑久卜鄰，軒軒少室竟何人。',64,'全唐诗/poet.song.157000.json','["咄咄柴桑久卜鄰，軒軒少室竟何人。", "一丘奇興心猶遠，千古論交迹未陳。", "奮鍤自隨天地闊，園林好在歲時新。", "東風相逐經行處，花草禽魚不計春。"]'),
('a7c5e1df-bc7c-4c82-bbea-f5a680c6feca','和遊歸來園韵  其二','廖行之','宋','宋诗','song-poetry','','[]','簿書叢裏厭紛埃，夙駕輶軒此地來。',64,'全唐诗/poet.song.157000.json','["簿書叢裏厭紛埃，夙駕輶軒此地來。", "好是板輿將母樂，不妨樽酒爲花開。", "難拚勝賞哦詩適，生怕嚴城打鼓催。", "明日江頭還眺望，松風閣上幾徘徊。"]'),
('2e7b294e-ba07-4479-b84c-3ace274533fa','春雪','廖行之','宋','宋诗','song-poetry','','[]','臘尾春風不著忙，雪花先壓百花香。',64,'全唐诗/poet.song.157000.json','["臘尾春風不著忙，雪花先壓百花香。", "試爲天上玉妃舞，欲遣人間越犬狂。", "萬里冰壺塵不染，一番瓊圃日初長。", "東皇喜作吾翁瑞，又報豐年到酉陽。"]'),
('643240f8-3ce2-4416-88a1-c07d5673410c','江樓雪望','廖行之','宋','宋诗','song-poetry','','[]','幾日凝空雪未闌，江頭乘興一凭欄。',64,'全唐诗/poet.song.157000.json','["幾日凝空雪未闌，江頭乘興一凭欄。", "瑶池宮闕連天迥，瓊圃山川特地寬。", "極目龍沙千里遠，倚空冰柱數峰寒。", "望中渾覺蟾宮近，便欲乘風寄羽翰。"]'),
('d6e2e647-0bdc-4961-9bac-53d760d73461','和春遊三首  其一','廖行之','宋','宋诗','song-poetry','','[]','駘蕩融和二月天，邀朋同是飲中仙。',64,'全唐诗/poet.song.157000.json','["駘蕩融和二月天，邀朋同是飲中仙。", "試將拄杖踏芳草，更看蘭舟航野川。", "酒興償花聊復一，詩篇賈勇或相千。", "何妨日日尋春去，醉把賡酬授簡傳。"]'),
('5b3e9e59-4ebc-4a49-ab40-d7f16be5a99c','和春遊三首  其二','廖行之','宋','宋诗','song-poetry','','[]','尋勝遨遊且樂天，楚狂應是地行仙。',64,'全唐诗/poet.song.157000.json','["尋勝遨遊且樂天，楚狂應是地行仙。", "一年最好春三月，到處那能花滿川。", "夢澤詩腸吞八九，河沙醉境渺三千。", "眼中況有江臯佩，應作瀟湘勝會傳。"]'),
('de08d15d-f2f6-4e16-b985-c6771867782c','和春遊三首  其三','廖行之','宋','宋诗','song-poetry','','[]','雨餘遲日放晴天，春入園林點化仙。',64,'全唐诗/poet.song.157000.json','["雨餘遲日放晴天，春入園林點化仙。", "爲約奚囊行秀野，更看花島媚清川。", "杖頭買醉多踰百，笑裏揮金知幾千。", "一段清狂誰會得，謾將高興付詩傳。"]'),
('9c1360b6-6656-4364-9a89-d31bacea284d','海棠','廖行之','宋','宋诗','song-poetry','','[]','暖日烘晴二月天，萬絲垂舞競春妍。',64,'全唐诗/poet.song.157000.json','["暖日烘晴二月天，萬絲垂舞競春妍。", "誰移西蜀寸根遠，獨領東風一笑嫣。", "醉臉凝脂朝過雨，紅粧照燭夜籠烟。", "漫山百卉空粗俗，知是流霞第一仙。"]'),
('14833056-8809-4d63-8ee7-ace71e7f01ff','社日雨','廖行之','宋','宋诗','song-poetry','','[]','一年好樂九十日，底事天工力作難。',64,'全唐诗/poet.song.157000.json','["一年好樂九十日，底事天工力作難。", "自古惜春晴有幾，只今連夕雨猶𩆑。", "朝來已報山城社，客裏那知花信寒。", "遥想故園田父樂，伐豚釃酒樹團欒。"]'),
('30cf2a57-4797-4942-8498-6f4858cbac5a','清江道中','廖行之','宋','宋诗','song-poetry','','[]','客裏春愁萬斛量，隨身抖擻一奚囊。',64,'全唐诗/poet.song.157000.json','["客裏春愁萬斛量，隨身抖擻一奚囊。", "了無池草入詩夢，粗有山花供酒狂。", "半載飛蓬成底事，幾鈎新月誤相望。", "夕陽又傍空山宿，杜宇聲中入異鄉。"]'),
('9d1c4027-57c5-4459-8a85-a3a43052b275','次綱官王簿韵兼簡伯潛二首  其一','廖行之','宋','宋诗','song-poetry','','[]','江上晴光照眼濃，十分春色滿城東。',64,'全唐诗/poet.song.157000.json','["江上晴光照眼濃，十分春色滿城東。", "客懷何限湘波綠，漕事方殷漢粟紅。", "雅有詩情添興遠，可無酒力破愁攻。", "舳艫早晚蒲帆穩，長嘯東南萬里風。"]'),
('4914eb29-5cad-451c-8bcb-fa6b2455c442','次綱官王簿韵兼簡伯潛二首  其二','廖行之','宋','宋诗','song-poetry','','[]','柳岸流鶑兩兩黄，風光渾在一帘香。',64,'全唐诗/poet.song.157000.json','["柳岸流鶑兩兩黄，風光渾在一帘香。", "休辭老去追隨懶，莫遣春歸倥傯忙。", "滿地芳茵猶勝踐，漫天飛絮漫輕狂。", "溪園早有同遊約，準擬盃行引興長。"]'),
('b9ab3f36-e062-47f5-b1dd-819a30cbb7af','和張王臣郊遊韵三首  其一','廖行之','宋','宋诗','song-poetry','','[]','君訪西郊古佛家，還因燒佛問丹霞。',64,'全唐诗/poet.song.157000.json','["君訪西郊古佛家，還因燒佛問丹霞。", "可能同住依彌勒，應是前身悟木叉。", "林杪危亭供宴坐，門前翠袖儼排衙。", "紛紛廛市何時了，靜看優曇浩劫花。"]'),
('daa925d5-065a-446b-8851-c452833509de','和張王臣郊遊韵三首  其二','廖行之','宋','宋诗','song-poetry','','[]','山頭笑語落千家，曉入登臨引暮霞。',64,'全唐诗/poet.song.157000.json','["山頭笑語落千家，曉入登臨引暮霞。", "極目未應煩笏拄，招朋端不羨魚叉。", "歸來皓月明於燭，睡熟黄紬卧放衙。", "幕府官閑詩思敏，賡酬亹亹筆生花。"]'),
('bf1e75b7-7443-44a6-ba23-0ea0da10b062','和張王臣郊遊韵三首  其三','廖行之','宋','宋诗','song-poetry','','[]','秀句清圓掩百家，錦心幽思定餐霞。',64,'全唐诗/poet.song.157000.json','["秀句清圓掩百家，錦心幽思定餐霞。", "風騷誰敢闚嚴律，誦數惟應滿洛叉。", "已有文名肩杜曲，却憐羈旅賦彭衙。", "自嗟下里陪高唱，羞說花時鼓子花。"]'),
('a546098c-e969-421d-bfce-383afd3d3bb9','和芍藥','廖行之','宋','宋诗','song-poetry','','[]','牡丹摧盡蘂初成，花譜還應壓後生。',64,'全唐诗/poet.song.157000.json','["牡丹摧盡蘂初成，花譜還應壓後生。", "右掖昔年陪俊賞，幽蘭今日助詩情。", "當階鎮日翻紅艷，傍砌何人翫秀英。", "國色要須歸第一，花王從此浪收名。"]'),
('80da532e-8d0b-462d-b101-110c2e77c7cd','送春','廖行之','宋','宋诗','song-poetry','','[]','煮醖青梅且共嘗，遊蜂飛蝶爲誰忙。',64,'全唐诗/poet.song.157000.json','["煮醖青梅且共嘗，遊蜂飛蝶爲誰忙。", "鞦韆綵索迷青草，車馬紅橋鎖綠楊。", "春事戰回蒲劍老，詩腸結盡柳絲長。", "韶光賦別休匆遽，凝佇東風更一觴。"]'),
('f4622908-48ed-45bf-bcfc-fe0e7df27ede','宿田舍遇雨','廖行之','宋','宋诗','song-poetry','','[]','奔走塵埃日幾西，又從舟楫問津涯。',64,'全唐诗/poet.song.157000.json','["奔走塵埃日幾西，又從舟楫問津涯。", "官身底事多羈束，世路由來足嶮巇。", "甘雨也知甦䆉䅉，輕風祗管舞漣漪。", "夕陽又傍田村宿，無限蜩螗噪晚颸。"]'),
('f3ab544f-5ca8-4541-bff7-bc5054e3ee6c','七夕','廖行之','宋','宋诗','song-poetry','','[]','從昔人傳鵲作橋，一年牛女會清宵。',64,'全唐诗/poet.song.157000.json','["從昔人傳鵲作橋，一年牛女會清宵。", "幾家乞巧羅瓜果，是處開樽沸管簫。", "雲雨暫成銀漢約，風雷催趁玉晨朝。", "憑誰與問支機石，好上仙槎款碧霄。"]'),
('e195eb83-a870-476e-9671-6a8a2ceeebc0','重九後菊','廖行之','宋','宋诗','song-poetry','','[]','寂寞東籬幾夕霜，不堪憔悴逐炎凉。',64,'全唐诗/poet.song.157000.json','["寂寞東籬幾夕霜，不堪憔悴逐炎凉。", "誰知璞玉渾金態，盡作紅塵紫陌粧。", "流液尚能甘水味，返魂應付與梅香。", "來年莫落秋深後，好趁登高入酒觴。"]'),
('3b06f76b-83b8-4e6e-b809-7560b52460f6','中秋日簡同盟諸公','廖行之','宋','宋诗','song-poetry','','[]','風囊嘯谷獵塵衫，雨鬣行天駕玉驂。',64,'全唐诗/poet.song.157000.json','["風囊嘯谷獵塵衫，雨鬣行天駕玉驂。", "一洗蠻烟渾逐北，全提商令似征南。", "佳時不負中秋約，雙桂能同一夜談。", "我亦蘭陔奉馨膳，與君歡事喜相參。"]'),
('c1a82597-56c5-4676-959d-d1fd561a6792','和晚菊三首  其一','廖行之','宋','宋诗','song-poetry','','[]','羈寓窮秋幾許清，晚芳猶爾亦何榮。',64,'全唐诗/poet.song.157000.json','["羈寓窮秋幾許清，晚芳猶爾亦何榮。", "東籬舊豈論餘子，三徑今應愧老成。", "氣味耐堪供飲興，登臨那得厠羣英。", "節華要是丈人行，俗眼誰知省屈平。"]'),
('c0476481-b7bf-4bd9-8259-bac7cf0b2c52','和晚菊三首  其二','廖行之','宋','宋诗','song-poetry','','[]','何事秋光老更清，故應有菊占秋榮。',64,'全唐诗/poet.song.157000.json','["何事秋光老更清，故應有菊占秋榮。", "後來漢陛知薪積，晚出商山歎翼成。", "三徑惟將松比操，東籬那爲酒含英。", "紛紛紅紫隨時好，臆對西風訴不平。"]'),
('287dc32d-2af1-48d5-ba61-02263c1e112a','和晚菊三首  其三','廖行之','宋','宋诗','song-poetry','','[]','荒凉籬落露華清，菊爲重陽特地榮。',64,'全唐诗/poet.song.157000.json','["荒凉籬落露華清，菊爲重陽特地榮。", "奔競鬭心知戒在，疎遲懶性習閑成。", "償秋爲子添秋興，見晚知誰恨晚英。", "頼有南山陪舊望，悠然目極與雲平。"]'),
('8f1fbd50-bc41-4711-90ef-0e95f933bb1c','月夜有懷二宋兄','廖行之','宋','宋诗','song-poetry','','[]','雲容冉冉碧於衫，蟾影騰騰穩勝驂。',64,'全唐诗/poet.song.157000.json','["雲容冉冉碧於衫，蟾影騰騰穩勝驂。", "萬壑凉聲生木末，一天秋色滿江南。", "聞雞漫起狂夫舞，捫虱誰從隠士談。", "坐想詩翁搜好句，初機還許學人參。"]'),
('ff1df358-b06b-4368-a790-423b238d3fa4','秋夜讀書示謙  其一','廖行之','宋','宋诗','song-poetry','','[]','百年詩種世科存，三載相望兩拜恩。',64,'全唐诗/poet.song.157000.json','["百年詩種世科存，三載相望兩拜恩。", "主簿從渠稱大小，儒冠喜我到兒孫。", "立身正要先忠孝，力學尤須造本原。", "老矣寸陰猶共惜，日新期汝大吾門。"]'),
('9fc808c0-aaa8-44c9-973d-459b38b369f4','秋夜讀書示謙  其二','廖行之','宋','宋诗','song-poetry','','[]','常記吾公誨語存，豈唯撫育念深恩。',64,'全唐诗/poet.song.157000.json','["常記吾公誨語存，豈唯撫育念深恩。", "要將禮義扶門戶，常把詩書訓子孫。", "衆耳尚聞垂絕語，爾曹無負起家原。", "慇懃事業能無忝，何羨于公駟馬門。"]'),
('e6d65908-3b34-4397-9c35-9062b5ce6e9e','西囿盧橘數株方窮秋蕭索間詫然敷榮薿薿可愛作詩記之','廖行之','宋','宋诗','song-poetry','','[]','寂寂園林秋暮時，可人盧橘玉英肥。',64,'全唐诗/poet.song.157000.json','["寂寂園林秋暮時，可人盧橘玉英肥。", "祗應籬菊返魂在，滿慰金行得意歸。", "僵立凍蜂攢翅白，霏微繁李綴枝稀。", "天公似恐緇塵汙，乞與氈裘護雪衣。"]'),
('b58a6231-bf09-46fd-8594-fc53fe78b8a5','和羅舜舉  其一','廖行之','宋','宋诗','song-poetry','','[]','岸岸花飛客思濃，拍空烟水與天東。',64,'全唐诗/poet.song.157000.json','["岸岸花飛客思濃，拍空烟水與天東。", "暮雲橫嶺依依碧，朝日翻波衮衮紅。", "鷗共忘機元自適，鼉猶鳴鼓定誰攻。", "凭欄萬里危樓望，愁絕江南一笛風。"]'),
('0c9c0ecd-4f83-4d37-8dde-a65058f95381','和羅舜舉  其二','廖行之','宋','宋诗','song-poetry','','[]','對酒憐鵝滿意黄，江天風暖水紋香。',64,'全唐诗/poet.song.157000.json','["對酒憐鵝滿意黄，江天風暖水紋香。", "詩情到底能多助，官事由來未苦忙。", "晴雨不妨春自好，醉醒何擇我非狂。", "幾時容與扁舟去，浩蕩烟波情興長。"]'),
('02f08c3e-e3e4-43b2-aade-ba8d64a648af','和張王臣','廖行之','宋','宋诗','song-poetry','','[]','詞伯今猶從事衫，追風才軼謝羸驂。',64,'全唐诗/poet.song.157000.json','["詞伯今猶從事衫，追風才軼謝羸驂。", "浪傳齊己聲江左，不見彌明隠岳南。", "騷讀正堪供痛飲，箎音那許接高談。", "君家况有輶軒法，乞與新編得細參。"]'),
('0eceff19-78fe-48b3-8c88-fb63051463ab','和家字韵呈同社諸公','廖行之','宋','宋诗','song-poetry','','[]','平生四海魯東家，貌敬誰能禮有加。',64,'全唐诗/poet.song.157000.json','["平生四海魯東家，貌敬誰能禮有加。", "試問離歌談狗曲，何如艷曲唱山茶。", "廣平似鐵詩猶好，河內聞箴喜更誇。", "惟有謫仙堪痛飲，世間佳處樂無涯。"]'),
('1dc372ea-b429-4cef-a868-cd26f2e96c54','和松坡劉迂詩四首  其一','廖行之','宋','宋诗','song-poetry','','[]','新凉憑雨入郊墟，却置詩書困簡書。',64,'全唐诗/poet.song.157000.json','["新凉憑雨入郊墟，却置詩書困簡書。", "顧我塵埃隨野馬，今誰風味憶鱸魚。", "可能三釜從吾好，且放雙眉滿意舒。", "賸買一尊澆礧磈，從他㶁㶁水鳴除。"]'),
('f0557e91-33d4-40c8-9798-d285edf1d7db','和松坡劉迂詩四首  其二','廖行之','宋','宋诗','song-poetry','','[]','白雲飛處祝融墟，心切平安一紙書。',64,'全唐诗/poet.song.157000.json','["白雲飛處祝融墟，心切平安一紙書。", "浪走毛生慚捧檄，清貧羊續漫懸魚。", "銀蟾浮彩秋尤好，金粟含香桂欲舒。", "指日安輿奉顔色，綵衣容與戲庭除。"]'),
('ae685d11-c50e-4f55-ae17-ec97decd9181','和松坡劉迂詩四首  其三','廖行之','宋','宋诗','song-poetry','','[]','平生湖海敝貂裘，一笑周南底滯留。',64,'全唐诗/poet.song.157000.json','["平生湖海敝貂裘，一笑周南底滯留。", "豪放不妨詩李白，崢嶸何意吏朱游。", "悠悠世上難窮事，落落胸中肯著愁。", "高興橫秋渾不淺，月明還上武昌樓。"]'),
('8237b316-4a80-4764-a86c-183dbc00f2ee','和松坡劉迂詩四首  其四','廖行之','宋','宋诗','song-poetry','','[]','滿袖風埃季子裘，誰憐斗粟漫淹留。',64,'全唐诗/poet.song.157000.json','["滿袖風埃季子裘，誰憐斗粟漫淹留。", "棲遲歲月渾閑事，放浪湖山得勝游。", "一律任渠從濫吹，數盃容我且澆愁。", "祗應好在平生志，更上陳登百尺樓。"]'),
('25df7601-832f-4061-a1c5-1145c236acf3','暮秋聞鴈','廖行之','宋','宋诗','song-poetry','','[]','微日輸晴宿靄妝，征鴻迎暖到南州。',64,'全唐诗/poet.song.157000.json','["微日輸晴宿靄妝，征鴻迎暖到南州。", "相呼相喚稻粱熟，年去年來蘆葦秋。", "琴操曾遺中散恨，海瀕還見子卿不。", "夕陽莫傍江樓去，長有別離人倚樓。"]'),
('5b20b7b8-6a84-41ae-afcb-bd705d97e3d5','和藺仰之咏含笑花','廖行之','宋','宋诗','song-poetry','','[]','何物包藏欲媚誰，千金難售惜光儀。',64,'全唐诗/poet.song.157000.json','["何物包藏欲媚誰，千金難售惜光儀。", "空凝巧倩如羞靨，晴吐濃薰已透肌。", "一夕舉烽徒自苦，三年射雉若爲奇。", "無情草木欣欣意，却惱多情爲賦詩。"]'),
('afdebdfe-481d-4190-99a1-48dedbd01543','得長兄書','廖行之','宋','宋诗','song-poetry','','[]','雨餘清夢話躊躇，投曉敲門一紙書。',64,'全唐诗/poet.song.157000.json','["雨餘清夢話躊躇，投曉敲門一紙書。", "尺組却能羈壯士，寸心渾欲駕飛車。", "青衫小吏誰知子，白髮慈親正念渠。", "只道爲官志三釜，而今那似守閻閭。"]'),
('b26a6a3d-2111-48ad-bd59-108651a272b9','同伯潛諸公聯騎出城東次衫字韵','廖行之','宋','宋诗','song-poetry','','[]','怯曉征衣襲小衫，山頭淡月照聯驂。',64,'全唐诗/poet.song.157000.json','["怯曉征衣襲小衫，山頭淡月照聯驂。", "晴光忽散湘江上，秋色疑連夢澤南。", "後約吹香舒藻思，同遊載酒款犀談。", "遥知堅卧朱文季，倦聽朝雞趁六參。"]'),
('1fa3b8e0-5bc4-42b0-b766-de7850900f6f','和武必達郢亭雜咏韵','廖行之','宋','宋诗','song-poetry','','[]','君家華屋隠松關，滿壑清風六月寒。',64,'全唐诗/poet.song.157000.json','["君家華屋隠松關，滿壑清風六月寒。", "半歲胡爲漫蓬轉，篇詩猶解惜春闌。", "人言占馬應東首，我欲移文向北山。", "試問啼鵑緣底事，盡情終日勸人還。"]'),
('00362cdc-769e-4b94-a3c9-ee252491256d','宿白湖即事','廖行之','宋','宋诗','song-poetry','','[]','亂蟬聲裏夕陽村，野寺荒凉竹映門。',64,'全唐诗/poet.song.157000.json','["亂蟬聲裏夕陽村，野寺荒凉竹映門。", "汩汩溪流新過雨，芃芃禾稼已平原。", "老僧不省論詩句，初月猶能共酒樽。", "莫爲奔馳起歸興，東西南北一乾坤。"]'),
('d79be4b2-92a2-462b-8694-dba285749efc','和洞庭古寺壁間韵','廖行之','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','六月湖天凜似秋，曾憑檣燕小遲留。',64,'全唐诗/poet.song.157000.json','["六月湖天凜似秋，曾憑檣燕小遲留。", "蒼崖偃蹇浮屠古，白壁淋漓醉墨流。", "吹浪魚龍供客戲，乘槎牛斗得天遊。", "一聲帝子雲璈曲，家在蓬壺碧玉樓。"]'),
('c77af4b8-762e-4b97-aae6-ed40f58d4e19','和徐志父道中池亭獨遊之什二首  其一','廖行之','宋','宋诗','song-poetry','','[]','炎風勃勃觸輕衫，何事驅塵未解驂。',64,'全唐诗/poet.song.157000.json','["炎風勃勃觸輕衫，何事驅塵未解驂。", "清我一泓能湛湛，洗渠雙耳任喃喃。", "方從君子歡相愛，未信樵夫笑不談。", "他日通泉訪陳迹，光芒寶劍與天參。"]'),
('21474372-f9d8-418d-9943-b1d2e16914e2','和徐志父道中池亭獨遊之什二首  其二','廖行之','宋','宋诗','song-poetry','','[]','聞絃那用濕青衫，俛首鹽車驥可驂。',64,'全唐诗/poet.song.157000.json','["聞絃那用濕青衫，俛首鹽車驥可驂。", "珍重居污自貞潔，飛揚巢幕漫呢喃。", "雲天意氣生懷抱，尊俎風流入笑談。", "不礙哦詩佐清逸，明朝斂板又庭參。"]'),
('bb43c840-50ab-4c21-98f2-17ab7fffe82b','游嶽麓宮抱黄洞','廖行之','宋','宋诗','song-poetry','','[]','長沙不足容回旋，放脚直到清虛天。',64,'全唐诗/poet.song.157000.json','["長沙不足容回旋，放脚直到清虛天。", "層雲蕩胸意矯矯，皓月入袖情娟娟。", "扶摇浩蕩九萬里，城郭彷彿三千年。", "仙期汗漫直牛斗，此志理我乘風船。"]'),
('61da9d07-98c0-4c49-b623-b838eba022e2','和張王臣登清斯亭韵三首  其一','廖行之','宋','宋诗','song-poetry','','[]','一年好景負黄花，洗眼江梅傲歲華。',64,'全唐诗/poet.song.157000.json','["一年好景負黄花，洗眼江梅傲歲華。", "把酒欲從天問月，知時誰解管飛葭。", "人情似水多涇渭，世味如禪說蜜樝。", "祇可高吟酬節物，鶑聲早晚又天涯。"]'),
('4f06e74f-5f62-490a-abba-6f2551aa394c','和張王臣登清斯亭韵三首  其二','廖行之','宋','宋诗','song-poetry','','[]','一夜寒窗剪燭花，細尋詩派憶京華。',64,'全唐诗/poet.song.157000.json','["一夜寒窗剪燭花，細尋詩派憶京華。", "愛人欲贈兩溪竹，弔古誰荒大澤葭。", "味永黄雞羹苦菜，香清沈水煮榠樝。", "拈來信手皆佳句，浩歎東洋渺際涯。"]'),
('6debdefc-3a06-485e-ad1d-554df09c8710','和張王臣登清斯亭韵三首  其三','廖行之','宋','宋诗','song-poetry','','[]','海棠冬暖亦狂花，步遶畦區羨物華。',64,'全唐诗/poet.song.157000.json','["海棠冬暖亦狂花，步遶畦區羨物華。", "微雨蒼茫低塞鴈，寒聲寂歷到汀葭。", "映人清絕梅松竹，照眼黄垂橘柚樝。", "自喜閑中足幽興，不妨時理醉生涯。"]'),
('4ebe988f-6bd9-434b-b4b2-1b451a628afb','題蘇瑑覺齋二首  其一','廖行之','宋','宋诗','song-poetry','','[]','不隨鑿枘辨方圓，安用蓍龜考未然。',64,'全唐诗/poet.song.157000.json','["不隨鑿枘辨方圓，安用蓍龜考未然。", "萬物由來皆備我，寸心既盡即知天。", "見幾那俟拈花手，樂道渾忘絕易編。", "自得誠明千古學，誰能證此具精專。"]'),
('75a74eeb-395e-4a62-811c-33b563cc8df6','題蘇瑑覺齋二首  其二','廖行之','宋','宋诗','song-poetry','','[]','滅去觚稜性本圓，了除藩蔽物皆然。',64,'全唐诗/poet.song.157000.json','["滅去觚稜性本圓，了除藩蔽物皆然。", "向來具足頂門眼，盡發卑微甕裏天。", "膠擾空花俱是幻，拘攣塵鞅束如編。", "非予孰爲幡然起，莫遣阿衡美獨專。"]'),
('10c75ed3-932d-4d3c-82ce-331b46c1708c','和長兄席間書事','廖行之','宋','宋诗','song-poetry','','[]','窮山二月無多樂，猶作春來料峭寒。',64,'全唐诗/poet.song.157000.json','["窮山二月無多樂，猶作春來料峭寒。", "常恐花枝暗蕭索，却教詩句漫艱難。", "尋芳頼有城西角，泥飲休論日幾竿。", "他日山僧紀清集，閣中應作畫圖看。"]'),
('ecb24b20-5fa3-4f6f-ae74-33c85fb7af0b','題舅氏耕隠圖','廖行之','宋','宋诗','song-poetry','','[]','詩書事業可公卿，垂上青冥却反耕。',64,'全唐诗/poet.song.157000.json','["詩書事業可公卿，垂上青冥却反耕。", "舍己芸人吾弗爾，種田得飽我何營。", "一犂春雨寧論力，萬里秋雲會享成。", "堂上更書無逸語，也知稼穡重金籝。"]'),
('a4b0621d-d279-4b09-975b-bea6f392919e','書懷','廖行之','宋','宋诗','song-poetry','','[]','萊衣喜氣著青衫，世路從渠裂兩驂。',64,'全唐诗/poet.song.157000.json','["萊衣喜氣著青衫，世路從渠裂兩驂。", "試問虛名空斗北，何如榮養樂陔南。", "鄰牆飽聽新詩句，尊酒相從幾笑談。", "聞道秋郊足佳趣，好奇誰復似岑參。"]'),
('925b6cea-d8f7-460e-acff-ba85f6ef9f5d','食菜作二首  其一','廖行之','宋','宋诗','song-poetry','','[]','吾儒不羨能方丈，彼相胡爲食萬錢。',64,'全唐诗/poet.song.157000.json','["吾儒不羨能方丈，彼相胡爲食萬錢。", "誰識春來有珍味，樂如疏食曲肱眠。", "園中菜把勤能致，曹掾蓴羹美未專。", "便作遠謀勝肉食，他年無愧作詩篇。"]'),
('dea7dd70-8f53-41f3-a1f8-1a8f223a9c1b','食菜作二首  其二','廖行之','宋','宋诗','song-poetry','','[]','春來日膳菜數本，絕勝杖頭携百錢。',64,'全唐诗/poet.song.157000.json','["春來日膳菜數本，絕勝杖頭携百錢。", "但得園蔬非饉歲，肯令午夢攪清眠。", "食芹有美吾思獻，采菲無遺利可專。", "莫笑先生長誑腹，解吟朝日照盤萹。"]'),
('419c3929-642f-4da8-ab17-1c38427fd295','豐城舟中','廖行之','宋','宋诗','song-poetry','','[]','踏遍江湖路幾千，買舟因得憩江天。',64,'全唐诗/poet.song.157000.json','["踏遍江湖路幾千，買舟因得憩江天。", "不嫌煙水牽離恨，要狎沙鷗伴醉眠。", "南浦春深波漲岸，長蘆風寢浪平川。", "生涯喜近長年老，夜半挐音月滿船。"]'),
('6205ac66-98f0-40da-8515-5ded4276b97b','上湖南孫漕四首  其一','廖行之','宋','宋诗','song-poetry','','[]','湘郡湘城四十餘，賦租無爽歲無虛。',64,'全唐诗/poet.song.157000.json','["湘郡湘城四十餘，賦租無爽歲無虛。", "三年自是澄清澤，一吏何能撫字書。", "底事古人勤勸課，由來國計在閻閭。", "南陽誰守蒲誰宰，更頼褰幃使者車。"]'),
('8c0d1a8b-fbb2-46df-90c1-9f04b27611c0','上湖南孫漕四首  其二','廖行之','宋','宋诗','song-poetry','','[]','湘水湘江衮衮流，南連五嶺北荆州。',64,'全唐诗/poet.song.157000.json','["湘水湘江衮衮流，南連五嶺北荆州。", "造船行粟無遺算，自葉流根皆運籌。", "國計已多劉晏策，民情滋欲寇恂留。", "善刀莫起庖丁念，何止恢恢十二牛。"]'),
('2cf87fa3-952d-4824-8476-631121db3edb','上湖南孫漕四首  其三','廖行之','宋','宋诗','song-poetry','','[]','湘俗湘人百不憂，口無異論只歌謳。',64,'全唐诗/poet.song.157000.json','["湘俗湘人百不憂，口無異論只歌謳。", "皆言此日孫夫子，還是當年郭細侯。", "不信民情容易得，可能仁聞鎮長流。", "而今九郡皆膏澤，看取黄雲萬頃秋。"]'),
('539d54f7-cf6d-488c-8f46-0280a1f56e41','上湖南孫漕四首  其四','廖行之','宋','宋诗','song-poetry','','[]','湘雨湘田處處同，誰知公意與天通。',64,'全唐诗/poet.song.157000.json','["湘雨湘田處處同，誰知公意與天通。", "愛民天亦憂民事，望歲公應喜歲豐。", "自古强兵先足食，從今積粟可平戎。", "關中事業非難辦，要看他時第一功。"]'),
('384d67f6-51e3-4e44-aa95-e4cc0a028432','代送王守赴湖北漕','廖行之','宋','宋诗','song-poetry','','[]','紫泥芝檢下遥天，綉斧榮更竹使權。',64,'全唐诗/poet.song.157000.json','["紫泥芝檢下遥天，綉斧榮更竹使權。", "六轡周王新禮樂，重湖楚國舊山川。", "澄清風采生麾節，眷倚精神跂邃綖。", "早晚沙堤歸步穩，二台齊色耀星躔。"]'),
('6711fd64-1cc5-4c4d-b7ef-aec5c8eaf772','和丙午衡州鹿鳴宴詩','廖行之','宋','宋诗','song-poetry','','[]','丹詔飛來萬國春，掄才美意屬賢臣。',64,'全唐诗/poet.song.157000.json','["丹詔飛來萬國春，掄才美意屬賢臣。", "幾年志氣風雲壯，一旦聲名日月新。", "好把良籌裨負扆，莫貪香餌墮垂綸。", "來年上國風光好，喜帖西馳沸路塵。"]'),
('fb7187b0-2664-49bb-ba79-8c2301af304a','和石鼓宴士二首  其一','廖行之','宋','宋诗','song-poetry','','[]','幾年蓬藋翳儒宮，文物新還俎豆中。',64,'全唐诗/poet.song.157000.json','["幾年蓬藋翳儒宮，文物新還俎豆中。", "幸甚諸生初見武，歡然置酒更親崇。", "晴收楚嶠千峰雨，薰奏虞絃萬籟風。", "須信廉平漢循吏，可能齊魯化蠶叢。"]'),
('928f7aaf-07c7-4fe8-a63b-4d9ad3912b1b','和石鼓宴士二首  其二','廖行之','宋','宋诗','song-poetry','','[]','江頭秀木碧參空，喜見新晴到眼中。',64,'全唐诗/poet.song.157000.json','["江頭秀木碧參空，喜見新晴到眼中。", "秩秩北林筵有序，潭潭東閣禮尤崇。", "廣平元老今賢傑，江左夷吾正祖風。", "况復贛君崇教養，清陰到處綠成叢。"]'),
('8f8b3bd3-1313-4bd0-81b1-d4b76c877f75','上湖北趙司倉三首  其一','廖行之','宋','宋诗','song-poetry','','[]','君侯德業簡淵衷，亟上朝端望寖隆。',64,'全唐诗/poet.song.157000.json','["君侯德業簡淵衷，亟上朝端望寖隆。", "鵷鷺羽儀從北闕，驂騑禮樂正西風。", "六條郡國褰帷裏，萬里沅湘攬轡中。", "早晚詔書歸衮舄，由來周召合三公。"]'),
('e6fa0eaa-914f-4ed0-a846-bd85826c2c4b','上湖北趙司倉三首  其二','廖行之','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','黼扆天高德意深，恩言臨遣重丁寧。',64,'全唐诗/poet.song.157000.json','["黼扆天高德意深，恩言臨遣重丁寧。", "九霄雨露新英節，一日風雷徧洞庭。", "財力定能均息耗，米鹽因得裕常經。", "如今想見南翁喜，長望吳頭認使星。"]'),
('f18ca722-d595-4506-ac1b-fcea774c6dfa','上湖北趙司倉三首  其三','廖行之','宋','宋诗','song-poetry','','[]','廷尉年來犴獄清，更憑藻鑑惠諸生。',64,'全唐诗/poet.song.157000.json','["廷尉年來犴獄清，更憑藻鑑惠諸生。", "新奇往往多聞罷，朴魯區區亦竟成。", "已見規橅通造化，會看勳業正鈞衡。", "先生小試澄清手，天下顒顒望太平。"]'),
('7cf5a79f-3bcf-4afd-9f25-d79c275ebed5','送黄尉解官因簡黄德亨  其一','廖行之','宋','宋诗','song-poetry','','[]','夫君解紐去通泉，十幅風帆下碧川。',64,'全唐诗/poet.song.157000.json','["夫君解紐去通泉，十幅風帆下碧川。", "寶劍詩成光射斗，扶摇路穩翼垂天。", "湖山桂老乘秋興，越水梅開近日邊。", "丹扆須賢方側席，會聽鳴履上星躔。"]'),
('b7fd7b3c-8d90-4d53-98c4-2de7a9c810a7','送黄尉解官因簡黄德亨  其二','廖行之','宋','宋诗','song-poetry','','[]','平生飽聽無雙譽，一見全勝得異書。',64,'全唐诗/poet.song.157000.json','["平生飽聽無雙譽，一見全勝得異書。", "妙語從君聞梗概，清尊酌我更躊躇。", "希蹤伯氏情何限，惜別吾曹意有餘。", "若見滁州新博士，爲言湘水愧汙渠。"]'),
('259db1ba-af7b-49ec-90f6-377cf4bcc39f','病中寄武公望二首  其一','廖行之','宋','宋诗','song-poetry','','[]','四十餘年尚轉蓬，渠論南北與西東。',64,'全唐诗/poet.song.157000.json','["四十餘年尚轉蓬，渠論南北與西東。", "但知愛子三遷教，不辦謀生一畝宮。", "北海可憐真意廣，步兵良苦漫途窮。", "人生擇術須循分，鵬鷃逍遥自不同。"]'),
('f9ee2f3f-2ce2-49f5-8095-4bf5bf612a6d','病中寄武公望二首  其二','廖行之','宋','宋诗','song-poetry','','[]','輕去千金若棄遺，高情勇決固應稀。',64,'全唐诗/poet.song.157000.json','["輕去千金若棄遺，高情勇決固應稀。", "端來共我茅一把，不肯折君腰十圍。", "世事彈棋無定局，人情蒙穽有深機。", "生涯也趁身强健，況是平陽德可依。"]'),
('ef6e788e-bb1c-45fb-97a1-ab92d4d2ebd5','無題  其一','廖行之','宋','宋诗','song-poetry','','[]','生憎城裏只塵埃，勝處何妨特地來。',64,'全唐诗/poet.song.157000.json','["生憎城裏只塵埃，勝處何妨特地來。", "況是近郊新雨歇，可能乘興一樽開。", "春隨使者軺車至，花倩梨園羯鼓催。", "來歲披香侍華宴，也應猶記此低徊。"]'),
('2f2e2b84-70e1-4baf-b3d3-7bf5a6a0e783','無題  其二','廖行之','宋','宋诗','song-poetry','','[]','逸興飄飄鶴九臯，涼州那得費蒲萄。',64,'全唐诗/poet.song.157000.json','["逸興飄飄鶴九臯，涼州那得費蒲萄。", "一從卜築東山勝，便覺聲名北斗高。", "手種百花從日涉，心澄萬慮弭湯鏖。", "主人已作騎鯨去，誰與鴻濛共勝遨。"]'),
('6e52be16-c95a-4ca5-b30b-97f7d8cb9c73','用韵雜興','廖行之','宋','宋诗','song-poetry','','[]','夏葛冬裘等一衫，飛黄跛鼈謾同驂。',64,'全唐诗/poet.song.157000.json','["夏葛冬裘等一衫，飛黄跛鼈謾同驂。", "人情展轉憐風月，世路沈迷泣北南。", "我已灰心忘厚味，誰其緘口罷游談。", "如今欲問西來意，便掛僧牌報放參。"]'),
('97e4bfbd-c789-445c-be67-f8955aee2e1c','萍鄉道中','廖行之','宋','宋诗','song-poetry','','[]','萍實鄉中雨初歇，野溪流水奔驚湍。',64,'全唐诗/poet.song.157000.json','["萍實鄉中雨初歇，野溪流水奔驚湍。", "蠶功欲登蠶婦急，春陰已濃春事闌。", "飛綿漫空白雪舞，疊巘插漢青螺攢。", "家山歸去此無幾，眼底已作瀟湘看。"]'),
('8709ec85-2ac4-44fa-8204-4cbfe8df1153','宜春道中','廖行之','宋','宋诗','song-poetry','','[]','路轉溪回幾曲村，溪頭流水去渾渾。',64,'全唐诗/poet.song.157000.json','["路轉溪回幾曲村，溪頭流水去渾渾。", "農忙野叟朝耕隴，蠶老人家晝掩門。", "游子漫憐春色晚，故園應想綠陰繁。", "歸歟屈指無多日，夜雨團欒酒一尊。"]'),
('f48a1df6-00c5-42d6-9603-7b899e15bf6c','覓酒於宋伯潜','廖行之','宋','宋诗','song-poetry','','[]','典衣無策漸朝衫，早計君毋笑拊驂。',64,'全唐诗/poet.song.157000.json','["典衣無策漸朝衫，早計君毋笑拊驂。", "未辨牆頭仍甕下，空哦斗北與箕南。", "蒲萄不作涼州想，庚癸猶酬褐父談。", "折簡更招花下飲，可能離坐亦容參。"]'),
('b6fb51dd-12f9-4ed5-aaab-1239bfe3ea2c','和武公望從人覓酒二首  其一','廖行之','宋','宋诗','song-poetry','','[]','野店醪香尚带煙，中山醖久漫經年。',64,'全唐诗/poet.song.157000.json','["野店醪香尚带煙，中山醖久漫經年。", "公營惡草安吾分，太白高吟羨子先。", "好辦一尊常對月，誰能百斛更浮川。", "正須澆我談天口，富貴浮雲且任緣。"]'),
('5a12b1a8-01a7-4b54-8060-35fedd50d317','和武公望從人覓酒二首  其二','廖行之','宋','宋诗','song-poetry','','[]','春愁滿眼久驅除，懶問生涯念及孥。',64,'全唐诗/poet.song.157000.json','["春愁滿眼久驅除，懶問生涯念及孥。", "但得論文留客醉，不妨問字到山居。", "寒收凍面應浮蟻，暖入芳腴可泛酥。", "便欲呼兒洗杯酌，陶然應許及波餘。"]'),
('39dcfb14-ae75-4350-b35f-331abf739d2b','又次韵二首  其一','廖行之','宋','宋诗','song-poetry','','[]','幾日春寒似禁煙，杜門渾欲任流年。',64,'全唐诗/poet.song.157000.json','["幾日春寒似禁煙，杜門渾欲任流年。", "得錢相覓非難辦，載酒來過定孰先。", "無奈梅邊虛勝踐，遥憐柳外漲晴川。", "佳時縱意須從事，莫笑幽人也化緣。"]'),
('174e82cb-6274-465d-b716-bde8514970d5','又次韵二首  其二','廖行之','宋','宋诗','song-poetry','','[]','年來那復不時須，斗酒珍藏敢罪孥。',64,'全唐诗/poet.song.157000.json','["年來那復不時須，斗酒珍藏敢罪孥。", "安我饋漿窮逆旅，有誰携榼訪幽居。", "粗粱何擇皆庚癸，題品寧當辨酪酥。", "自笑悲辛慙杜老，却愁人不食吾餘。"]'),
('aef0a273-37be-415a-bf4c-050af733f972','棄屣有感','廖行之','宋','宋诗','song-poetry','','[]','蹈遍關山日幾西，周旋步武鎮相依。',64,'全唐诗/poet.song.157000.json','["蹈遍關山日幾西，周旋步武鎮相依。", "居貧原憲履長決，戰罷吳王屨不歸。", "已類憊靴無復召，空慙釋屩頓成非。", "塵勞棄屣今何有，縱爾雙鳬自在飛。"]'),
('db882770-8e7b-4aac-bdb3-c0be11efb208','宋伯華趨朝用川字衫字韵作二詩送之  其一','廖行之','宋','宋诗','song-poetry','','[]','微雨輕寒透客衫，十分秋色相征驂。',64,'全唐诗/poet.song.157000.json','["微雨輕寒透客衫，十分秋色相征驂。", "人占逸駕應空北，君自良圖已運南。", "須信由來非枉尺，誰云領取勿多談。", "而今吐握逢知己，會聽新除趁六參。"]'),
('c8d91484-9f77-407a-a8d8-a6768dc881f4','宋伯華趨朝用川字衫字韵作二詩送之  其二','廖行之','宋','宋诗','song-poetry','','[]','馳名衮衮甚長川，君獨乘風萬里船。',64,'全唐诗/poet.song.157000.json','["馳名衮衮甚長川，君獨乘風萬里船。", "得意正看期汗漫，趨時寧肯媚連娟。", "升沈百辟方公道，扶植斯文要衆賢。", "元獻景文今棣萼，還須柱石漢中天。"]'),
('af3a73d1-cf2d-4ba0-94e7-273979cc5516','送鮑判官解官歸浙西','廖行之','宋','宋诗','song-poetry','','[]','蚤行吳越得清名，歲久湘中始識君。',64,'全唐诗/poet.song.157000.json','["蚤行吳越得清名，歲久湘中始識君。", "人物自堪交仲父，才華端可繼參軍。", "一州從事曾游刃，萬里封侯好策勳。", "江上今朝話離別，西風吹起楚天雲。"]'),
('7497abf2-ccae-462b-b596-7a0590ef4e0d','送樂貢父赴書館','廖行之','宋','宋诗','song-poetry','','[]','秀出書堂雋有聲，又携琴劍主文盟。',64,'全唐诗/poet.song.157000.json','["秀出書堂雋有聲，又携琴劍主文盟。", "師承自得春秋學，經行俱高月旦評。", "援繳解令專志慮，窺園那肯亂精明。", "安昌異日多成就，何止從宣一二名。"]'),
('5062a0b4-9919-4cdc-9ede-ab5e26d7dcd1','送伯華醉歸不寐又用韵雜言二首  其一','廖行之','宋','宋诗','song-poetry','','[]','十幅風蒲下碧川，別懷何惜醉金船。',64,'全唐诗/poet.song.157000.json','["十幅風蒲下碧川，別懷何惜醉金船。", "婁公正遣江流穩，庾老寧辜月影娟。", "善世如君皆夙望，澤民應我愧前賢。", "榮華莫美城南杜，早晚還親尺五天。"]'),
('7a2bedf2-0c5d-48d7-91b9-fac9c4d2cfae','送伯華醉歸不寐又用韵雜言二首  其二','廖行之','宋','宋诗','song-poetry','','[]','休論決處甚防川，剛道呼來不上船。',64,'全唐诗/poet.song.157000.json','["休論決處甚防川，剛道呼來不上船。", "正使涓流鳴㶁㶁，終然脩竹浄娟娟。", "浮沈與世魚潛躍，清濁從渠酒聖賢。", "富貴功名皆自有，可憐邀月問青天。"]'),
('e94d04b7-06b7-4009-a7f7-72530ffbed1a','和曾知運寄兄詩二首  其一','廖行之','宋','宋诗','song-poetry','','[]','得喪區區指屈伸，褰裳歸去楚江濱。',64,'全唐诗/poet.song.157000.json','["得喪區區指屈伸，褰裳歸去楚江濱。", "蓴鱸到底秋風美，牛斗依然夜氣新。", "滿壑煙霜供嘯傲，傳家詩禮照清貧。", "不須變姓吳門隠，自有相從化鶴人。"]'),
('00961516-6f72-4a7d-be99-2679ab149948','和曾知運寄兄詩二首  其二','廖行之','宋','宋诗','song-poetry','','[]','忠孝蟬聯萃一門，鴈行相望款天閽。',64,'全唐诗/poet.song.157000.json','["忠孝蟬聯萃一門，鴈行相望款天閽。", "青雲有弟先行志，藍綬今兄亦拜恩。", "肘印一時饒季子，風雩千載見諸孫。", "二難金玉交輝映，出處相高德義尊。"]'),
('3c6052cb-6640-43b0-bccc-ed360ee06edc','送長兄赴調上都次田俊卿韵二首  其一','廖行之','宋','宋诗','song-poetry','','[]','霜熟林空月滿川，衝寒突兀聳詩肩。',64,'全唐诗/poet.song.157000.json','["霜熟林空月滿川，衝寒突兀聳詩肩。", "便應策驥行夷路，不用燃犀照碧淵。", "從昔正人終遇世，到今方士漫求仙。", "老成謀國須吾輩，可笑輕疎賈少年。"]'),
('1d522efe-0ebd-4934-8beb-65e3cd8de957','送長兄赴調上都次田俊卿韵二首  其二','廖行之','宋','宋诗','song-poetry','','[]','從今日日聽新除，去馬加鞭不用徐。',64,'全唐诗/poet.song.157000.json','["從今日日聽新除，去馬加鞭不用徐。", "最是好爲三釜計，不妨頻寄萬金書。", "君行霄漢無留軔，我得江湖欲縱魚。", "更念起家人底事，百年門戶正關渠。"]'),
('05d4b499-1f36-4bd5-97c1-5a14d394a81d','重九道中懷長兄二首  其一','廖行之','宋','宋诗','song-poetry','','[]','客裏匆匆飽歲時，今誰能免利名羈。',64,'全唐诗/poet.song.157000.json','["客裏匆匆飽歲時，今誰能免利名羈。", "有人騎鶴去千歲，顧我巢林方一枝。", "後日空懷棠杕燕，經年慙愧菊花期。", "白雲飛處湘天碧，心在南陔日詠詩。"]'),
('f58ef2ff-d6a6-447d-ae0d-ad632c483cd4','重九道中懷長兄二首  其二','廖行之','宋','宋诗','song-poetry','','[]','追歡那復少年時，老驥如今亦受羈。',64,'全唐诗/poet.song.157000.json','["追歡那復少年時，老驥如今亦受羈。", "白髮驚人風落帽，黄花伴我歲寒枝。", "誰能尋勝過元亮，自嘆知音失子期。", "點檢胸中猶礧磈，强傾濁酒自哦詩。"]'),
('55fde957-896c-4a9e-97db-4ccbfe72f3fc','田舍雜興懷長兄四首  其一','廖行之','宋','宋诗','song-poetry','','[]','少休廛市喧囂耳，來聽田農應和歌。',64,'全唐诗/poet.song.157000.json','["少休廛市喧囂耳，來聽田農應和歌。", "畟畟耕疇皆帝力，欣欣時物自天和。", "山雲亭午半未斂，溪雨黄昏清更多。", "但得長年飽禾稻，也勝官裏厭風波。"]'),
('8fd929e2-139a-430c-9a1f-ee5bbf56e157','田舍雜興懷長兄四首  其二','廖行之','宋','宋诗','song-poetry','','[]','不到田家又夏初，試從野老訪耕鋤。',64,'全唐诗/poet.song.157000.json','["不到田家又夏初，試從野老訪耕鋤。", "稻畦高下水皆足，天意雨晴時自如。", "學稼我猶慙孔子，問津君且向長沮。", "宦游何似團欒好，更念懷歸畏簡書。"]'),
('3ecf6860-a65c-4aeb-bad9-115c6b0b7729','田舍雜興懷長兄四首  其三','廖行之','宋','宋诗','song-poetry','','[]','去城靳靳路一驛，故歲迢迢今甫來。',64,'全唐诗/poet.song.157000.json','["去城靳靳路一驛，故歲迢迢今甫來。", "桃李陰成真綠野，溪山清絕勝章臺。", "青衫手板徒勞爾，竹杖芒鞋亦快哉。", "莫向紅塵深著脚，而今毛鷙苦相猜。"]'),
('845596f2-6c1f-4e2b-9641-fe838819d66c','田舍雜興懷長兄四首  其四','廖行之','宋','宋诗','song-poetry','','[]','遥知此日黄初起，頗憶平生馬少游。',64,'全唐诗/poet.song.157000.json','["遥知此日黄初起，頗憶平生馬少游。", "薄有田園奉甘旨，苦無機械與沈浮。", "如今官事真誰了，底事周南獨子留。", "白髮倚門還念否，令人翻動北山謳。"]'),
('207bca66-5673-4c7a-a037-922b0bf7bbcb','壽巴陵朱宰','廖行之','宋','宋诗','song-poetry','','[]','萬里沅湘浩蕩秋，秋來佳致日清遒。',64,'全唐诗/poet.song.157000.json','["萬里沅湘浩蕩秋，秋來佳致日清遒。", "湖平一碧波光靜，雨足千崖暑氣收。", "底事歡聲騰下雋，祗今賢宰在中牟。", "民情天意歸仁壽，看到三公尚黑頭。"]'),
('d5dab068-3197-4ab5-9cd4-2e8f86c4e4f1','送許兄還侍兼簡廣南監場二首  其一','廖行之','宋','宋诗','song-poetry','','[]','君家疇昔汝南龍，淵有驪珠自不窮。',64,'全唐诗/poet.song.157000.json','["君家疇昔汝南龍，淵有驪珠自不窮。", "黄卷乃翁廉取位，碧梧之子秀參空。", "儒冠底誤資身術，鹽筴聊成富國功。", "莫倚沃饒云近盬，圖南九萬看摶風。"]'),
('7579f458-cf0b-4194-b805-faf100a0cd54','送許兄還侍兼簡廣南監場二首  其二','廖行之','宋','宋诗','song-poetry','','[]','舊游歷歷記湟川，南下番禺穩可沿。',64,'全唐诗/poet.song.157000.json','["舊游歷歷記湟川，南下番禺穩可沿。", "知有文星衝斗去，遥憐海水遶城邊。", "而今五嶺多宜客，見說羣卿賸好賢。", "問訊夫君聊吏隠，云胡三月未官遷。"]'),
('da9a7fce-7ae4-482b-b7f2-6c41c1641833','次韵酬宋伯潛三首  其一','廖行之','宋','宋诗','song-poetry','','[]','詩壇得雋敵無强，獨立南豐一瓣香。',64,'全唐诗/poet.song.157000.json','["詩壇得雋敵無强，獨立南豐一瓣香。", "我欲句中聞妙法，君應肘後出神方。", "陶鎔景色春長好，流轉風光物自忙。", "珍重三薰更三沐，全勝湯餠試何郎。"]'),
('72c82cc9-3599-4eab-827c-1d9ad26a6adb','次韵酬宋伯潛三首  其二','廖行之','宋','宋诗','song-poetry','','[]','百拙無堪不自强，身謀猶得學黄香。',64,'全唐诗/poet.song.157000.json','["百拙無堪不自强，身謀猶得學黄香。", "青衫良助君衣綵，圓鑿何嫌我枘方。", "舊雨故人相得甚，浮雲蒼狗可憐忙。", "從君更許聞詩律，喚醒風騷起夜郎。"]'),
('5db549c6-10f3-4b7b-b2a7-c430cc14f1ed','次韵酬宋伯潛三首  其三','廖行之','宋','宋诗','song-poetry','','[]','老懶渠能更倔强，鄰牆可戀甕頭香。',64,'全唐诗/poet.song.157000.json','["老懶渠能更倔强，鄰牆可戀甕頭香。", "卷舒自我聊全璧，非笑從人亦大方。", "日永遊絲隨望遠，春深乳燕趁晴忙。", "閒來不入邯鄲夢，未厭區區白首郎。"]'),
('75d24a05-5fd6-4523-93a4-799e2b4dc156','酬羅季康二首  其一','廖行之','宋','宋诗','song-poetry','','[]','慚愧材非可與言，等閒微籟自鳴天。',64,'全唐诗/poet.song.157000.json','["慚愧材非可與言，等閒微籟自鳴天。", "井蛙無理祇成閙，里婦空顰豈解妍。", "君自平生多與點，誰云一語始知然。", "欲伸床下慇勤拜，詩律於今屬大賢。"]'),
('6d2507fb-90b2-44c3-ad8b-7401b12e6ed7','酬羅季康二首  其二','廖行之','宋','宋诗','song-poetry','','[]','自憐疎拙百奚宜，不省胡顔可媚時。',64,'全唐诗/poet.song.157000.json','["自憐疎拙百奚宜，不省胡顔可媚時。", "馳騖功名非我事，歡娛菽水祇心知。", "風姿故陋難施粉，面目堪憎正類倛。", "惟有靈臺亦裴度，到君明眼不能欺。"]'),
('7e78d353-9289-41fa-b386-30479eb604f4','次陳頤剛與許拾遺酬唱之作','廖行之','宋','宋诗','song-poetry','','[]','奇謀端合贊幾沈，何事山林意味深。',64,'全唐诗/poet.song.157000.json','["奇謀端合贊幾沈，何事山林意味深。", "引類古人方厚祿，憂時百念可灰心。", "會看覽德翔千仞，未信干霄老百尋。", "却笑疎慵真漫仕，閒中贏得二毛侵。"]'),
('1c7c7cc4-2a35-4082-bedd-7ac70564b78b','和四十五叔慶謙子過省二首  其一','廖行之','宋','宋诗','song-poetry','','[]','行年五十尚青衫，耿耿胸中負不凡。',64,'全唐诗/poet.song.157000.json','["行年五十尚青衫，耿耿胸中負不凡。", "那意寧馨聯桂籍，祇知清白映冰銜。", "平生濟叔耽周易，何日商宗起傅巖。", "好上公車治安策，綠緹飛詔下方函。"]'),
('2964f8fe-76fc-4b92-99e8-28931cc7a12d','和四十五叔慶謙子過省二首  其二','廖行之','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','長笑癡兒戀戲衫，拖泥带水漫卑凡。',64,'全唐诗/poet.song.157000.json','["長笑癡兒戀戲衫，拖泥带水漫卑凡。", "何如一動君王聽，不入徒勞簿尉銜。", "細水循除空㶁㶁，泰山終古鎮巖巖。", "可憐司馬身華寵，晚作諛書擬奏函。"]'),
('e1deb363-c512-402f-9267-777e0c50e97a','還十五弟文稿','廖行之','宋','宋诗','song-poetry','','[]','文府高扃守鬼神，蔽虧那揜豔華春。',64,'全唐诗/poet.song.157000.json','["文府高扃守鬼神，蔽虧那揜豔華春。", "屠門肯作朵頤過，龍頷輕攘照海珍。", "十襲莫論藏弆寵，雙眸姑浣向來塵。", "從茲染指諳腴味，藜莧難甘誑腹貧。"]'),
('703eeddd-3992-4d07-ba67-014cdcd5f46f','示夢龍姪','廖行之','宋','宋诗','song-poetry','','[]','小驗文場粗慰心，讀書從此更諄諄。',64,'全唐诗/poet.song.157000.json','["小驗文場粗慰心，讀書從此更諄諄。", "要令大敵尤能勇，須索新功又過人。", "得力無過親翰墨，致身端可上星辰。", "秋風春浪鼇頭好，拭目吾宗盡國珍。"]'),
('33b59f3b-830a-4eaf-a60b-ab84a98f6d2d','贈別羅舜舉二首  其一','廖行之','宋','宋诗','song-poetry','','[]','疇昔交情一輔車，年來造物且乘除。',64,'全唐诗/poet.song.157000.json','["疇昔交情一輔車，年來造物且乘除。", "論文誰共肺肝語，道舊空傳咫尺書。", "半歲不堪心鄙吝，一樽聊得語躊躇。", "匆匆又作相違恨，愁絕臨風送目初。"]'),
('10c30408-b614-4b18-9863-e67e5c8d501e','贈別羅舜舉二首  其二','廖行之','宋','宋诗','song-poetry','','[]','鼇峰夜色輸明月，龍穴秋光藹碧雲。',64,'全唐诗/poet.song.157000.json','["鼇峰夜色輸明月，龍穴秋光藹碧雲。", "景物故應人惜別，風流難與世相聞。", "新詩題處君思我，啼鳥聲中我夢君。", "一笑相從非易得，有懷聊復此云云。"]'),
('9c1ece9c-1d33-4ee7-8379-aafd88f24c62','別蒲圻徐丞于金鷄驛次李和卿韵','廖行之','宋','宋诗','song-poetry','','[]','金鷄亭上小舂容，日射湖光照眼濃。',64,'全唐诗/poet.song.157000.json','["金鷄亭上小舂容，日射湖光照眼濃。", "痛飲壯君堪八斗，劇談應我避羣鋒。", "笑看天際孤飛鶩，驚起波中老蟄龍。", "明日東西各奔走，莫隨流俗浪迎逢。"]'),
('50f0e4b6-414a-491b-aa32-25ddfef30fbf','有禽聲急而似可曉鄉人以催稅目之其聲亦頗類焉因感而成詩','廖行之','宋','宋诗','song-poetry','','[]','怪底微禽似有知，區區舌吻竟奚爲。',64,'全唐诗/poet.song.157000.json','["怪底微禽似有知，區區舌吻竟奚爲。", "欲將終日能鳴巧，深爲當時遠害思。", "布穀尚應勤播種，春畦何事較公私。", "誰如獨占催科考，無復陽城恨拙遲。"]'),
('8f4cca99-e6df-48c4-aac7-20236950d668','挽江西宋漕三首  其一','廖行之','宋','宋诗','song-poetry','','[]','蚤歲才名畫省郎，會紆玉節惠三湘。',64,'全唐诗/poet.song.157000.json','["蚤歲才名畫省郎，會紆玉節惠三湘。", "哀矜折獄人無怨，訪問垂心慮最長。", "不便幽潛遺陋巷，更將文物萃書堂。", "期公四海皆膏澤，太息思賢殄瘁章。"]'),
('4cf543fa-b8ed-4c41-b993-b25eb981d877','挽江西宋漕三首  其二','廖行之','宋','宋诗','song-poetry','','[]','牙籌坐席未全溫，尚想星沙戀德門。',64,'全唐诗/poet.song.157000.json','["牙籌坐席未全溫，尚想星沙戀德門。", "剡牘方新蠲賦請，憂民不計此身存。", "平生大樂功何晚，壽相龐眉理莫論。", "雲黯江南失春色，可堪杜宇更銷魂。"]'),
('6d8ad554-ee65-4324-8031-c09b3022ad9e','挽江西宋漕三首  其三','廖行之','宋','宋诗','song-poetry','','[]','櫑具曾承衣繡迎，學宮仍見選諸生。',64,'全唐诗/poet.song.157000.json','["櫑具曾承衣繡迎，學宮仍見選諸生。", "求文於白遠何取，聯第如詹時共榮。", "公自典刑多教化，人誰菑播頼生成。", "而今未報何侯力，萬里神馳兩淚傾。"]'),
('32e5b63f-65f3-483e-839f-477ce0a5ca97','挽宋知縣剛仲二首  其一','廖行之','宋','宋诗','song-poetry','','[]','與君同志復同州，少日論文放一頭。',64,'全唐诗/poet.song.157000.json','["與君同志復同州，少日論文放一頭。", "孝子憂親雙鬢白，癡兒了事一生愁。", "凌雲意氣須臾盡，積歲聲名取次休。", "頼有遺編留史筆，幾回廢卷淚橫流。"]'),
('ef202fb1-30c6-4731-8cc7-ad323fd1764c','挽宋知縣剛仲二首  其二','廖行之','宋','宋诗','song-poetry','','[]','閥閲方成一段奇，三湘況是古來稀。',64,'全唐诗/poet.song.157000.json','["閥閲方成一段奇，三湘況是古來稀。", "弟兄同歲乘槎去，父子連科折桂歸。", "詩禮傳家人共羨，歡華過眼事俱非。", "秋風寂寞萱堂露，染盡當年戲綵衣。"]'),
('6f6e8abe-d3c9-4b51-bc7b-25a977ae1d4c','挽陳宣教直中','廖行之','宋','宋诗','song-poetry','','[]','回鴈峰前憶隠淪，平生謀道不謀身。',64,'全唐诗/poet.song.157000.json','["回鴈峰前憶隠淪，平生謀道不謀身。", "詩書滿腹空名世，科第衰年獨後人。", "頼有佳兒傳素業，能令潜德上貞珉。", "交游半世今零落，忍望銘旌淚墨新。"]'),
('e7430e3a-9c09-46b0-83a0-5e92a234f0e5','挽武宣教徹二首  其一','廖行之','宋','宋诗','song-poetry','','[]','三釜何如菽水長，毅然投劾奉歸裝。',64,'全唐诗/poet.song.157000.json','["三釜何如菽水長，毅然投劾奉歸裝。", "共欽箠楚辭巴嶺，又聽勾稽復楚鄉。", "鸂鶒下灘誰御史，鳳鸞棲棘漫仇香。", "絕憐五十三年筆，不草文園封禪囊。"]'),
('acc17cb4-a50d-45ab-be48-6fc619037117','挽武宣教徹二首  其二','廖行之','宋','宋诗','song-poetry','','[]','書來撩我重思君，情比雝雝鴈叫羣。',64,'全唐诗/poet.song.157000.json','["書來撩我重思君，情比雝雝鴈叫羣。", "詞賦一時高李杜，弟兄今日掃機雲。", "未還金馬日邊詔，去作玉樓天上文。", "千里莫能親視窆，篇詩寄挽亦徒云。"]'),
('b1626732-dbfb-4cb3-82fc-ac16140b63ed','挽武宣教徯四首  其一','廖行之','宋','宋诗','song-poetry','','[]','南楚東吳萬里長，幾年來往共資裝。',64,'全唐诗/poet.song.157000.json','["南楚東吳萬里長，幾年來往共資裝。", "公方著脚功名路，我辦卜隣文物鄉。", "雅意嘉招言在耳，贈行新句墨猶香。", "追思氣概生涯語，誠意諄諄總括囊。"]'),
('8cb6b709-2709-4574-9d92-ac25cb8e5345','挽武宣教徯四首  其二','廖行之','宋','宋诗','song-poetry','','[]','生平耿耿不忘君，位下才高氣不羣。',64,'全唐诗/poet.song.157000.json','["生平耿耿不忘君，位下才高氣不羣。", "手取科名如拾芥，眼高富貴等浮雲。", "祇知世可行吾道，其奈天將喪此文。", "知遇莫酬今已矣，篇詩聊寓一哀云。"]'),
('57cd2a83-482e-4913-8a9e-f01146368bb5','挽武宣教徯四首  其三','廖行之','宋','宋诗','song-poetry','','[]','嗚咽鍾悲子夜昏，靈椿摧折重銷魂。',64,'全唐诗/poet.song.157000.json','["嗚咽鍾悲子夜昏，靈椿摧折重銷魂。", "數絲白雪遺慈母，一寸青松括耳孫。", "返哺聲乾那可及，挽鬚情在不堪論。", "桂枝皎皎欹寒玉，竚看揚名振禮門。"]'),
('467cfb79-1926-4bea-a3bb-3411e74d2478','挽武宣教徯四首  其四','廖行之','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','哭公無計挽公留，痛寫哀衷佐紼謳。',64,'全唐诗/poet.song.157000.json','["哭公無計挽公留，痛寫哀衷佐紼謳。", "丹旐姓名何所益，青編事業等閑休。", "長江百里浮清恨，明月孤峰起些愁。", "底事波神均此怨，白頭寒浪拍空流。"]'),
('33b8a198-081a-48f2-b77f-502e92f65baa','挽周宣教宗沂二首  其一','廖行之','宋','宋诗','song-poetry','','[]','子職勤勞衆莫攀，巴丘高節世尤難。',64,'全唐诗/poet.song.157000.json','["子職勤勞衆莫攀，巴丘高節世尤難。", "一官未抵琴書樂，三釜何如菽水歡。", "儻有軒裳存妙句，平居豐儉只儒酸。", "音容渺邈今何在，雲黯江南萬木寒。"]'),
('9a61b0c8-2712-44af-984d-ca2e40046289','挽周宣教宗沂二首  其二','廖行之','宋','宋诗','song-poetry','','[]','始別猶承笑語溫，昭暉相望幾晨昏。',64,'全唐诗/poet.song.157000.json','["始別猶承笑語溫，昭暉相望幾晨昏。", "伻來駭聽言傳異，淚哽悲懷飽不餐。", "歸拜文帷人已去，痛瞻靈室像徒存。", "反思博我諄諄意，何日能酬知遇恩。"]'),
('09b390ee-c693-40f7-b8ac-809b0ade139e','挽劉宣教秉二首  其一','廖行之','宋','宋诗','song-poetry','','[]','銘旌摇曳淚沾巾，爲惜賢才生死分。',64,'全唐诗/poet.song.157000.json','["銘旌摇曳淚沾巾，爲惜賢才生死分。", "樂道喜陪今漫道，高文誰與共論文。", "西湘岸脚送霜雨，明月嶺頭留暮雲。", "有子登科真不朽，它年勳鼎慰嚴君。"]'),
('47d759a5-4f1f-45f4-86b9-f9ff6a3c1f36','挽劉宣教秉二首  其二','廖行之','宋','宋诗','song-poetry','','[]','道義君家振楚荆，嗟君功業負平生。',64,'全唐诗/poet.song.157000.json','["道義君家振楚荆，嗟君功業負平生。", "詩書累世有底盛，簿領一官徒爾榮。", "親族追思應重惜，慈顔悵望不勝情。", "靈輀遠送松岡外，風雨凄凄猿鶴鳴。"]'),
('1659f1ad-7287-4274-aa52-86d2e2080fe7','挽黄承事三首  其一','廖行之','宋','宋诗','song-poetry','','[]','肯爲儒冠嘆誤身，直將富貴等浮雲。',64,'全唐诗/poet.song.157000.json','["肯爲儒冠嘆誤身，直將富貴等浮雲。", "談棋柯腐塵勞想，讀易編摩世俗紛。", "鄭叟遽嗟年在己，卜商寧作地脩文。", "須知異日高人傳，耿耿君平繼有君。"]'),
('9f30dfbd-8a83-45db-a5c3-4324970bb65c','挽黄承事三首  其二','廖行之','宋','宋诗','song-poetry','','[]','不用籯金侈厚藏，無煩農圃富耕桑。',64,'全唐诗/poet.song.157000.json','["不用籯金侈厚藏，無煩農圃富耕桑。", "一經父子韋編訓，餘慶階庭玉樹芳。", "道義固堪綿有後，功名渾把付諸郎。", "他年竇桂詵詵報，當信於今種德香。"]');
